def newspaper_publisher_lookup(newspaper_name: str, date: str = None, output_format: str = 'name_only', language: str = None, region: str = None) -> dict:
    """
    Finds the publisher of a given newspaper using various query parameters.

    Parameters:
    - newspaper_name (str): The name of the newspaper whose publisher is to be found.
    - date (str, optional): The date for which the publisher information is relevant.
    - output_format (str, optional): The format of the output ('name_only', 'detailed', 'full_report').
    - language (str, optional): The language in which the newspaper is published.
    - region (str, optional): The geographical region or country where the newspaper is published.

    Returns:
    - dict: A dictionary containing the publisher information or an error message.
    """
    # Simulated database query result
    database = {
        'Hürriyet Daily News': {
            'publisher': 'Doğan Media',
            'details': {
                'contact': 'contact@hurriyet.com.tr',
                'history': 'Founded in 1961',
                'frequency': 'Daily',
                'circulation': '500,000'
            }
        }
    }

    # Error handling for required parameter
    if not newspaper_name:
        return {'error': 'The newspaper_name parameter is required.'}

    # Validate output_format
    if output_format not in ['name_only', 'detailed', 'full_report']:
        return {'error': 'Invalid output_format. Choose from name_only, detailed, full_report.'}

    # Simulate fetching data from the database
    newspaper_info = database.get(newspaper_name)
    if not newspaper_info:
        return {'error': 'Newspaper not found in the database.'}

    # Prepare the response based on output_format
    if output_format == 'name_only':
        return {'publisher': newspaper_info['publisher']}
    elif output_format == 'detailed':
        return {
            'publisher': newspaper_info['publisher'],
            'contact': newspaper_info['details']['contact'],
            'history': newspaper_info['details']['history']
        }
    elif output_format == 'full_report':
        return {
            'publisher': newspaper_info['publisher'],
            'contact': newspaper_info['details']['contact'],
            'history': newspaper_info['details']['history'],
            'frequency': newspaper_info['details']['frequency'],
            'circulation': newspaper_info['details']['circulation']
        }

    # Default error if something unexpected happens
    return {'error': 'An unexpected error occurred.'}

def enhanced_year_calculator(current_year, number_of_years=1, calendar_system='Gregorian'):
    """
    Calculate subsequent years following a given year.
    :param current_year: The current year for which the next year(s) is to be calculated.
    :param number_of_years: The number of subsequent years to calculate. Defaults to 1.
    :param calendar_system: The calendar system to use for calculation. Defaults to 'Gregorian'.
    :return: The subsequent year(s) based on the input parameters.
    """
    # Error handling for invalid inputs
    if not isinstance(current_year, int):
        return {'error': 'Invalid input: current_year must be an integer.'}
    if not isinstance(number_of_years, int) or number_of_years < 1:
        return {'error': 'Invalid input: number_of_years must be a positive integer.'}
    if not isinstance(calendar_system, str):
        return {'error': 'Invalid input: calendar_system must be a string.'}

    # Currently, only the Gregorian calendar system is implemented
    if calendar_system != 'Gregorian':
        return {'error': 'Unsupported calendar system: Only Gregorian is supported at this time.'}

    # Calculate the subsequent year(s)
    subsequent_years = [current_year + i for i in range(1, number_of_years + 1)]

    # Return the result
    return {'subsequent_years': subsequent_years}

