def extract_last_name(full_name: str, delimiter: str = ' ', ignore_suffixes: bool = True, include_middle_names: bool = False, case_sensitive: bool = False, handle_special_characters: bool = True, prefix_handling: bool = False) -> str:
    """
    Extracts the last name from a full name string based on the provided parameters.
    """
    # Error handling for incorrect input types
    if not isinstance(full_name, str):
        raise ValueError('The full_name must be a string.')
    if not isinstance(delimiter, str):
        raise ValueError('The delimiter must be a string.')

    # Split the full name using the specified delimiter
    name_parts = full_name.split(delimiter)

    # Handle prefix if prefix_handling is enabled
    if prefix_handling and name_parts[0].lower() in ['mr', 'ms', 'mrs', 'dr', 'prof']:
        name_parts = name_parts[1:]

    # Handle suffixes if ignore_suffixes is enabled
    if ignore_suffixes:
        suffixes = ['jr', 'sr', 'ii', 'iii', 'iv']
        name_parts = [part for part in name_parts if part.lower().strip('.') not in suffixes]

    # Determine the last name
    if include_middle_names:
        last_name = delimiter.join(name_parts[1:]) if len(name_parts) > 1 else name_parts[0]
    else:
        last_name = name_parts[-1] if name_parts else ''

    # Handle case sensitivity
    if not case_sensitive:
        last_name = last_name.lower()

    # Handle special characters
    if handle_special_characters:
        last_name = last_name.replace('-', '').replace("'", '')

    return last_name

