def letter_counter(input: str, ignore_non_letters: bool = True, output_format: str = 'integer', case_sensitive: bool = False, count_vowels: bool = False, count_consonants: bool = False):
    # Error handling for required parameter 'input'
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Initialize counts
    total_count = 0
    vowel_count = 0
    consonant_count = 0

    # Define vowels
    vowels = 'aeiouAEIOU' if case_sensitive else 'aeiou'

    # Process each character in the input
    for char in input:
        if ignore_non_letters and not char.isalpha():
            continue
        if not case_sensitive:
            char = char.lower()
        total_count += 1
        if count_vowels and char in vowels:
            vowel_count += 1
        elif count_consonants and char.isalpha() and char not in vowels:
            consonant_count += 1

    # Prepare output based on the specified format
    if output_format == 'integer':
        return total_count
    elif output_format == 'text':
        return f'Total letters: {total_count}'
    elif output_format == 'detailed':
        return {
            'total_letters': total_count,
            'vowels': vowel_count if count_vowels else 'Not counted',
            'consonants': consonant_count if count_consonants else 'Not counted'
        }
    else:
        return {'error': 'Invalid output format specified.'}

