print(result)  # Output: 2

def legislative_sponsor_finder(resolution_title: str, primary_sponsor: str = '', include_co_sponsors: bool = True, date_range: dict = None, resolution_type: str = '', legislative_body: str = '', sponsor_party_affiliation: str = '') -> dict:
    """
    Searches for sponsors and co-sponsors of legislative resolutions based on the provided parameters.

    :param resolution_title: The title or keywords of the resolution to search for. Partial matches are allowed.
    :param primary_sponsor: The name of the primary sponsor to filter the search results.
    :param include_co_sponsors: Whether to include co-sponsors in the search results. Defaults to true.
    :param date_range: The date range or session within which to search for the resolution.
    :param resolution_type: The type of resolution, e.g., 'bill', 'amendment', 'motion'.
    :param legislative_body: The legislative body to search within, e.g., 'Senate', 'House of Representatives'.
    :param sponsor_party_affiliation: Filter results by the political party affiliation of the sponsor.
    :return: A dictionary containing the search results, including sponsors and co-sponsors.
    """
    # Simulated database of resolutions
    resolutions_db = [
        {
            'title': 'Resolution to Reopen Trade with Vietnam',
            'primary_sponsor': 'John McCain',
            'co_sponsors': ['John Kerry'],
            'date': '2000-01-01',
            'type': 'bill',
            'body': 'Senate',
            'party_affiliation': 'Republican'
        }
    ]

    # Validate required parameter
    if not resolution_title:
        return {'error': 'resolution_title is required'}

    # Initialize results
    results = []

    # Search logic
    for resolution in resolutions_db:
        if resolution_title.lower() in resolution['title'].lower():
            if primary_sponsor and primary_sponsor.lower() != resolution['primary_sponsor'].lower():
                continue
            if date_range:
                start_date = date_range.get('start_date')
                end_date = date_range.get('end_date')
                if start_date and resolution['date'] < start_date:
                    continue
                if end_date and resolution['date'] > end_date:
                    continue
            if resolution_type and resolution_type.lower() != resolution['type'].lower():
                continue
            if legislative_body and legislative_body.lower() != resolution['body'].lower():
                continue
            if sponsor_party_affiliation and sponsor_party_affiliation.lower() != resolution['party_affiliation'].lower():
                continue
            if include_co_sponsors:
                results.append({
                    'primary_sponsor': resolution['primary_sponsor'],
                    'co_sponsors': resolution['co_sponsors']
                })
            else:
                results.append({'primary_sponsor': resolution['primary_sponsor']})

    # Return results
    if not results:
        return {'error': 'No matching resolutions found'}
    return {'results': results}

