def extract_first_name(full_name: str, output_format: str = 'string', case_sensitive: bool = False, include_middle_name: bool = False, batch_processing: bool = False):
    """
    Extracts the first name from a full name string with various customization options.
    """
    # Error handling for input types
    if not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a string.'}
    if output_format not in ['string', 'json', 'position']:
        return {'error': 'Invalid input: output_format must be one of string, json, or position.'}

    # Split the full name into parts
    name_parts = full_name.split()

    # Determine the first name
    first_name = name_parts[0] if name_parts else ''

    # Include middle name if specified
    if include_middle_name and len(name_parts) > 2:
        first_name = ' '.join(name_parts[:2])

    # Handle case sensitivity
    if not case_sensitive:
        first_name = first_name.lower().capitalize()

    # Return based on the specified output format
    if output_format == 'string':
        return first_name
    elif output_format == 'json':
        return {'first_name': first_name}
    elif output_format == 'position':
        return full_name.find(first_name)

    # Default return
    return first_name

