def string_length_calculator(input_string, ignore_special_characters=True, ignore_spaces=True, count_digits=False, case_sensitive=False, count_mode='letters'):
    """
    Calculate the length of the input string based on specified parameters.
    """
    import re

    if not isinstance(input_string, str):
        return {'error': 'Invalid input: input_string must be a string.'}

    if count_mode not in ['letters', 'words', 'sentences']:
        return {'error': 'Invalid count_mode. Supported modes are: letters, words, sentences.'}

    # Adjust string based on parameters
    if not case_sensitive:
        input_string = input_string.lower()

    if ignore_special_characters:
        input_string = re.sub(r'[^\w\s]', '', input_string)

    if ignore_spaces:
        input_string = input_string.replace(' ', '')

    if not count_digits:
        input_string = re.sub(r'\d', '', input_string)

    # Calculate length based on count_mode
    if count_mode == 'letters':
        count = len(input_string)
    elif count_mode == 'words':
        count = len(input_string.split())
    elif count_mode == 'sentences':
        count = len(re.split(r'[.!?]+', input_string)) - 1

    return {'count': count}

