def geo_time_zone_finder(location: str, entity_type: str = 'city', date: str = None, latitude: float = None, longitude: float = None, historical: bool = False, include_offset: bool = True):
    """
    Determines the time zone of a given geographical location.

    :param location: The name of the geographical location for which the time zone is to be determined.
    :param entity_type: The type of geographical entity. Defaults to 'city'.
    :param date: The date for which the time zone is required, to account for daylight saving time changes. Defaults to the current date.
    :param latitude: The latitude of the location for precise identification. Optional if location name is provided.
    :param longitude: The longitude of the location for precise identification. Optional if location name is provided.
    :param historical: Whether to include historical time zone data. Defaults to false.
    :param include_offset: Whether to include the time zone offset in the result. Defaults to true.
    :return: The time zone of the location, possibly including the offset.
    """
    # Error handling for required parameters
    if not location:
        return {'error': 'Location is required.'}
    if entity_type not in ['county', 'city', 'country', 'state']:
        return {'error': f"Invalid entity_type '{entity_type}'. Must be one of ['county', 'city', 'country', 'state']."}

    # Simulate the time zone determination logic
    # For the purpose of this example, we assume the time zone for Randall County is 'America/Chicago'
    if location.lower() == 'randall county' and entity_type == 'county':
        time_zone = 'America/Chicago'
        if include_offset:
            # Simulate offset inclusion
            offset = '-06:00'  # Example offset for CST
            return {'time_zone': time_zone, 'offset': offset}
        else:
            return {'time_zone': time_zone}
    else:
        return {'error': 'Location not found or unsupported entity type.'}

