def extract_last_name(full_name, name_delimiter=' ', ignore_titles=True, cultural_context='western', include_middle_name=False, handle_suffixes=True, custom_rules=None):
    # Error handling for required parameter
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name. It must be a non-empty string.'}

    # Error handling for cultural context
    if cultural_context not in ['western', 'eastern', 'arabic', 'custom']:
        return {'error': 'Invalid cultural_context. Must be one of: western, eastern, arabic, custom.'}

    # Split the full name using the specified delimiter
    name_parts = full_name.split(name_delimiter)

    # Handle titles if ignore_titles is True
    if ignore_titles:
        titles = ['Dr.', 'Mr.', 'Ms.', 'Mrs.']
        if custom_rules and 'title_list' in custom_rules:
            titles.extend(custom_rules['title_list'])
        name_parts = [part for part in name_parts if part not in titles]

    # Handle suffixes if handle_suffixes is True
    if handle_suffixes:
        suffixes = ['Jr.', 'Sr.', 'II', 'III']
        if custom_rules and 'suffix_list' in custom_rules:
            suffixes.extend(custom_rules['suffix_list'])
        if name_parts[-1] in suffixes:
            name_parts.pop()

    # Determine the last name based on cultural context
    last_name = ''
    if cultural_context == 'western':
        last_name = name_parts[-1]
    elif cultural_context == 'eastern':
        last_name = name_parts[0]
    elif cultural_context == 'arabic':
        # Assuming 'al-' as a common prefix in Arabic names
        last_name = next((part for part in name_parts if 'al-' in part), name_parts[-1])
    elif cultural_context == 'custom' and custom_rules:
        # Custom parsing logic can be implemented here
        last_name = name_parts[-1]  # Default to last part if no custom logic

    # Include middle name if specified
    if include_middle_name and len(name_parts) > 2:
        middle_name = name_parts[1:-1] if cultural_context == 'western' else name_parts[1:]
        last_name = ' '.join(middle_name + [last_name])

    return {'last_name': last_name}

