def count_repeated_letters_v2(input, case_sensitive=False, include_special_characters=False, character_types=['letters'], output_format='summary', ignore_whitespace=True):
    # Validate input parameter
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}

    # Validate character_types parameter
    valid_character_types = {'letters', 'digits', 'special'}
    if not all(ct in valid_character_types for ct in character_types):
        return {'error': 'Invalid character type specified.'}

    # Validate output_format parameter
    if output_format not in {'summary', 'detailed'}:
        return {'error': 'Invalid output format specified.'}

    # Prepare the string for analysis
    if not case_sensitive:
        input = input.lower()

    # Filter characters based on character_types
    filtered_input = ''
    for char in input:
        if 'letters' in character_types and char.isalpha():
            filtered_input += char
        elif 'digits' in character_types and char.isdigit():
            filtered_input += char
        elif 'special' in character_types and not char.isalnum():
            filtered_input += char

    # Ignore whitespace if specified
    if ignore_whitespace:
        filtered_input = filtered_input.replace(' ', '')

    # Count repeated characters
    from collections import Counter
    char_count = Counter(filtered_input)
    repeated_count = {char: count for char, count in char_count.items() if count > 1}

    # Prepare output
    if output_format == 'summary':
        return {'repeated_count': sum(repeated_count.values())}
    elif output_format == 'detailed':
        return {'repeated_details': repeated_count}

    return {'error': 'Unexpected error occurred.'}

