def vowel_counter(input, case_sensitive=False, output_format='integer', specific_vowels=[], ignore_non_alphabetic=True):
    # Validate input
    if not isinstance(input, list) or len(input) == 0:
        return {'error': 'Input must be a non-empty list of strings.'}
    if not all(isinstance(s, str) for s in input):
        return {'error': 'All items in input must be strings.'}
    if specific_vowels and not all(v in 'aeiou' for v in specific_vowels):
        return {'error': 'Specific vowels must be a subset of [a, e, i, o, u].'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Output format must be one of [integer, text, detailed].'}

    # Define vowels
    vowels = 'aeiou'
    if case_sensitive:
        vowels += vowels.upper()
    if specific_vowels:
        vowels = ''.join(specific_vowels)
        if case_sensitive:
            vowels += ''.join(v.upper() for v in specific_vowels)

    # Count vowels
    total_count = 0
    detailed_count = {v: 0 for v in vowels}
    for string in input:
        for char in string:
            if ignore_non_alphabetic and not char.isalpha():
                continue
            if char in vowels:
                total_count += 1
                if output_format == 'detailed':
                    detailed_count[char] += 1

    # Prepare output
    if output_format == 'integer':
        return total_count
    elif output_format == 'text':
        return f'Total vowels: {total_count}'
    elif output_format == 'detailed':
        return detailed_count

