def extract_first_name(full_name, delimiter=' ', case_sensitive=False, include_titles=False, include_suffixes=False):
    # Error handling for incorrect input types
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name: must be a non-empty string.'}
    if not isinstance(delimiter, str) or len(delimiter) != 1:
        return {'error': 'Invalid delimiter: must be a single character string.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive: must be a boolean value.'}
    if not isinstance(include_titles, bool):
        return {'error': 'Invalid include_titles: must be a boolean value.'}
    if not isinstance(include_suffixes, bool):
        return {'error': 'Invalid include_suffixes: must be a boolean value.'}

    # Titles and suffixes lists
    titles = ['Mr.', 'Mrs.', 'Ms.', 'Dr.', 'Prof.'] if include_titles else []
    suffixes = ['Jr.', 'Sr.', 'II', 'III', 'IV'] if include_suffixes else []

    # Split the full name by the delimiter
    parts = full_name.split(delimiter)

    # Remove titles and suffixes if not included
    if not include_titles:
        parts = [part for part in parts if part not in titles]
    if not include_suffixes:
        parts = [part for part in parts if part not in suffixes]

    # Extract the first name
    first_name = parts[0] if parts else ''

    # Adjust case sensitivity
    if not case_sensitive:
        first_name = first_name.capitalize()

    return {'first_name': first_name}

