def first_letter_extractor_v2(input, output_format='character', ignore_non_alpha=False, error_handling='warn'):
    # Validate input type
    if not isinstance(input, list) or not all(isinstance(i, str) for i in input):
        raise ValueError("Input must be a list of strings.")

    # Validate output_format
    if output_format not in ['character', 'text', 'json', 'list']:
        raise ValueError("Invalid output_format. Must be one of 'character', 'text', 'json', 'list'.")

    # Validate error_handling
    if error_handling not in ['ignore', 'warn', 'strict']:
        raise ValueError("Invalid error_handling. Must be one of 'ignore', 'warn', 'strict'.")

    # Initialize result list
    results = []
    warnings = []

    for string in input:
        if not string:
            if error_handling == 'strict':
                raise ValueError("Empty string encountered.")
            elif error_handling == 'warn':
                warnings.append("Empty string encountered.")
            continue

        # Extract first letter
        first_letter = None
        for char in string:
            if char.isalpha() or not ignore_non_alpha:
                first_letter = char
                break

        if first_letter is None:
            if error_handling == 'strict':
                raise ValueError("No valid starting character found.")
            elif error_handling == 'warn':
                warnings.append(f"No valid starting character in '{string}'.")
            continue

        results.append(first_letter)

    # Format output
    if output_format == 'character':
        return results[0] if results else None
    elif output_format == 'text':
        return ''.join(results)
    elif output_format == 'json':
        return {i: results[i] for i in range(len(results))}
    elif output_format == 'list':
        return results

    # Return warnings if any
    if warnings and error_handling == 'warn':
        print("Warnings:", warnings)

