def extract_last_name(full_name: str, delimiter: str = ' ', ignore_suffix: bool = False, handle_compound_last_names: bool = True, cultural_convention: str = 'Western', include_prefix: bool = False, middle_name_handling: str = 'ignore') -> str:
    # Error handling for invalid inputs
    if not isinstance(full_name, str) or not full_name.strip():
        return 'Error: full_name must be a non-empty string.'
    if not isinstance(delimiter, str):
        return 'Error: delimiter must be a string.'
    if not isinstance(ignore_suffix, bool):
        return 'Error: ignore_suffix must be a boolean.'
    if not isinstance(handle_compound_last_names, bool):
        return 'Error: handle_compound_last_names must be a boolean.'
    if cultural_convention not in ['Western', 'Eastern']:
        return 'Error: cultural_convention must be either "Western" or "Eastern".'
    if not isinstance(include_prefix, bool):
        return 'Error: include_prefix must be a boolean.'
    if middle_name_handling not in ['ignore', 'include', 'separate']:
        return 'Error: middle_name_handling must be "ignore", "include", or "separate".'

    # Split the full name based on the delimiter
    name_parts = full_name.split(delimiter)

    # Handle cultural conventions and compound last names
    if cultural_convention == 'Western':
        # Western convention typically has the last name at the end
        last_name = name_parts[-1]
        if handle_compound_last_names and len(name_parts) > 1:
            # Check for compound last names
            if name_parts[-2].lower() in ['de', 'la', 'van', 'von']:
                last_name = delimiter.join(name_parts[-2:])
    else:
        # Eastern convention typically has the last name at the beginning
        last_name = name_parts[0]

    # Handle suffixes if needed
    if ignore_suffix:
        suffixes = ['Jr.', 'Sr.', 'II', 'III']
        if last_name in suffixes:
            last_name = name_parts[-2] if cultural_convention == 'Western' else name_parts[1]

    # Include prefix if specified
    if include_prefix and len(name_parts) > 1:
        prefixes = ['Dr.', 'Mr.', 'Ms.', 'Mrs.']
        if name_parts[0] in prefixes:
            last_name = name_parts[0] + delimiter + last_name

    return last_name

