    if not isinstance(date, str):
        return {'error': 'Invalid input: date must be a string.'}
    if output_format not in ['hours', 'detailed', 'full_report']:
        return {'error': 'Invalid input: output_format must be one of ["hours", "detailed", "full_report"].'}
    if recurrence not in ['none', 'daily', 'weekly', 'monthly']:
        return {'error': 'Invalid input: recurrence must be one of ["none", "daily", "weekly", "monthly"].'}

    # Parse the date
    try:
        if 'T' in date:
            date_obj = datetime.fromisoformat(date)
        else:
            date_obj = datetime.strptime(date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid date format. Use YYYY-MM-DD or YYYY-MM-DDTHH:MM:SS.'}

    # Calculate time difference
    results = {}
    for location in locations:
        try:
            local_tz = pytz.timezone(location)
            local_time = local_tz.localize(date_obj)
            utc_time = local_time.astimezone(pytz.utc)
            time_difference = (local_time.utcoffset() - utc_time.utcoffset()).total_seconds() / 3600
            results[location] = time_difference
        except Exception as e:
            results[location] = f'Error calculating time difference: {str(e)}'

    # Format output
    if output_format == 'hours':
        return {'time_differences': results}
    elif output_format == 'detailed':
        return {'detailed_report': results, 'additional_info': 'Includes daylight saving time adjustments.'}
    elif output_format == 'full_report':
        return {'full_report': results, 'historical_changes': 'Includes historical changes in time zone definitions.'}

    return {'error': 'Unexpected error occurred.'}

