def character_counter(input, ignore_characters=[], ignore_position=[], ignore_position_range={'start': 0, 'end': 0}, case_sensitive=False, output_format='integer'):
    """
    Counts the number of characters in the input string based on specified parameters.
    """
    # Error handling for required parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Error handling for ignore_characters
    if not all(isinstance(char, str) for char in ignore_characters):
        return {'error': 'Invalid ignore_characters type. Each character must be a string.'}

    # Error handling for ignore_position
    valid_positions = {'first', 'last', 'range'}
    if not all(pos in valid_positions for pos in ignore_position):
        return {'error': 'Invalid ignore_position value. Must be one of first, last, or range.'}

    # Error handling for ignore_position_range
    if not isinstance(ignore_position_range, dict) or 'start' not in ignore_position_range or 'end' not in ignore_position_range:
        return {'error': 'Invalid ignore_position_range. Must be a dictionary with start and end keys.'}
    if not isinstance(ignore_position_range['start'], int) or not isinstance(ignore_position_range['end'], int):
        return {'error': 'Invalid range values. Start and end must be integers.'}

    # Error handling for case_sensitive
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive value. Must be a boolean.'}

    # Error handling for output_format
    valid_formats = {'integer', 'text', 'detailed'}
    if output_format not in valid_formats:
        return {'error': 'Invalid output_format. Must be one of integer, text, or detailed.'}

    # Adjust input for case sensitivity
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Initialize count
    count = 0
    detailed_count = {}

    # Determine positions to ignore
    ignore_indices = set()
    if 'first' in ignore_position:
        ignore_indices.add(0)
    if 'last' in ignore_position:
        ignore_indices.add(len(input) - 1)
    if 'range' in ignore_position:
        ignore_indices.update(range(ignore_position_range['start'], ignore_position_range['end'] + 1))

    # Count characters
    for i, char in enumerate(input):
        if i in ignore_indices or char in ignore_characters:
            continue
        count += 1
        if output_format == 'detailed':
            if char in detailed_count:
                detailed_count[char] += 1
            else:
                detailed_count[char] = 1

    # Return result based on output_format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'Total characters: {count}'
    elif output_format == 'detailed':
        return detailed_count

