def extract_last_name(full_name, delimiter=' ', ignore_prefixes=[], ignore_suffixes=[], include_middle_names=False, compound_last_name_delimiters=['-']):
    # Check if full_name is a valid string
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name provided. It must be a non-empty string.'}

    # Split the full name using the specified delimiter
    name_parts = full_name.split(delimiter)

    # Remove any prefixes
    name_parts = [part for part in name_parts if part not in ignore_prefixes]

    # Remove any suffixes
    if ignore_suffixes:
        name_parts = [part for part in name_parts if part not in ignore_suffixes]

    # If include_middle_names is False, consider only the last part as the last name
    if not include_middle_names:
        last_name = name_parts[-1]
    else:
        # Consider all parts after the first as the last name
        last_name = delimiter.join(name_parts[1:])

    # Handle compound last names
    for compound_delimiter in compound_last_name_delimiters:
        if compound_delimiter in last_name:
            last_name_parts = last_name.split(compound_delimiter)
            last_name = compound_delimiter.join(last_name_parts)
            break

    return {'last_name': last_name}

