def count_letters(input: str, ignore_characters: list = [], ignore_position: list = [], case_sensitive: bool = False, output_format: str = 'integer') -> any:
    # Validate input
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not all(isinstance(char, str) for char in ignore_characters):
        return {'error': 'All ignore_characters must be strings.'}
    if not all(pos in ['first', 'last', 'even', 'odd'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position value.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format value.'}

    # Prepare input
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Filter characters
    filtered_input = [char for i, char in enumerate(input)
                      if char.isalpha() and
                      char not in ignore_characters and
                      not ((i == 0 and 'first' in ignore_position) or
                           (i == len(input) - 1 and 'last' in ignore_position) or
                           (i % 2 == 0 and 'even' in ignore_position) or
                           (i % 2 != 0 and 'odd' in ignore_position))]

    # Count letters
    letter_count = len(filtered_input)

    # Generate output
    if output_format == 'integer':
        return letter_count
    elif output_format == 'text':
        return f'The number of letters is {letter_count}.'
    elif output_format == 'detailed':
        from collections import Counter
        return dict(Counter(filtered_input))

