def date_calculator(start_date: str, time_unit: str, amount: int, calendar_system: str = 'gregorian', time_zone: str = '+00:00') -> str:
    from datetime import datetime, timedelta
    import pytz
    from dateutil.relativedelta import relativedelta

    # Error handling for input validation
    try:
        # Parse the start_date with timezone
        start_date = datetime.strptime(start_date, '%Y-%m-%dT%H:%M:%SZ')
        start_date = start_date.replace(tzinfo=pytz.timezone('UTC'))
    except ValueError:
        return 'Error: Invalid start_date format. Expected YYYY-MM-DDTHH:MM:SSZ.'

    # Adjust for the specified time zone
    try:
        tz_offset = pytz.timezone('Etc/GMT' + time_zone.replace(':', ''))
        start_date = start_date.astimezone(tz_offset)
    except Exception as e:
        return f'Error: Invalid time_zone format or value. {str(e)}'

    # Calculate the new date based on the time_unit
    try:
        if time_unit == 'minutes':
            delta = timedelta(minutes=amount)
        elif time_unit == 'hours':
            delta = timedelta(hours=amount)
        elif time_unit == 'days':
            delta = timedelta(days=amount)
        elif time_unit == 'weeks':
            delta = timedelta(weeks=amount)
        elif time_unit == 'months':
            delta = relativedelta(months=amount)
        elif time_unit == 'years':
            delta = relativedelta(years=amount)
        else:
            return 'Error: Invalid time_unit. Must be one of minutes, hours, days, weeks, months, years.'

        new_date = start_date + delta
    except Exception as e:
        return f'Error: Calculation failed. {str(e)}'

    # Return the new date in the specified format
    return new_date.strftime('%Y-%m-%d')

