def extract_last_name(names, consider_middle_names=True, handle_suffixes=True, output_format='string', handle_compound_last_names=True, cultural_naming_conventions='western', error_handling='warn'):
    """
    Extracts last names from a list of full names based on various parameters.

    Parameters:
    - names (list of str): The full names from which to extract the last names.
    - consider_middle_names (bool): Whether to consider middle names in the parsing process.
    - handle_suffixes (bool): Whether to handle suffixes like Jr., Sr., III, etc.
    - output_format (str): The format of the output ('string', 'array', 'json').
    - handle_compound_last_names (bool): Whether to handle compound last names.
    - cultural_naming_conventions (str): The cultural naming convention to consider ('western', 'eastern', 'custom').
    - error_handling (str): The error handling strategy ('ignore', 'warn', 'strict').

    Returns:
    - str, list, or dict: The extracted last names in the specified format.
    """
    if not isinstance(names, list) or not all(isinstance(name, str) for name in names):
        if error_handling == 'strict':
            raise ValueError("'names' must be a list of strings.")
        elif error_handling == 'warn':
            print("Warning: 'names' must be a list of strings.")
            return None
        else:
            return None

    last_names = []
    for name in names:
        parts = name.split()
        if cultural_naming_conventions == 'western':
            if handle_suffixes and parts[-1] in ['Jr.', 'Sr.', 'III']:
                last_name = parts[-2]
            else:
                last_name = parts[-1]
        elif cultural_naming_conventions == 'eastern':
            last_name = parts[0]
        else:  # custom or other conventions
            last_name = parts[-1]  # default to western-style

        if handle_compound_last_names:
            # Example logic for compound last names
            if len(parts) > 1 and parts[-2].lower() in ['de', 'la', 'van']:
                last_name = ' '.join(parts[-2:])

        last_names.append(last_name)

    if output_format == 'string':
        return last_names[0] if last_names else ''
    elif output_format == 'array':
        return last_names
    elif output_format == 'json':
        return {"last_names": last_names}
    else:
        if error_handling == 'strict':
            raise ValueError("Invalid output format specified.")
        elif error_handling == 'warn':
            print("Warning: Invalid output format specified.")
            return None
        else:
            return None

