def count_consonants(input, ignore_characters=None, ignore_position=None, case_sensitive=False, character_set='latin', detailed_output=False):
    # Error handling for required parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Default values for optional parameters
    if ignore_characters is None:
        ignore_characters = []
    if ignore_position is None:
        ignore_position = []

    # Validate optional parameters
    if not isinstance(ignore_characters, list) or not all(isinstance(c, str) for c in ignore_characters):
        return {'error': 'Invalid ignore_characters type. Must be a list of strings.'}
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position value. Must be a list containing "first" or "last".'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive type. Must be a boolean.'}
    if character_set not in ['latin', 'cyrillic', 'greek']:
        return {'error': 'Invalid character_set value. Must be "latin", "cyrillic", or "greek".'}
    if not isinstance(detailed_output, bool):
        return {'error': 'Invalid detailed_output type. Must be a boolean.'}

    # Define consonants based on character set
    consonants = {
        'latin': 'bcdfghjklmnpqrstvwxyz',
        'cyrillic': 'бвгджзйклмнпрстфхцчшщ',
        'greek': 'βγδζθκλμνξπρστφχψ'
    }[character_set]

    # Adjust for case sensitivity
    if not case_sensitive:
        input = input.lower()
        consonants = consonants.lower()

    # Initialize consonant count
    consonant_count = 0
    detailed_counts = {}

    # Iterate over input string
    for i, char in enumerate(input):
        if char in ignore_characters:
            continue
        if 'first' in ignore_position and i == 0:
            continue
        if 'last' in ignore_position and i == len(input) - 1:
            continue
        if char in consonants:
            consonant_count += 1
            if detailed_output:
                if char not in detailed_counts:
                    detailed_counts[char] = 0
                detailed_counts[char] += 1

    # Return result
    if detailed_output:
        return {'total_consonants': consonant_count, 'detailed_counts': detailed_counts}
    else:
        return {'total_consonants': consonant_count}

