def reverse_number_advanced(number, output_format='string', handle_negative=True, base=10, preserve_decimal=True):
    """
    Reverses the order of digits in a given number based on specified parameters.
    """
    # Error handling for unsupported bases
    if not (2 <= base <= 36):
        return {'error': 'Base must be between 2 and 36.'}

    # Convert number to string in the specified base
    try:
        if base != 10:
            num_str = format(int(number), f'{base}').upper()
        else:
            num_str = str(number)
    except ValueError:
        return {'error': 'Invalid number for the specified base.'}

    # Handle negative numbers
    if handle_negative and num_str.startswith('-'):
        num_str = num_str[1:]
        negative = True
    else:
        negative = False

    # Reverse the number string
    if preserve_decimal and '.' in num_str:
        integer_part, decimal_part = num_str.split('.')
        reversed_num_str = integer_part[::-1] + '.' + decimal_part[::-1]
    else:
        reversed_num_str = num_str[::-1]

    # Reapply negative sign if needed
    if negative:
        reversed_num_str = '-' + reversed_num_str

    # Format output based on output_format
    if output_format == 'number':
        try:
            reversed_number = float(reversed_num_str) if '.' in reversed_num_str else int(reversed_num_str)
        except ValueError:
            return {'error': 'Reversed number is not valid in the specified format.'}
        return reversed_number
    elif output_format == 'scientific':
        try:
            reversed_number = float(reversed_num_str)
            return f'{reversed_number:.2e}'
        except ValueError:
            return {'error': 'Reversed number is not valid in scientific format.'}
    else:  # Default to string
        return reversed_num_str

