def last_letter_extractor_plus(input: str, ignore_special_characters: bool = False, output_format: str = 'character', case_sensitive: bool = True, trim_whitespace: bool = False, number_of_letters: int = 1):
    # Validate input parameters
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if output_format not in ['character', 'ascii', 'unicode', 'hex']:
        return {'error': 'Invalid output format.'}
    if number_of_letters < 1:
        return {'error': 'Number of letters must be at least 1.'}

    # Trim whitespace if required
    if trim_whitespace:
        input = input.rstrip()

    # Ignore special characters if required
    if ignore_special_characters:
        input = ''.join(filter(str.isalnum, input))

    # Extract the last letter(s)
    extracted = input[-number_of_letters:]

    # Convert the extracted letters based on the output format
    if output_format == 'ascii':
        result = [ord(char) for char in extracted]
    elif output_format == 'unicode':
        result = [f'U+{ord(char):04X}' for char in extracted]
    elif output_format == 'hex':
        result = [hex(ord(char)) for char in extracted]
    else:  # Default to 'character'
        result = extracted

    return {'result': result}

