def extract_name_components(full_name, ignore_prefixes=False, ignore_suffixes=False, output_format='string', name_order='western'):
    # Error handling for required parameter
    if not full_name or not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a non-empty string.'}

    # Split the full name into components
    name_parts = full_name.split()

    # Handle name order
    if name_order == 'eastern':
        # Eastern order: last-first-middle
        last_name = name_parts[0] if len(name_parts) > 0 else ''
        first_name = name_parts[1] if len(name_parts) > 1 else ''
        middle_name = ' '.join(name_parts[2:]) if len(name_parts) > 2 else ''
    else:
        # Western order: first-middle-last
        first_name = name_parts[0] if len(name_parts) > 0 else ''
        middle_name = ' '.join(name_parts[1:-1]) if len(name_parts) > 2 else ''
        last_name = name_parts[-1] if len(name_parts) > 1 else ''

    # Construct the output based on the specified format
    if output_format == 'array':
        return [first_name, middle_name, last_name]
    elif output_format == 'object':
        return {'first_name': first_name, 'middle_name': middle_name, 'last_name': last_name}
    else:
        return first_name

