def string_length_counter(input: str, ignore_characters: list = [], ignore_position: list = [], case_sensitive: bool = False, specific_indices: list = [], output_format: str = 'integer') -> str:
    # Error handling for input type
    if not isinstance(input, str):
        return 'Error: Input must be a string.'

    # Error handling for ignore_position values
    valid_positions = {'first', 'last', 'even', 'odd'}
    if any(pos not in valid_positions for pos in ignore_position):
        return 'Error: Invalid ignore_position value.'

    # Prepare the string based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Initialize character count
    count = 0
    detailed_count = {}

    # Iterate over each character in the string
    for index, char in enumerate(input):
        # Check if character should be ignored
        if char in ignore_characters:
            continue
        if index in specific_indices:
            continue
        if 'first' in ignore_position and index == 0:
            continue
        if 'last' in ignore_position and index == len(input) - 1:
            continue
        if 'even' in ignore_position and index % 2 == 0:
            continue
        if 'odd' in ignore_position and index % 2 != 0:
            continue

        # Count the character
        count += 1
        if output_format == 'detailed':
            if char in detailed_count:
                detailed_count[char] += 1
            else:
                detailed_count[char] = 1

    # Format the output
    if output_format == 'integer':
        return str(count)
    elif output_format == 'text':
        return f'The total number of characters is {count}.'
    elif output_format == 'detailed':
        return f'Detailed count: {detailed_count}'
    else:
        return 'Error: Invalid output format.'

