def date_calculator(start_date, days_difference, output_format='YYYY-MM-DD', time_zone='UTC', business_days_only=False, exclude_holidays=None):
    from datetime import datetime, timedelta
    import pytz
    from dateutil import parser
    import holidays

    # Validate start_date format
    try:
        start_date_obj = datetime.strptime(start_date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid start_date format. Expected YYYY-MM-DD.'}

    # Validate days_difference
    if not isinstance(days_difference, int):
        return {'error': 'days_difference must be an integer.'}

    # Validate output_format
    valid_formats = ['YYYY-MM-DD', 'MM-DD-YYYY', 'DD-MM-YYYY', 'ISO8601', 'RFC2822']
    if output_format not in valid_formats:
        return {'error': f'Invalid output_format. Choose from {valid_formats}.'}

    # Validate time_zone
    try:
        tz = pytz.timezone(time_zone)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time_zone specified.'}

    # Validate exclude_holidays
    if exclude_holidays:
        for holiday in exclude_holidays:
            try:
                datetime.strptime(holiday, '%Y-%m-%d')
            except ValueError:
                return {'error': f'Invalid holiday format: {holiday}. Expected YYYY-MM-DD.'}

    # Calculate the target date
    current_date = start_date_obj
    days_remaining = abs(days_difference)
    step = 1 if days_difference > 0 else -1

    while days_remaining > 0:
        current_date += timedelta(days=step)
        if business_days_only:
            if current_date.weekday() >= 5:  # Skip weekends
                continue
            if exclude_holidays and current_date.strftime('%Y-%m-%d') in exclude_holidays:
                continue
        days_remaining -= 1

    # Adjust for time zone
    current_date = tz.localize(current_date)

    # Format the output date
    if output_format == 'YYYY-MM-DD':
        result_date = current_date.strftime('%Y-%m-%d')
    elif output_format == 'MM-DD-YYYY':
        result_date = current_date.strftime('%m-%d-%Y')
    elif output_format == 'DD-MM-YYYY':
        result_date = current_date.strftime('%d-%m-%Y')
    elif output_format == 'ISO8601':
        result_date = current_date.isoformat()
    elif output_format == 'RFC2822':
        result_date = current_date.strftime('%a, %d %b %Y %H:%M:%S %z')

    return {'result_date': result_date}

