def sum_of_digits(input: str, output_format: str = 'integer', ignore_negative_sign: bool = True, decimal_handling: str = 'ignore'):
    # Validate output_format
    if output_format not in ['integer', 'text', 'json', 'detailed']:
        return {'error': 'Invalid output_format. Choose from integer, text, json, detailed.'}

    # Validate decimal_handling
    if decimal_handling not in ['ignore', 'sum', 'average']:
        return {'error': 'Invalid decimal_handling. Choose from ignore, sum, average.'}

    # Process input
    digits = []
    for char in input:
        if char.isdigit():
            digits.append(int(char))
        elif char == '-' and not ignore_negative_sign:
            return {'error': 'Negative numbers are not supported unless ignore_negative_sign is true.'}

    # Handle decimal points
    if decimal_handling == 'sum':
        sum_digits = sum(digits)
    elif decimal_handling == 'average':
        sum_digits = sum(digits) / len(digits) if digits else 0
    else:  # 'ignore'
        sum_digits = sum(digits)

    # Format output
    if output_format == 'integer':
        return sum_digits
    elif output_format == 'text':
        return f'The sum of the digits is {sum_digits}.'
    elif output_format == 'json':
        return {'sum': sum_digits}
    elif output_format == 'detailed':
        return {
            'input': input,
            'processed_digits': digits,
            'sum': sum_digits,
            'ignore_negative_sign': ignore_negative_sign,
            'decimal_handling': decimal_handling
        }

