def distinct_combinations(input: str, combination_length: int = 2, case_sensitive: bool = False, output_format: str = 'array', include_special_characters: bool = False, trim_whitespace: bool = True):
    # Validate input
    if not isinstance(input, str) or len(input) < 2:
        raise ValueError('Input must be a string with at least two characters.')
    if combination_length < 2:
        raise ValueError('Combination length must be at least 2.')
    if output_format not in ['array', 'count', 'string']:
        raise ValueError("Output format must be 'array', 'count', or 'string'.")

    # Trim whitespace if required
    if trim_whitespace:
        input = input.strip()

    # Handle case sensitivity
    if not case_sensitive:
        input = input.lower()

    # Filter out special characters if not included
    if not include_special_characters:
        input = ''.join(filter(str.isalnum, input))

    # Generate combinations
    from itertools import combinations
    unique_combinations = set(combinations(input, combination_length))

    # Format output
    if output_format == 'array':
        return [''.join(comb) for comb in unique_combinations]
    elif output_format == 'count':
        return len(unique_combinations)
    elif output_format == 'string':
        return ''.join([''.join(comb) for comb in unique_combinations])

