def date_calculator(base_date: str, days_offset: int, time_offset: dict = {'hours': 0, 'minutes': 0, 'seconds': 0}, output_format: str = 'YYYY-MM-DDTHH:MM:SS', calendar_system: str = 'gregorian', timezone: str = 'UTC', date_difference: dict = None) -> str:
    from datetime import datetime, timedelta
    import pytz

    # Error handling for base_date format
    try:
        base_date_obj = datetime.strptime(base_date, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return 'Error: base_date must be in YYYY-MM-DDTHH:MM:SS format.'

    # Error handling for timezone
    try:
        tz = pytz.timezone(timezone)
    except pytz.UnknownTimeZoneError:
        return 'Error: Unknown timezone specified.'

    # Apply timezone to base_date
    base_date_obj = tz.localize(base_date_obj)

    # Calculate new date
    new_date_obj = base_date_obj + timedelta(days=days_offset, 
                                             hours=time_offset.get('hours', 0), 
                                             minutes=time_offset.get('minutes', 0), 
                                             seconds=time_offset.get('seconds', 0))

    # Format output
    if output_format == 'YYYY-MM-DD':
        return new_date_obj.strftime('%Y-%m-%d')
    elif output_format == 'MM/DD/YYYY':
        return new_date_obj.strftime('%m/%d/%Y')
    elif output_format == 'DD-MM-YYYY':
        return new_date_obj.strftime('%d-%m-%Y')
    elif output_format == 'YYYY-MM-DDTHH:MM:SS':
        return new_date_obj.strftime('%Y-%m-%dT%H:%M:%S')
    else:
        return 'Error: Invalid output format specified.'

