def extract_last_letter(input, output_format='character', case_sensitive=False, error_handling='warn'):
    """
    Extracts the last letter from each string in the input list.
    :param input: List of strings to process.
    :param output_format: The format of the output ('character', 'text', 'json', 'xml').
    :param case_sensitive: Boolean indicating if extraction should be case sensitive.
    :param error_handling: Strategy for handling empty strings ('ignore', 'warn', 'error').
    :return: Extracted last letters in the specified format.
    """
    import json
    import xml.etree.ElementTree as ET

    results = []
    warnings = []

    for string in input:
        if not string:
            if error_handling == 'warn':
                warnings.append('Empty string encountered.')
            elif error_handling == 'error':
                raise ValueError('Empty string encountered.')
            continue

        last_letter = string[-1]
        if not case_sensitive:
            last_letter = last_letter.lower()

        results.append(last_letter)

    if output_format == 'character':
        return results[0] if results else None
    elif output_format == 'text':
        return ' '.join(results)
    elif output_format == 'json':
        return json.dumps({'last_letters': results})
    elif output_format == 'xml':
        root = ET.Element('LastLetters')
        for letter in results:
            ET.SubElement(root, 'Letter').text = letter
        return ET.tostring(root, encoding='unicode')

    if warnings:
        print('Warnings:', warnings)

