print(result)  # Expected output: 'a'

def char_to_binary(characters, bit_format=8, output_format='binary_string', error_handling='strict'):
    # Validate bit_format
    if bit_format not in [8, 16, 32]:
        raise ValueError("Invalid bit_format. Supported formats are 8, 16, or 32.")

    # Validate output_format
    if output_format not in ['binary_string', 'integer', 'hexadecimal']:
        raise ValueError("Invalid output_format. Supported formats are 'binary_string', 'integer', or 'hexadecimal'.")

    # Validate error_handling
    if error_handling not in ['ignore', 'strict']:
        raise ValueError("Invalid error_handling. Supported options are 'ignore' or 'strict'.")

    result = []
    for char in characters:
        try:
            # Convert character to binary
            binary_value = format(ord(char), f'0{bit_format}b')
            if output_format == 'binary_string':
                result.append(binary_value)
            elif output_format == 'integer':
                result.append(int(binary_value, 2))
            elif output_format == 'hexadecimal':
                result.append(hex(int(binary_value, 2)))
        except Exception as e:
            if error_handling == 'strict':
                raise ValueError(f"Unsupported character '{char}' encountered.") from e
            elif error_handling == 'ignore':
                continue
    return result

