def reverse_string(input: str, case_transformation: str = 'none', reverse_by: str = 'characters', trim_whitespace: bool = False, ignore_characters: str = '') -> str:
    # Error handling for parameter types and values
    if not isinstance(input, str):
        raise ValueError("Input must be a string.")
    if case_transformation not in ['none', 'uppercase', 'lowercase']:
        raise ValueError("case_transformation must be 'none', 'uppercase', or 'lowercase'.")
    if reverse_by not in ['characters', 'words']:
        raise ValueError("reverse_by must be 'characters' or 'words'.")
    if not isinstance(trim_whitespace, bool):
        raise ValueError("trim_whitespace must be a boolean.")
    if not isinstance(ignore_characters, str):
        raise ValueError("ignore_characters must be a string.")

    # Trim whitespace if required
    if trim_whitespace:
        input = input.strip()

    # Remove ignored characters
    if ignore_characters:
        input = ''.join(c for c in input if c not in ignore_characters)

    # Reverse the string by characters or words
    if reverse_by == 'characters':
        reversed_string = input[::-1]
    else:  # reverse_by == 'words'
        reversed_string = ' '.join(input.split()[::-1])

    # Apply case transformation
    if case_transformation == 'uppercase':
        reversed_string = reversed_string.upper()
    elif case_transformation == 'lowercase':
        reversed_string = reversed_string.lower()

    return reversed_string

