    # Perform the operation
    if operation == 'previous_year':
        result = input_year - 1
    else:
        return {'error': 'Operation not implemented in this context.'}

    # Format the output
    if output_format == 'integer':
        return result
    elif output_format == 'string':
        return str(result)
