def date_parser(date_input: str, output_component: str = 'month', date_format: str = None, time_zone: str = None, output_format: str = None):
    from datetime import datetime
    import pytz

    # Default output component is 'month'
    if output_component not in ['month', 'day', 'year', 'hour', 'minute', 'second']:
        return {'error': 'Invalid output component specified.'}

    # Attempt to parse the date
    try:
        # If a date format is provided, use it
        if date_format:
            date_obj = datetime.strptime(date_input, date_format)
        else:
            # Try common formats if no format is provided
            date_obj = datetime.strptime(date_input, '%d %B %Y')

        # Handle time zone if provided
        if time_zone:
            try:
                tz = pytz.timezone(time_zone)
                date_obj = tz.localize(date_obj)
            except pytz.UnknownTimeZoneError:
                return {'error': 'Unknown time zone specified.'}

        # Extract the desired component
        if output_component == 'month':
            result = date_obj.month
        elif output_component == 'day':
            result = date_obj.day
        elif output_component == 'year':
            result = date_obj.year
        elif output_component == 'hour':
            result = date_obj.hour
        elif output_component == 'minute':
            result = date_obj.minute
        elif output_component == 'second':
            result = date_obj.second

        # Apply output format if specified
        if output_format:
            result = format(result, output_format)

        return {'result': result}
    except ValueError:
        return {'error': 'Date format is incorrect or not supported.'}

