def advanced_timezone_difference_calculator(timezones, date_range, output_format='hours'):
    import pytz
    from datetime import datetime

    # Validate input parameters
    if not isinstance(timezones, list) or len(timezones) < 2:
        return {'error': 'At least two time zones must be specified.'}
    if not isinstance(date_range, dict) or 'start_date' not in date_range or 'end_date' not in date_range:
        return {'error': 'Date range must include start_date and end_date.'}
    if output_format not in ['hours', 'minutes', 'detailed', 'summary']:
        return {'error': 'Invalid output format specified.'}

    try:
        # Parse dates
        start_date = datetime.strptime(date_range['start_date'], '%Y-%m-%d')
        end_date = datetime.strptime(date_range['end_date'], '%Y-%m-%d')
    except ValueError:
        return {'error': 'Dates must be in YYYY-MM-DD format.'}

    # Initialize timezone objects
    try:
        tz1 = pytz.timezone(timezones[0])
        tz2 = pytz.timezone(timezones[1])
    except pytz.UnknownTimeZoneError:
        return {'error': 'One or more specified time zones are invalid.'}

    # Calculate time difference
    try:
        dt_start_tz1 = tz1.localize(start_date)
        dt_start_tz2 = tz2.localize(start_date)
        dt_end_tz1 = tz1.localize(end_date)
        dt_end_tz2 = tz2.localize(end_date)

        # Calculate time differences
        diff_start = (dt_start_tz2 - dt_start_tz1).total_seconds() / 3600
        diff_end = (dt_end_tz2 - dt_end_tz1).total_seconds() / 3600

        # Determine output
        if output_format == 'hours':
            return {'difference_start': diff_start, 'difference_end': diff_end}
        elif output_format == 'minutes':
            return {'difference_start': diff_start * 60, 'difference_end': diff_end * 60}
        elif output_format == 'detailed':
            return {
                'start_date_difference': diff_start,
                'end_date_difference': diff_end,
                'details': f'Time difference from {timezones[0]} to {timezones[1]} varies from {diff_start} to {diff_end} hours over the specified date range.'
            }
        elif output_format == 'summary':
            avg_diff = (diff_start + diff_end) / 2
            return {'average_difference': avg_diff}
    except Exception as e:
        return {'error': str(e)}

