def prime_factorizer(number, output_format='list', sort_order='ascending', max_factors=None, include_performance_metrics=False):
    import time

    # Error handling for invalid 'number' input
    if not isinstance(number, int) or number <= 1:
        return {'error': 'Invalid input: number must be an integer greater than 1.'}

    # Convert negative numbers to their absolute values
    number = abs(number)

    # Function to calculate prime factors
    def calculate_prime_factors(n):
        factors = []
        # Check for number of 2s
        while n % 2 == 0:
            factors.append(2)
            n = n // 2
        # Check for odd factors
        for i in range(3, int(n**0.5) + 1, 2):
            while n % i == 0:
                factors.append(i)
                n = n // i
        # If n is a prime number greater than 2
        if n > 2:
            factors.append(n)
        return factors

    # Start performance timing
    start_time = time.time()

    # Calculate prime factors
    factors = calculate_prime_factors(number)

    # Sort factors
    factors = sorted(factors, reverse=(sort_order == 'descending'))

    # Limit the number of factors if max_factors is specified
    if max_factors is not None:
        factors = factors[:max_factors]

    # Prepare output
    if output_format == 'dictionary':
        from collections import Counter
        output = dict(Counter(factors))
    else:
        output = factors

    # Include performance metrics if requested
    if include_performance_metrics:
        computation_time = time.time() - start_time
        return {'factors': output, 'performance_metrics': {'computation_time': computation_time}}
    else:
        return {'factors': output}

