def character_extractor(input: str, position: str, custom_index: int = None, range_start: int = None, range_end: int = None, case_sensitive: bool = True, multi_byte_support: bool = False) -> str:
    """
    Extracts specific characters from a string based on the given position.

    Parameters:
    - input (str): The string from which to extract the character(s).
    - position (str): The position of the character(s) to extract ('first', 'last', 'custom', 'range').
    - custom_index (int, optional): The index of the character to extract if 'custom' is selected.
    - range_start (int, optional): The starting index of the range to extract if 'range' is selected.
    - range_end (int, optional): The ending index of the range to extract if 'range' is selected.
    - case_sensitive (bool): Indicates whether the extraction should be case-sensitive.
    - multi_byte_support (bool): Indicates whether the tool should handle multi-byte characters correctly.

    Returns:
    - str: The extracted character(s).
    """
    try:
        if position == 'first':
            return input[0] if case_sensitive else input[0].lower()
        elif position == 'last':
            return input[-1] if case_sensitive else input[-1].lower()
        elif position == 'custom':
            if custom_index is None or custom_index < 0 or custom_index >= len(input):
                raise ValueError("Invalid custom index.")
            return input[custom_index] if case_sensitive else input[custom_index].lower()
        elif position == 'range':
            if range_start is None or range_end is None or range_start < 0 or range_end >= len(input) or range_start > range_end:
                raise ValueError("Invalid range indices.")
            return input[range_start:range_end+1] if case_sensitive else input[range_start:range_end+1].lower()
        else:
            raise ValueError("Invalid position value.")
    except Exception as e:
        return str(e)

