def timezone_converter(input_datetime: str, source_timezone: str, target_timezone: str, utc_offset: float = None, output_format: str = 'ISO 8601', daylight_saving: bool = True, custom_format: str = None, error_handling: str = 'strict') -> str:
    import pytz
    from datetime import datetime

    try:
        # Parse the input datetime
        dt = datetime.fromisoformat(input_datetime.replace('Z', '+00:00'))

        # Handle source timezone
        if source_timezone not in pytz.all_timezones:
            if error_handling == 'strict':
                raise ValueError('Invalid source timezone')
            else:
                source_timezone = 'UTC'

        # Handle target timezone
        if target_timezone not in pytz.all_timezones:
            if error_handling == 'strict':
                raise ValueError('Invalid target timezone')
            else:
                target_timezone = 'UTC'

        # Convert to source timezone
        source_tz = pytz.timezone(source_timezone)
        dt = source_tz.localize(dt)

        # Adjust for UTC offset if provided
        if utc_offset is not None:
            dt = dt.astimezone(pytz.FixedOffset(int(utc_offset * 60)))

        # Convert to target timezone
        target_tz = pytz.timezone(target_timezone)
        dt = dt.astimezone(target_tz)

        # Format the output
        if output_format == 'ISO 8601':
            return dt.isoformat()
        elif output_format == 'RFC 2822':
            return dt.strftime('%a, %d %b %Y %H:%M:%S %z')
        elif output_format == 'custom' and custom_format is not None:
            return dt.strftime(custom_format)
        else:
            if error_handling == 'strict':
                raise ValueError('Invalid output format or custom format not provided')
            else:
                return dt.isoformat()
    except Exception as e:
        if error_handling == 'strict':
            raise e
        else:
            return str(e)

