def date_calculator(start_date_time, duration, calendar_system='Gregorian', time_zone='UTC', output_format='YYYY-MM-DDTHH:MM:SS', calculate_difference=False, end_date_time=None):
    from datetime import datetime, timedelta
    import pytz

    # Validate start_date_time format
    try:
        start_date = datetime.strptime(start_date_time, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return {'error': 'Invalid start_date_time format. Expected YYYY-MM-DDTHH:MM:SS.'}

    # Validate duration
    if duration['unit'] not in ['seconds', 'minutes', 'hours', 'days', 'weeks', 'months', 'years']:
        return {'error': 'Invalid duration unit. Supported units are seconds, minutes, hours, days, weeks, months, years.'}

    # Calculate new date based on duration
    if duration['unit'] == 'weeks':
        delta = timedelta(weeks=duration['value'])
    elif duration['unit'] == 'days':
        delta = timedelta(days=duration['value'])
    elif duration['unit'] == 'hours':
        delta = timedelta(hours=duration['value'])
    elif duration['unit'] == 'minutes':
        delta = timedelta(minutes=duration['value'])
    elif duration['unit'] == 'seconds':
        delta = timedelta(seconds=duration['value'])
    else:
        return {'error': 'Duration unit not supported for this operation.'}

    # Adjust for time zone
    try:
        tz = pytz.timezone(time_zone)
        start_date = tz.localize(start_date)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time zone specified.'}

    # Calculate new date
    new_date = start_date + delta

    # Format output
    if output_format == 'YYYY-MM-DDTHH:MM:SS':
        formatted_date = new_date.strftime('%Y-%m-%dT%H:%M:%S')
    elif output_format == 'MM-DD-YYYY HH:MM:SS':
        formatted_date = new_date.strftime('%m-%d-%Y %H:%M:%S')
    elif output_format == 'DD-MM-YYYY HH:MM:SS':
        formatted_date = new_date.strftime('%d-%m-%Y %H:%M:%S')
    else:
        return {'error': 'Invalid output format specified.'}

    return {'result': formatted_date}

