def enhanced_unique_letter_counter(input, case_sensitive=False, ignore_non_alpha=True, include_chars='', exclude_chars='', count_frequencies=False, output_format='dict'):
    # Validate input type
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}

    # Initialize a set for unique letters
    unique_letters = set()
    frequencies = {}

    # Normalize input based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        include_chars = include_chars.lower()
        exclude_chars = exclude_chars.lower()

    # Iterate over each character in the input
    for char in input:
        # Check if character is alphabetic or included in include_chars
        if (char.isalpha() or char in include_chars) and char not in exclude_chars:
            if ignore_non_alpha and not char.isalpha():
                continue
            # Add to unique letters set
            unique_letters.add(char)
            # Count frequencies if required
            if count_frequencies:
                if char in frequencies:
                    frequencies[char] += 1
                else:
                    frequencies[char] = 1

    # Prepare output based on the specified format
    if output_format == 'list':
        result = list(unique_letters)
    elif output_format == 'string':
        result = ''.join(sorted(unique_letters))
    else:  # default to 'dict'
        result = {'unique_letters': list(unique_letters)}
        if count_frequencies:
            result['frequencies'] = frequencies

    return result

