def extract_first_name(full_name: str, output_format: str = 'string', include_middle_name: bool = False, handle_prefix_suffix: bool = True):
    # Error handling for invalid input types
    if not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a string.'}
    if output_format not in ['string', 'json', 'xml']:
        return {'error': 'Invalid input: output_format must be one of ["string", "json", "xml"].'}

    # Define common prefixes and suffixes
    prefixes = ['Dr.', 'Mr.', 'Mrs.', 'Ms.']
    suffixes = ['Jr.', 'Sr.', 'II', 'III']

    # Split the full name into parts
    name_parts = full_name.split()

    # Handle prefixes
    if handle_prefix_suffix and name_parts[0] in prefixes:
        name_parts = name_parts[1:]

    # Handle suffixes
    if handle_prefix_suffix and name_parts[-1] in suffixes:
        name_parts = name_parts[:-1]

    # Extract first name and optionally middle name
    first_name = name_parts[0]
    if include_middle_name and len(name_parts) > 2:
        first_name += ' ' + ' '.join(name_parts[1:-1])

    # Format the output
    if output_format == 'json':
        return {'first_name': first_name}
    elif output_format == 'xml':
        return f'<first_name>{first_name}</first_name>'
    else:  # Default to string
        return first_name

