def get_last_letter(input: str, ignore_whitespace: bool = True, output_format: str = 'character', case_sensitive: bool = False, special_character_handling: str = 'include') -> str:
    # Error handling for empty input
    if not input:
        return 'Error: Input string must be non-empty.'

    # Trim whitespace if ignore_whitespace is True
    if ignore_whitespace:
        input = input.rstrip()

    # Handle special character exclusion
    if special_character_handling == 'exclude':
        input = ''.join(filter(str.isalnum, input))

    # Error handling for empty input after processing
    if not input:
        return 'Error: No valid characters found in input.'

    # Extract the last character
    last_letter = input[-1]

    # Handle case sensitivity
    if not case_sensitive:
        last_letter = last_letter.lower()

    # Return the last letter in the specified format
    if output_format == 'character':
        return last_letter
    elif output_format == 'ascii':
        return str(ord(last_letter))
    elif output_format == 'unicode':
        return str(ord(last_letter))
    elif output_format == 'hex':
        return hex(ord(last_letter))
    else:
        return 'Error: Invalid output format specified.'

