def date_calculator(start_date, years_to_add=0, months_to_add=0, days_to_add=0, output_format='YYYY-MM-DD', time_zone='UTC'):
    from datetime import datetime, timedelta
    from dateutil.relativedelta import relativedelta
    import pytz

    # Validate and parse the start_date
    try:
        date_obj = datetime.strptime(start_date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid start_date format. Expected YYYY-MM-DD.'}

    # Adjust the date based on the input parameters
    try:
        date_obj += relativedelta(years=years_to_add, months=months_to_add, days=days_to_add)
    except Exception as e:
        return {'error': str(e)}

    # Adjust for the time zone
    try:
        tz = pytz.timezone(time_zone)
        date_obj = tz.localize(date_obj)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Unknown time zone.'}

    # Format the output date
    if output_format == 'YYYY-MM-DD':
        formatted_date = date_obj.strftime('%Y-%m-%d')
    elif output_format == 'MM-DD-YYYY':
        formatted_date = date_obj.strftime('%m-%d-%Y')
    elif output_format == 'DD-MM-YYYY':
        formatted_date = date_obj.strftime('%d-%m-%Y')
    elif output_format == 'ISO8601':
        formatted_date = date_obj.isoformat()
    elif output_format == 'RFC2822':
        formatted_date = date_obj.strftime('%a, %d %b %Y %H:%M:%S %z')
    else:
        return {'error': 'Unsupported output format.'}

    return {'result': formatted_date}

