def sum_of_digits(year, input_format='integer', output_format='integer', digit_positions=None, include_negative=False, statistics=False):
    """
    Calculate the sum of the digits of a given year.
    :param year: The year for which the sum of digits is to be calculated.
    :param input_format: The format of the input year(s).
    :param output_format: The format of the output.
    :param digit_positions: Specific digit positions to include in the sum.
    :param include_negative: Whether to include the negative sign as a digit.
    :param statistics: Whether to provide statistical summaries.
    :return: The sum of the digits in the specified output format.
    """
    # Error handling for input types
    if not isinstance(year, (int, str, list)):
        return {'error': 'Invalid year type. Must be integer, string, or list.'}
    if input_format not in ['integer', 'string', 'list']:
        return {'error': 'Invalid input_format. Must be one of: integer, string, list.'}
    if output_format not in ['integer', 'text', 'json']:
        return {'error': 'Invalid output_format. Must be one of: integer, text, json.'}

    # Convert year to a list of digits
    if input_format == 'integer':
        digits = list(str(abs(year)))
    elif input_format == 'string':
        digits = list(year)
    elif input_format == 'list':
        digits = [str(abs(y)) for y in year]

    # Handle digit positions
    if digit_positions is not None:
        digits = [digits[i] for i in digit_positions if i < len(digits)]

    # Calculate the sum of digits
    digit_sum = sum(int(d) for d in digits if d.isdigit())

    # Include negative sign if specified
    if include_negative and year < 0:
        digit_sum += 1

    # Prepare output
    if output_format == 'integer':
        return digit_sum
    elif output_format == 'text':
        return f'The sum of the digits is {digit_sum}.'
    elif output_format == 'json':
        return {'sum': digit_sum, 'details': {'year': year, 'digits': digits}}

# Example usage
