print(result)  # Output: 19

def advanced_power_calculator(base, operation='exponentiation', exponent=3, root_degree=2, log_base=10, output_format='float'):
    """
    Perform a mathematical operation on the base number.

    Parameters:
    - base (number): The base number for the calculation.
    - operation (string): The type of mathematical operation to perform.
    - exponent (number): The exponent for exponentiation operations.
    - root_degree (number): The degree of the root for root extraction operations.
    - log_base (number): The base of the logarithm for logarithmic calculations.
    - output_format (string): The format of the output.

    Returns:
    - result (number): The result of the calculation in the specified format.
    """
    try:
        if not isinstance(base, (int, float)):
            raise ValueError("Base must be a number.")
        if operation not in ['exponentiation', 'root', 'logarithm']:
            raise ValueError("Invalid operation type.")

        if operation == 'exponentiation':
            result = base ** exponent
        elif operation == 'root':
            if root_degree == 0:
                raise ValueError("Root degree cannot be zero.")
            result = base ** (1 / root_degree)
        elif operation == 'logarithm':
            if base <= 0 or log_base <= 0:
                raise ValueError("Base and log base must be positive numbers.")
            import math
            result = math.log(base, log_base)

        if output_format == 'integer':
            return int(result)
        elif output_format == 'float':
            return float(result)
        elif output_format == 'scientific':
            return f"{result:.2e}"
        elif output_format == 'fraction':
            from fractions import Fraction
            return str(Fraction(result).limit_denominator())
        else:
            raise ValueError("Invalid output format.")
    except Exception as e:
        return str(e)

