def distinct_combinations(input_string, combination_length=2, case_sensitive=True, output_format='list', include_characters=None, exclude_characters=None):
    import itertools

    # Error handling for input string length
    if len(input_string) < 2:
        return {'error': 'Input string must be at least two characters long.'}

    # Adjust input string based on case sensitivity
    if not case_sensitive:
        input_string = input_string.lower()

    # Apply include and exclude character filters
    if include_characters:
        input_string = ''.join([ch for ch in input_string if ch in include_characters])
    if exclude_characters:
        input_string = ''.join([ch for ch in input_string if ch not in exclude_characters])

    # Generate combinations
    combinations = set(itertools.combinations(input_string, combination_length))

    # Prepare output based on the specified format
    if output_format == 'list':
        return {'result': [''.join(comb) for comb in combinations]}
    elif output_format == 'count':
        return {'result': len(combinations)}
    elif output_format == 'detailed':
        return {'result': {'combinations': [''.join(comb) for comb in combinations], 'count': len(combinations)}}
    else:
        return {'error': 'Invalid output format specified.'}

