def reverse_number(number, output_format='string', preserve_sign=True, decimal_precision=None):
    """
    Reverse the digits of a number with options for output format and sign preservation.

    :param number: The number to be reversed (integer or float).
    :param output_format: The format of the output ('string', 'integer', 'float').
    :param preserve_sign: Whether to preserve the sign of the number.
    :param decimal_precision: Number of decimal places to maintain if output_format is 'float'.
    :return: The reversed number in the specified format.
    """
    try:
        # Convert number to string and handle sign
        sign = '-' if number < 0 and preserve_sign else ''
        num_str = str(abs(number))

        # Reverse the digits
        if '.' in num_str:
            integer_part, decimal_part = num_str.split('.')
            reversed_number = integer_part[::-1] + '.' + decimal_part[::-1]
        else:
            reversed_number = num_str[::-1]

        # Format the output
        if output_format == 'integer':
            return int(sign + reversed_number)
        elif output_format == 'float':
            if '.' in reversed_number:
                if decimal_precision is not None:
                    reversed_number = f"{float(sign + reversed_number):.{decimal_precision}f}"
                else:
                    reversed_number = float(sign + reversed_number)
            else:
                reversed_number = float(sign + reversed_number)
            return reversed_number
        elif output_format == 'string':
            return sign + reversed_number
        else:
            raise ValueError("Invalid output_format. Choose from 'string', 'integer', 'float'.")
    except Exception as e:
        return f"Error: {str(e)}"

