def character_extractor_plus(input: str, position: str = 'last', custom_index: int = None, length: int = 1, case_sensitive: bool = True) -> str:
    """
    Extract specific characters from a string based on the given parameters.
    """
    # Error handling for required input
    if not input:
        return 'Error: Input string is required.'

    # Determine the starting index based on the position
    if position == 'first':
        start_index = 0
    elif position == 'last':
        start_index = -length
    elif position == 'custom':
        if custom_index is None:
            return 'Error: Custom index must be provided for custom position.'
        start_index = custom_index
    else:
        return 'Error: Invalid position value.'

    # Handle negative indexing and out of range issues
    try:
        if start_index < 0:
            start_index += len(input)
        if start_index < 0 or start_index >= len(input):
            return 'Error: Custom index out of range.'

        # Extract the characters
        extracted = input[start_index:start_index + length]

        # Handle case sensitivity
        if not case_sensitive:
            extracted = extracted.lower()

        return extracted
    except Exception as e:
        return f'Error: {str(e)}'

