def find_closest_palindrome(number, direction='both', return_distance=False, max_search_limit=1000, include_original=True, return_all_palindromes=False):
    # Helper function to check if a number is a palindrome
    def is_palindrome(n):
        return str(n) == str(n)[::-1]

    # Validate input types
    if not isinstance(number, int):
        raise ValueError('The number must be an integer.')
    if direction not in ['both', 'lower', 'higher']:
        raise ValueError("Direction must be 'both', 'lower', or 'higher'.")
    if not isinstance(return_distance, bool):
        raise ValueError('Return_distance must be a boolean.')
    if not isinstance(max_search_limit, int) or max_search_limit <= 0:
        raise ValueError('Max_search_limit must be a positive integer.')
    if not isinstance(include_original, bool):
        raise ValueError('Include_original must be a boolean.')
    if not isinstance(return_all_palindromes, bool):
        raise ValueError('Return_all_palindromes must be a boolean.')

    closest_palindrome = None
    closest_distance = float('inf')
    palindromes = []

    # Search for palindromes
    for i in range(max_search_limit + 1):
        if direction in ['both', 'lower']:
            lower_candidate = number - i
            if lower_candidate >= 0 and is_palindrome(lower_candidate):
                if include_original or lower_candidate != number:
                    palindromes.append(lower_candidate)
                    if abs(number - lower_candidate) < closest_distance:
                        closest_palindrome = lower_candidate
                        closest_distance = abs(number - lower_candidate)

        if direction in ['both', 'higher']:
            higher_candidate = number + i
            if is_palindrome(higher_candidate):
                if include_original or higher_candidate != number:
                    palindromes.append(higher_candidate)
                    if abs(number - higher_candidate) < closest_distance:
                        closest_palindrome = higher_candidate
                        closest_distance = abs(number - higher_candidate)

        if closest_palindrome is not None and not return_all_palindromes:
            break

    result = {'closest_palindrome': closest_palindrome}
    if return_distance:
        result['distance'] = closest_distance
    if return_all_palindromes:
        result['all_palindromes'] = palindromes

    return result

