def date_calculator(start_date: str, interval: int, unit: str = 'days', direction: str = 'forward', calendar_system: str = 'gregorian', time_zone: str = 'UTC', output_format: str = 'date') -> str:
    from datetime import datetime, timedelta
    import pytz

    # Validate and parse the start_date
    try:
        start_dt = datetime.fromisoformat(start_date.replace('Z', '+00:00'))
    except ValueError:
        return 'Error: Invalid start_date format. Please use YYYY-MM-DDTHH:MM:SSZ format.'

    # Adjust for time zone
    try:
        tz = pytz.timezone(time_zone)
        start_dt = start_dt.astimezone(tz)
    except pytz.UnknownTimeZoneError:
        return 'Error: Unknown time zone specified.'

    # Calculate the time delta
    if unit == 'weeks':
        delta = timedelta(weeks=interval)
    elif unit == 'days':
        delta = timedelta(days=interval)
    elif unit == 'hours':
        delta = timedelta(hours=interval)
    elif unit == 'minutes':
        delta = timedelta(minutes=interval)
    else:
        return 'Error: Unsupported time unit. Supported units are minutes, hours, days, weeks.'

    # Adjust the date based on direction
    if direction == 'forward':
        result_dt = start_dt + delta
    elif direction == 'backward':
        result_dt = start_dt - delta
    else:
        return 'Error: Invalid direction. Use forward or backward.'

    # Format the output
    if output_format == 'date':
        return result_dt.strftime('%Y-%m-%d')
    elif output_format == 'text':
        return result_dt.strftime('%A, %B %d, %Y')
    elif output_format == 'json':
        return {'year': result_dt.year, 'month': result_dt.month, 'day': result_dt.day}
    else:
        return 'Error: Unsupported output format. Use date, text, or json.'

