def string_length_counter(input, ignore_characters=[], ignore_position=[], case_sensitive=False, count_character_types=[], output_format='integer'):
    # Validate input type
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}

    # Validate ignore_characters
    if not all(isinstance(char, str) and len(char) == 1 for char in ignore_characters):
        return {'error': 'All ignore_characters must be single-character strings.'}

    # Validate ignore_position
    valid_positions = {'first', 'last'}
    if not all(pos in valid_positions for pos in ignore_position):
        return {'error': 'Invalid ignore_position value. Must be "first" or "last".'}

    # Validate count_character_types
    valid_types = {'vowels', 'consonants', 'digits', 'special'}
    if not all(ct in valid_types for ct in count_character_types):
        return {'error': 'Invalid count_character_types value.'}

    # Filter input based on ignore_characters
    filtered_input = ''.join(char for char in input if char not in ignore_characters)

    # Handle ignore_position
    if 'first' in ignore_position and filtered_input:
        filtered_input = filtered_input[1:]
    if 'last' in ignore_position and filtered_input:
        filtered_input = filtered_input[:-1]

    # Handle case sensitivity
    if not case_sensitive:
        filtered_input = filtered_input.lower()

    # Count letters
    if not count_character_types:
        count = sum(char.isalpha() for char in filtered_input)
    else:
        count = 0
        if 'vowels' in count_character_types:
            count += sum(char in 'aeiou' for char in filtered_input)
        if 'consonants' in count_character_types:
            count += sum(char.isalpha() and char not in 'aeiou' for char in filtered_input)
        if 'digits' in count_character_types:
            count += sum(char.isdigit() for char in filtered_input)
        if 'special' in count_character_types:
            count += sum(not char.isalnum() for char in filtered_input)

    # Format output
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The count is {count}.'
    elif output_format == 'detailed':
        details = {
            'total': count,
            'vowels': sum(char in 'aeiou' for char in filtered_input),
            'consonants': sum(char.isalpha() and char not in 'aeiou' for char in filtered_input),
            'digits': sum(char.isdigit() for char in filtered_input),
            'special': sum(not char.isalnum() for char in filtered_input)
        }
        return details
    else:
        return {'error': 'Invalid output_format value.'}

