def date_calculator(input_date, days_to_add, calendar_system='Gregorian', output_format='YYYY-MM-DD', time_zone='UTC', calculate_difference=False, second_date=None):
    from datetime import datetime, timedelta
    import pytz

    # Error handling for input_date format
    try:
        date_obj = datetime.strptime(input_date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid input_date format. Expected YYYY-MM-DD.'}

    # Error handling for calendar_system
    if calendar_system not in ['Gregorian', 'Julian', 'Hebrew', 'Islamic']:
        return {'error': 'Invalid calendar_system. Supported systems: Gregorian, Julian, Hebrew, Islamic.'}

    # Error handling for output_format
    if output_format not in ['YYYY-MM-DD', 'DD-MM-YYYY', 'MM-DD-YYYY']:
        return {'error': 'Invalid output_format. Supported formats: YYYY-MM-DD, DD-MM-YYYY, MM-DD-YYYY.'}

    # Error handling for time_zone
    try:
        timezone = pytz.timezone(time_zone)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time_zone. Please provide a valid time zone.'}

    # Calculate new date
    if not calculate_difference:
        new_date = date_obj + timedelta(days=days_to_add)

        # Format the new date
        if output_format == 'YYYY-MM-DD':
            formatted_date = new_date.strftime('%Y-%m-%d')
        elif output_format == 'DD-MM-YYYY':
            formatted_date = new_date.strftime('%d-%m-%Y')
        elif output_format == 'MM-DD-YYYY':
            formatted_date = new_date.strftime('%m-%d-%Y')

        return {'result': formatted_date}
    else:
        # Error handling for second_date
        if not second_date:
            return {'error': 'second_date is required when calculate_difference is true.'}

        try:
            second_date_obj = datetime.strptime(second_date, '%Y-%m-%d')
        except ValueError:
            return {'error': 'Invalid second_date format. Expected YYYY-MM-DD.'}

        # Calculate difference
        date_difference = (second_date_obj - date_obj).days
        return {'result': date_difference}

