def enhanced_previous_year_calculator(year, output_format='integer', calendar_system='gregorian', locale='en-US'):
    """
    Calculate the year immediately preceding the given year.

    Parameters:
    - year (int or str): The year for which the previous year is to be calculated.
    - output_format (str): The format of the output. Defaults to 'integer'.
    - calendar_system (str): The calendar system to use. Defaults to 'gregorian'.
    - locale (str): The locale for formatting the output as a localized string. Defaults to 'en-US'.

    Returns:
    - The previous year in the specified format.
    """
    import datetime
    import locale as loc

    # Error handling for input types
    if not isinstance(year, (int, str)):
        return {'error': 'Invalid year format. Must be an integer or a string in YYYY-MM-DD format.'}

    # Convert year to integer if it's a string
    if isinstance(year, str):
        try:
            if '-' in year:
                year = datetime.datetime.strptime(year, '%Y-%m-%d').year
            else:
                year = int(year)
        except ValueError:
            return {'error': 'Invalid year string format. Must be YYYY-MM-DD or a valid integer string.'}

    # Calculate the previous year
    previous_year = year - 1

    # Handle different output formats
    if output_format == 'integer':
        return previous_year
    elif output_format == 'string':
        return str(previous_year)
    elif output_format == 'localized_string':
        try:
            loc.setlocale(loc.LC_TIME, locale)
            return previous_year
        except loc.Error:
            return {'error': 'Invalid locale specified.'}
    elif output_format == 'calendar_system':
        if calendar_system == 'gregorian':
            return previous_year
        elif calendar_system == 'julian':
            # Simplified conversion for demonstration purposes
            return previous_year - 13
        elif calendar_system == 'islamic':
            # Simplified conversion for demonstration purposes
            return previous_year - 622
        elif calendar_system == 'hebrew':
            # Simplified conversion for demonstration purposes
            return previous_year - 3760
        else:
            return {'error': 'Unsupported calendar system specified.'}
    else:
        return {'error': 'Unsupported output format specified.'}

