    # Validate required parameter
    if not isinstance(name, str) or not name:
        return {'error': 'Invalid input: name must be a non-empty string.'}

    # Validate output_format
    if output_format not in ['character', 'ascii', 'unicode']:
        return {'error': 'Invalid output_format. Must be one of: character, ascii, unicode.'}

    # Validate language_support
    if language_support not in ['latin', 'cyrillic', 'arabic', 'all']:
        return {'error': 'Invalid language_support. Must be one of: latin, cyrillic, arabic, all.'}

    # Process the name based on parameters
    processed_name = name
    if ignore_special_characters:
        processed_name = ''.join(filter(str.isalnum, name))

    # Extract the first letter based on conditions
    first_letter = None
    position = None
    for index, char in enumerate(processed_name):
        if first_uppercase and char.isupper():
            first_letter = char
            position = index
            break
        elif not first_uppercase:
            first_letter = char
            position = index
            break

    if first_letter is None:
        return {'error': 'No valid letter found in the input string.'}

    # Adjust case sensitivity
    if not case_sensitive:
        first_letter = first_letter.lower()

    # Prepare the output
    if output_format == 'ascii':
        first_letter = ord(first_letter)
    elif output_format == 'unicode':
        first_letter = f'U+{ord(first_letter):04X}'

    result = {'first_letter': first_letter}
    if return_position:
        result['position'] = position

    return result

