def extract_last_name(full_name: str, delimiter: str = 'space', output_format: str = 'string', include_titles: bool = False, include_suffixes: bool = False):
    # Error handling for required parameter
    if not full_name:
        return {'error': 'The full_name parameter is required.'}

    # Define delimiters
    delimiters = {
        'space': ' ',
        'hyphen': '-',
        'comma': ','
    }

    # Check if the delimiter is valid
    if delimiter not in delimiters:
        return {'error': 'Invalid delimiter. Choose from space, hyphen, or comma.'}

    # Split the full name based on the delimiter
    parts = full_name.split(delimiters[delimiter])

    # Initialize variables for titles and suffixes
    titles = ['Dr.', 'Mr.', 'Ms.', 'Mrs.']
    suffixes = ['Jr.', 'Sr.', 'III']

    # Filter out titles and suffixes if not included
    if not include_titles:
        parts = [part for part in parts if part not in titles]
    if not include_suffixes:
        parts = [part for part in parts if part not in suffixes]

    # Assume the last part is the last name
    last_name = parts[-1]

    # Format the output based on the output_format parameter
    if output_format == 'string':
        return last_name
    elif output_format == 'array':
        return last_name.split()
    elif output_format == 'object':
        return {
            'last_name': last_name,
            'original_name': full_name,
            'delimiter_used': delimiter
        }
    else:
        return {'error': 'Invalid output format. Choose from string, array, or object.'}

