def sum_of_digits(input: str, ignore_non_numeric: bool = True, output_format: str = 'integer', digit_range: list = None, numeral_system: str = 'decimal', detailed_feedback: bool = False):
    # Validate numeral system
    if numeral_system not in ['decimal', 'binary', 'hexadecimal']:
        return {'error': 'Unsupported numeral system'}

    # Validate output format
    if output_format not in ['integer', 'text', 'json']:
        return {'error': 'Unsupported output format'}

    # Convert input to the appropriate numeral system
    try:
        if numeral_system == 'binary':
            input = str(int(input, 2))
        elif numeral_system == 'hexadecimal':
            input = str(int(input, 16))
    except ValueError:
        return {'error': 'Invalid input for the specified numeral system'}

    # Initialize sum and feedback
    total_sum = 0
    feedback = {'ignored_characters': [], 'intermediate_sums': []}

    # Iterate over each character in the input
    for char in input:
        if char.isdigit():
            digit = int(char)
            if digit_range is None or digit in digit_range:
                total_sum += digit
                feedback['intermediate_sums'].append(total_sum)
        elif not ignore_non_numeric:
            return {'error': 'Non-numeric characters present in input'}
        else:
            feedback['ignored_characters'].append(char)

    # Prepare the output
    if output_format == 'integer':
        result = total_sum
    elif output_format == 'text':
        result = f'The sum of digits is {total_sum}'
    elif output_format == 'json':
        result = {'sum': total_sum}

    # Add detailed feedback if requested
    if detailed_feedback:
        result = {'result': result, 'feedback': feedback}

    return result

