def date_calculator(start_date_time: str, days_to_add: int, hours_to_add: int = 0, output_format: str = 'YYYY-MM-DDTHH:MM:SS', time_zone: str = 'UTC', business_days_only: bool = False) -> str:
    from datetime import datetime, timedelta
    import pytz
    from dateutil import parser

    try:
        # Parse the start date and time
        start_dt = parser.isoparse(start_date_time)

        # Adjust for time zone
        if time_zone:
            tz = pytz.timezone(time_zone)
            start_dt = start_dt.astimezone(tz)

        # Calculate the new date
        if business_days_only:
            # Add days considering only business days
            days_added = 0
            while days_added < abs(days_to_add):
                start_dt += timedelta(days=1 if days_to_add > 0 else -1)
                if start_dt.weekday() < 5:  # Monday to Friday are business days
                    days_added += 1
        else:
            # Add days directly
            start_dt += timedelta(days=days_to_add)

        # Add hours
        start_dt += timedelta(hours=hours_to_add)

        # Format the output date
        if output_format == 'YYYY-MM-DD':
            result = start_dt.strftime('%Y-%m-%d')
        elif output_format == 'DD-MM-YYYY':
            result = start_dt.strftime('%d-%m-%Y')
        elif output_format == 'MM-DD-YYYY':
            result = start_dt.strftime('%m-%d-%Y')
        elif output_format == 'YYYY-MM-DDTHH:MM:SS':
            result = start_dt.strftime('%Y-%m-%dT%H:%M:%S')
        elif output_format == 'DD-MM-YYYY HH:MM':
            result = start_dt.strftime('%d-%m-%Y %H:%M')
        elif output_format == 'MM-DD-YYYY HH:MM':
            result = start_dt.strftime('%m-%d-%Y %H:%M')
        else:
            raise ValueError('Invalid output format specified.')

        return result

    except Exception as e:
        return f'Error: {str(e)}'

