print(result)

def timezone_converter(input_datetime: str, input_timezone_offset: float, output_timezone: str = 'AoE', output_format: str = 'ISO', daylight_saving: bool = True, locale: str = 'en-US') -> str:
    from datetime import datetime, timedelta
    import pytz

    # Define time zone offsets
    timezone_offsets = {
        'AoE': -12,
        'UTC': 0,
        'PST': -8,
        'EST': -5,
        'CET': 1,
        'IST': 5.5,
        'JST': 9,
        'AEST': 10,
        'GMT': 0,
        'BST': 1,
        'CST': -6,
        'MST': -7
    }

    # Validate output_timezone
    if output_timezone not in timezone_offsets:
        return 'Error: Unsupported output timezone.'

    # Parse input datetime
    try:
        input_dt = datetime.fromisoformat(input_datetime)
    except ValueError:
        return 'Error: Invalid input datetime format.'

    # Calculate the time difference
    input_offset = timedelta(hours=input_timezone_offset)
    output_offset = timedelta(hours=timezone_offsets[output_timezone])

    # Adjust for daylight saving if applicable
    if daylight_saving:
        # This is a simplified assumption; real DST handling would require more complex logic
        if output_timezone in ['PST', 'EST', 'CET', 'BST', 'CST', 'MST']:
            output_offset += timedelta(hours=1)

    # Convert to target timezone
    target_dt = input_dt + (output_offset - input_offset)

    # Format the output
    if output_format == 'ISO':
        return target_dt.isoformat()
    elif output_format == 'readable':
        return target_dt.strftime('%Y-%m-%d %H:%M')
    elif output_format == 'timestamp':
        return str(int(target_dt.timestamp()))
    else:
        return 'Error: Unsupported output format.'

