def vowel_counter(input: str, ignore_characters: list = None, ignore_position: list = None, output_format: str = 'integer', case_sensitive: bool = False, specific_vowels: list = None):
    # Define default vowels
    vowels = 'aeiouAEIOU' if case_sensitive else 'aeiou'
    # Adjust vowels if specific vowels are provided
    if specific_vowels:
        vowels = ''.join(specific_vowels)

    # Initialize count dictionary for detailed output
    count_dict = {v: 0 for v in vowels}

    # Prepare input string
    input_to_count = input
    if ignore_characters:
        for char in ignore_characters:
            input_to_count = input_to_count.replace(char, '')

    # Handle ignore_position
    if ignore_position:
        if 'first' in ignore_position and len(input_to_count) > 0:
            input_to_count = input_to_count[1:]
        if 'last' in ignore_position and len(input_to_count) > 0:
            input_to_count = input_to_count[:-1]

    # Count vowels
    total_count = 0
    for char in input_to_count:
        if char in vowels:
            total_count += 1
            count_dict[char] += 1

    # Format output
    if output_format == 'integer':
        return total_count
    elif output_format == 'text':
        return f'Total vowels: {total_count}'
    elif output_format == 'detailed':
        return count_dict
    else:
        raise ValueError('Invalid output format specified.')

