def remove_spaces_advanced(input: str, remove_characters: list = [], output_format: str = 'string', case_sensitive: bool = False, replace_characters: dict = None, whitespace_handling: str = 'all') -> str:
    # Validate output_format
    if output_format not in ['string', 'array', 'json']:
        raise ValueError("Invalid output_format. Supported formats are 'string', 'array', 'json'.")

    # Validate whitespace_handling
    if whitespace_handling not in ['all', 'leading', 'trailing', 'none']:
        raise ValueError("Invalid whitespace_handling. Supported values are 'all', 'leading', 'trailing', 'none'.")

    # Handle whitespace based on whitespace_handling
    if whitespace_handling == 'all':
        input = ''.join(input.split())
    elif whitespace_handling == 'leading':
        input = input.lstrip()
    elif whitespace_handling == 'trailing':
        input = input.rstrip()

    # Remove additional characters
    if not case_sensitive:
        input = input.lower()
        remove_characters = [char.lower() for char in remove_characters]

    for char in remove_characters:
        input = input.replace(char, '')

    # Replace characters if specified
    if replace_characters:
        target = replace_characters.get('target', '')
        replacement = replace_characters.get('replacement', '')
        input = input.replace(target, replacement)

    # Format output
    if output_format == 'array':
        return list(input)
    elif output_format == 'json':
        return {'result': input}
    else:
        return input

