def date_calculator(start_date, duration, calendar_system='Gregorian', time_zone='UTC', output_format='date_string', error_handling='strict'):
    from datetime import datetime, timedelta
    import pytz
    from dateutil.relativedelta import relativedelta

    # Validate input parameters
    try:
        # Parse the start date
        start_date = datetime.strptime(start_date, '%Y-%m-%dT%H:%M:%SZ')
        start_date = pytz.timezone(time_zone).localize(start_date)
    except Exception as e:
        if error_handling == 'strict':
            raise ValueError(f"Invalid start_date format: {e}")
        else:
            return 'Invalid start_date format'

    # Calculate the new date based on the duration
    try:
        if duration['unit'] == 'seconds':
            delta = timedelta(seconds=duration['value'])
        elif duration['unit'] == 'minutes':
            delta = timedelta(minutes=duration['value'])
        elif duration['unit'] == 'hours':
            delta = timedelta(hours=duration['value'])
        elif duration['unit'] == 'days':
            delta = timedelta(days=duration['value'])
        elif duration['unit'] == 'weeks':
            delta = timedelta(weeks=duration['value'])
        elif duration['unit'] == 'months':
            delta = relativedelta(months=duration['value'])
        elif duration['unit'] == 'years':
            delta = relativedelta(years=duration['value'])
        else:
            raise ValueError('Invalid duration unit')

        new_date = start_date + delta
    except Exception as e:
        if error_handling == 'strict':
            raise ValueError(f"Error in calculating new date: {e}")
        else:
            return 'Error in calculating new date'

    # Format the output
    if output_format == 'date_string':
        return new_date.strftime('%Y-%m-%d')
    elif output_format == 'timestamp':
        return int(new_date.timestamp())
    elif output_format == 'iso8601':
        return new_date.isoformat()
    else:
        if error_handling == 'strict':
            raise ValueError('Invalid output format')
        else:
            return 'Invalid output format'

