def extract_first_name(full_name, name_format='western', ignore_titles=True, custom_delimiters=None, nickname_handling=False, case_sensitivity=False):
    """
    Extracts the first name from a full name string based on the specified parameters.

    :param full_name: The full name from which to extract the first name.
    :param name_format: The format of the name, which helps in parsing. Defaults to 'western'.
    :param ignore_titles: Whether to ignore titles such as Mr., Dr., etc. Defaults to true.
    :param custom_delimiters: Custom delimiters to use when parsing the name, useful for non-standard name formats.
    :param nickname_handling: Whether to attempt to extract nicknames as first names if present. Defaults to false.
    :param case_sensitivity: Whether the parsing should be case-sensitive. Defaults to false.
    :return: The extracted first name or an error message if extraction fails.
    """
    if not isinstance(full_name, str) or not full_name.strip():
        return "Error: 'full_name' must be a non-empty string."

    # Normalize the case if case_sensitivity is False
    if not case_sensitivity:
        full_name = full_name.lower()

    # Handle title removal if ignore_titles is True
    if ignore_titles:
        titles = ['mr.', 'mrs.', 'dr.', 'ms.', 'prof.']
        for title in titles:
            if full_name.lower().startswith(title):
                full_name = full_name[len(title):].strip()
                break

    # Use custom delimiters if provided
    if custom_delimiters:
        for delimiter in custom_delimiters:
            if delimiter in full_name:
                parts = full_name.split(delimiter)
                break
        else:
            parts = full_name.split()
    else:
        parts = full_name.split()

    # Extract first name based on name_format
    if name_format == 'western':
        first_name = parts[0]
    elif name_format == 'eastern':
        first_name = parts[-1]
    elif name_format == 'arabic':
        first_name = parts[0]
    elif name_format == 'hispanic':
        first_name = parts[0]
    elif name_format == 'custom':
        first_name = parts[0]
    else:
        return "Error: Unsupported name format."

    # Handle nickname extraction if enabled
    if nickname_handling and '(' in full_name and ')' in full_name:
        nickname_start = full_name.find('(') + 1
        nickname_end = full_name.find(')')
        first_name = full_name[nickname_start:nickname_end].strip()

    return first_name.capitalize() if not case_sensitivity else first_name

