def vowel_counter(input, case_sensitive=False, include_accents=True, output_format='integer', vowels_to_count=['a', 'e', 'i', 'o', 'u', 'y'], character_encoding='UTF-8'):
    # Error handling for input validation
    if not isinstance(input, list) or not all(isinstance(s, str) for s in input):
        return {'error': 'Invalid input: input must be a list of strings.'}
    if len(input) < 1 or len(input) > 10:
        return {'error': 'Invalid input: input list must contain between 1 and 10 strings.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid input: case_sensitive must be a boolean.'}
    if not isinstance(include_accents, bool):
        return {'error': 'Invalid input: include_accents must be a boolean.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid input: output_format must be one of integer, text, detailed.'}
    if not isinstance(vowels_to_count, list) or not all(v in ['a', 'e', 'i', 'o', 'u', 'y'] for v in vowels_to_count):
        return {'error': 'Invalid input: vowels_to_count must be a list of specified vowels.'}
    if character_encoding not in ['UTF-8', 'ASCII', 'ISO-8859-1']:
        return {'error': 'Invalid input: character_encoding must be one of UTF-8, ASCII, ISO-8859-1.'}

    # Vowel counting logic
    vowel_set = set(vowels_to_count)
    if not case_sensitive:
        vowel_set = vowel_set.union({v.upper() for v in vowel_set})

    total_vowel_count = 0
    detailed_count = {v: 0 for v in vowel_set}

    for string in input:
        for char in string:
            if include_accents:
                if char.lower() in 'áéíóúýàèìòùâêîôûäëïöüÿãõñç':
                    char = char.lower().replace('á', 'a').replace('é', 'e').replace('í', 'i').replace('ó', 'o').replace('ú', 'u').replace('ý', 'y')
            if char in vowel_set:
                total_vowel_count += 1
                detailed_count[char] += 1

    if output_format == 'integer':
        return total_vowel_count
    elif output_format == 'text':
        return f'Total vowels: {total_vowel_count}'
    elif output_format == 'detailed':
        return detailed_count

