def enhanced_combined_length_calculator(names, output_format='integer', ignore_duplicates=False, trim_whitespace=True, weighting_factors=None, statistical_summary=False):
    # Validate input parameters
    if not isinstance(names, list) or len(names) < 1:
        return {'error': 'Invalid input: names must be a non-empty list of strings.'}
    if weighting_factors and len(weighting_factors) != len(names):
        return {'error': 'Invalid input: weighting_factors must match the length of names.'}

    # Handle duplicate names if required
    if ignore_duplicates:
        names = list(set(names))

    # Trim whitespace if required
    if trim_whitespace:
        names = [name.strip() for name in names]

    # Calculate the combined length
    combined_length = 0
    for i, name in enumerate(names):
        length = len(name)
        if weighting_factors:
            length *= weighting_factors[i]
        combined_length += length

    # Prepare the output based on the specified format
    if output_format == 'integer':
        return combined_length
    elif output_format == 'text':
        return f'The combined length is {combined_length}.'
    elif output_format == 'json':
        return {'combined_length': combined_length}
    elif output_format == 'detailed_report':
        report = {'combined_length': combined_length}
        if statistical_summary:
            lengths = [len(name) for name in names]
            report['mean'] = sum(lengths) / len(lengths)
            report['median'] = sorted(lengths)[len(lengths) // 2]
            report['mode'] = max(set(lengths), key=lengths.count)
        return report
    else:
        return {'error': 'Invalid output format specified.'}

