def count_repeated_letters(input, case_sensitive=False, output_format='integer', ignore_characters='', min_repetitions=2):
    # Validate input parameters
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Case_sensitive must be a boolean.'}
    if output_format not in ['integer', 'list', 'detailed_list']:
        return {'error': 'Output_format must be one of: integer, list, detailed_list.'}
    if not isinstance(ignore_characters, str):
        return {'error': 'Ignore_characters must be a string.'}
    if not isinstance(min_repetitions, int) or min_repetitions < 1:
        return {'error': 'Min_repetitions must be a positive integer.'}

    # Prepare the input string
    if not case_sensitive:
        input = input.lower()
        ignore_characters = ignore_characters.lower()

    # Remove ignored characters
    input = ''.join([char for char in input if char not in ignore_characters])

    # Count occurrences of each letter
    from collections import Counter
    letter_counts = Counter(input)

    # Filter letters based on min_repetitions
    repeated_letters = {letter: count for letter, count in letter_counts.items() if count >= min_repetitions}

    # Generate output based on the specified format
    if output_format == 'integer':
        return len(repeated_letters)
    elif output_format == 'list':
        return list(repeated_letters.keys())
    elif output_format == 'detailed_list':
        return list(repeated_letters.items())

