def count_repeated_letters(input: str, case_sensitive: bool = False, output_format: str = 'integer', ignore_characters: list = None, consecutive_only: bool = False):
    # Initialize variables
    if ignore_characters is None:
        ignore_characters = []
    letter_count = {}
    input_processed = input if case_sensitive else input.lower()

    # Iterate over the string to count repeated letters
    for i, char in enumerate(input_processed):
        if char in ignore_characters or not char.isalpha():
            continue
        if consecutive_only:
            if i > 0 and char == input_processed[i - 1]:
                letter_count[char] = letter_count.get(char, 0) + 1
        else:
            if input_processed.count(char) > 1:
                letter_count[char] = input_processed.count(char)

    # Format the output based on the specified output_format
    if output_format == 'integer':
        return sum(letter_count.values())
    elif output_format == 'text':
        return f"Total repeated letters: {sum(letter_count.values())}"
    elif output_format == 'detailed':
        return {char: count for char, count in letter_count.items()}
    else:
        raise ValueError("Invalid output_format specified.")

    # Error handling for invalid inputs
    if not isinstance(input, str):
        raise TypeError("Input must be a string.")
    if not isinstance(case_sensitive, bool):
        raise TypeError("case_sensitive must be a boolean.")
    if output_format not in ['integer', 'text', 'detailed']:
        raise ValueError("output_format must be 'integer', 'text', or 'detailed'.")
    if not isinstance(ignore_characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in ignore_characters):
        raise TypeError("ignore_characters must be a list of single-character strings.")
    if not isinstance(consecutive_only, bool):
        raise TypeError("consecutive_only must be a boolean.")

