def get_last_letter(input: str, output_format: str = 'original', trim_whitespace: bool = False, error_handling: str = 'ignore') -> str:
    """
    Extracts the last character of a given string with options for formatting and error handling.

    :param input: The string from which to extract the last character.
    :param output_format: The format of the output character ('uppercase', 'lowercase', 'original', 'ascii', 'unicode').
    :param trim_whitespace: Whether to trim trailing whitespace before extracting the last character.
    :param error_handling: Behavior when the input string is empty ('ignore', 'warn', 'error').
    :return: The last character in the specified format.
    """
    if trim_whitespace:
        input = input.rstrip()

    if not input:
        if error_handling == 'error':
            raise ValueError("Input string is empty.")
        elif error_handling == 'warn':
            print("Warning: Input string is empty.")
        return ''

    last_char = input[-1]

    if output_format == 'uppercase':
        return last_char.upper()
    elif output_format == 'lowercase':
        return last_char.lower()
    elif output_format == 'ascii':
        return str(ord(last_char))
    elif output_format == 'unicode':
        return f"U+{ord(last_char):04X}"
    else:
        return last_char

