def enhanced_ascii_converter(characters, output_format='list', encoding='ascii', include_metadata=False, error_handling='strict'):
    import json
    import csv
    from datetime import datetime

    # Validate 'characters' parameter
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        raise ValueError("'characters' must be a list of single-character strings.")

    # Validate 'output_format' parameter
    if output_format not in ['list', 'dictionary', 'json', 'csv']:
        raise ValueError("Invalid 'output_format'. Choose from 'list', 'dictionary', 'json', 'csv'.")

    # Validate 'encoding' parameter
    if encoding not in ['ascii', 'utf-8']:
        raise ValueError("Invalid 'encoding'. Choose 'ascii' or 'utf-8'.")

    # Validate 'error_handling' parameter
    if error_handling not in ['ignore', 'replace', 'strict']:
        raise ValueError("Invalid 'error_handling'. Choose 'ignore', 'replace', 'strict'.")

    ascii_codes = {}
    for char in characters:
        try:
            if encoding == 'ascii':
                ascii_code = ord(char)
                if ascii_code > 127:
                    raise ValueError(f"Character '{char}' is not supported in ASCII.")
            else:  # utf-8
                ascii_code = ord(char)
            ascii_codes[char] = ascii_code
        except Exception as e:
            if error_handling == 'ignore':
                continue
            elif error_handling == 'replace':
                ascii_codes[char] = '?'  # Placeholder for unsupported characters
            elif error_handling == 'strict':
                raise e

    # Format output
    if output_format == 'list':
        result = list(ascii_codes.values())
    elif output_format == 'dictionary':
        result = ascii_codes
    elif output_format == 'json':
        result = json.dumps(ascii_codes)
    elif output_format == 'csv':
        result = ','.join(f'{k}:{v}' for k, v in ascii_codes.items())

    # Include metadata if requested
    if include_metadata:
        metadata = {
            'conversion_time': datetime.now().isoformat(),
            'character_count': len(characters)
        }
        if isinstance(result, str):
            result += f' | Metadata: {metadata}'
        else:
            result = {'result': result, 'metadata': metadata}

    return result

