def ascii_converter(characters, output_format='list', case_sensitive=True, include_non_printable=False):
    """
    Convert a list of characters to their ASCII codes with customizable output formats.

    :param characters: List of single-character strings to convert.
    :param output_format: The format of the output ('list', 'dictionary', 'json', 'csv').
    :param case_sensitive: Boolean indicating if conversion should be case-sensitive.
    :param include_non_printable: Boolean indicating if non-printable ASCII characters should be included.
    :return: ASCII codes in the specified format or an error message.
    """
    import json
    import csv
    from io import StringIO

    # Error handling for input validation
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        return {'error': 'Invalid input: characters must be a list of single-character strings.'}
    if len(characters) < 1 or len(characters) > 100:
        return {'error': 'Invalid input: characters list must contain between 1 and 100 items.'}
    if output_format not in ['list', 'dictionary', 'json', 'csv']:
        return {'error': 'Invalid output format. Choose from list, dictionary, json, csv.'}

    # ASCII conversion logic
    ascii_codes = {}
    for char in characters:
        if not case_sensitive:
            char = char.lower()
        ascii_code = ord(char)
        if include_non_printable or (32 <= ascii_code <= 126):
            ascii_codes[char] = ascii_code

    # Output formatting
    if output_format == 'list':
        return list(ascii_codes.values())
    elif output_format == 'dictionary':
        return ascii_codes
    elif output_format == 'json':
        return json.dumps(ascii_codes)
    elif output_format == 'csv':
        output = StringIO()
        writer = csv.writer(output)
        writer.writerow(['Character', 'ASCII'])
        for char, code in ascii_codes.items():
            writer.writerow([char, code])
        return output.getvalue().strip()

