def extract_last_name(full_name, name_list=None, ignore_suffixes=True, include_prefixes=False, handle_middle_names=False, international_support=False):
    """
    Extracts the last name from a full name string or a list of full names.
    """
    import re

    # Define common suffixes and prefixes
    suffixes = ['Jr', 'Sr', 'II', 'III', 'IV']
    prefixes = ['Dr', 'Mr', 'Ms', 'Mrs']

    def process_name(name):
        # Split the name into parts
        parts = name.split()

        # Handle prefixes
        if include_prefixes:
            parts = [part for part in parts if part not in prefixes]

        # Handle suffixes
        if ignore_suffixes:
            parts = [part for part in parts if part not in suffixes]

        # Handle middle names
        if not handle_middle_names and len(parts) > 2:
            parts = [parts[0], parts[-1]]

        # Handle international support
        if international_support:
            # Example: Handle Spanish names like 'Juan Carlos de la Cruz'
            if 'de' in parts:
                last_name_index = parts.index('de') + 1
                return ' '.join(parts[last_name_index:])

        # Return the last part as the last name
        return parts[-1] if parts else ''

    # Validate input
    if not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a string.'}

    # Process a single name
    if name_list is None:
        return {'last_name': process_name(full_name)}

    # Validate name_list
    if not isinstance(name_list, list) or not all(isinstance(name, str) for name in name_list):
        return {'error': 'Invalid input: name_list must be a list of strings.'}

    # Process a list of names
    last_names = [process_name(name) for name in name_list]
    return {'last_names': last_names}

# Example usage
result = extract_last_name('Don Hahn')
print(result)  # Expected output: {'last_name': 'Hahn'}

