def day_of_week_calculator(date, calendar_system='gregorian', output_format='full', time_zone='UTC'):
    import datetime
    import pytz
    from dateutil import parser

    # Error handling for date format
    try:
        date_obj = parser.parse(date)
    except ValueError:
        return {'error': 'Invalid date format. Please use YYYY-MM-DD.'}

    # Error handling for calendar system
    if calendar_system not in ['gregorian', 'julian', 'hebrew', 'islamic']:
        return {'error': 'Unsupported calendar system. Choose from gregorian, julian, hebrew, islamic.'}

    # Error handling for output format
    if output_format not in ['full', 'abbreviated', 'numeric']:
        return {'error': 'Invalid output format. Choose from full, abbreviated, numeric.'}

    # Error handling for time zone
    try:
        tz = pytz.timezone(time_zone)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time zone. Please use a valid IANA time zone.'}

    # Adjust date for time zone
    date_obj = tz.localize(date_obj)

    # Calculate day of the week
    day_of_week = date_obj.strftime('%A')  # Default to full name
    if output_format == 'abbreviated':
        day_of_week = date_obj.strftime('%a')
    elif output_format == 'numeric':
        day_of_week = date_obj.strftime('%w')  # 0=Sunday, 1=Monday, etc.

    return {'day_of_week': day_of_week}

# Example usage
result = day_of_week_calculator('1980-10-20')
print(result)  # Expected output: {'day_of_week': 'Monday'}

