def letter_counter(input, exclude_characters=['-', ' '], case_sensitive=False, count_vowels=False, count_consonants=False, letter_frequency=False):
    # Validate input type
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not isinstance(exclude_characters, list) or not all(isinstance(ch, str) for ch in exclude_characters):
        return {'error': 'Exclude characters must be a list of strings.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Case sensitive must be a boolean.'}
    if not isinstance(count_vowels, bool):
        return {'error': 'Count vowels must be a boolean.'}
    if not isinstance(count_consonants, bool):
        return {'error': 'Count consonants must be a boolean.'}
    if not isinstance(letter_frequency, bool):
        return {'error': 'Letter frequency must be a boolean.'}

    # Prepare the input string
    if not case_sensitive:
        input = input.lower()

    # Define vowels and consonants
    vowels = 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyz'

    # Initialize counters
    total_letters = 0
    vowel_count = 0
    consonant_count = 0
    frequency = {}

    # Count letters
    for char in input:
        if char in exclude_characters:
            continue
        if char.isalpha():
            total_letters += 1
            if count_vowels and char in vowels:
                vowel_count += 1
            if count_consonants and char in consonants:
                consonant_count += 1
            if letter_frequency:
                if char in frequency:
                    frequency[char] += 1
                else:
                    frequency[char] = 1

    # Prepare the result
    result = {'total_letters': total_letters}
    if count_vowels:
        result['vowel_count'] = vowel_count
    if (count_consonants and char in consonants):
            consonant_count += 1

    # Prepare the result
    result = {'total_letters': total_letters}
    if count_vowels:
        result['vowel_count'] = vowel_count
    if count_consonants:
        result['consonant_count'] = consonant_count
    if letter_frequency:
        result['letter_frequency'] = frequency

    return result

# Example usage based on the question
result = letter_counter(input='Rees-Williams')
print(result)  # Expected output: {'total_letters': 13}

