    if sort_direction not in ['ascending', 'descending']:
        raise ValueError('sort_direction must be either "ascending" or "descending"')
    if not isinstance(handle_diacritics, bool):
        raise ValueError('handle_diacritics must be a boolean')
    if character_set not in ['latin', 'cyrillic', 'greek', 'all']:
        raise ValueError('character_set must be one of "latin", "cyrillic", "greek", "all"')

    # Process input string
    if remove_non_alpha:
        input_string = ''.join(filter(str.isalpha, input_string))

    if ignore_case:
        input_string = input_string.lower()

    # Sort the characters
    sorted_chars = sorted(input_string, reverse=(sort_direction == 'descending'))

    # Return in the specified format
    if output_format == 'string':
        return ''.join(sorted_chars)
