def string_length_calculator(input, ignore_characters=[], ignore_position=[], output_format='integer', case_sensitive=False, character_type_filter=[]):
    """
    Calculate the total number of characters in a given string with options to ignore specific characters or positions,
    customize the output format, and apply filters for character types and case sensitivity.
    """
    # Error handling for required parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Initialize the character set based on filters
    if not case_sensitive:
        input = input.lower()

    # Filter characters based on character_type_filter
    if character_type_filter:
        filtered_input = ''
        for char in input:
            if 'letters' in character_type_filter and char.isalpha():
                filtered_input += char
            elif 'digits' in character_type_filter and char.isdigit():
                filtered_input += char
            elif 'symbols' in character_type_filter and not char.isalnum():
                filtered_input += char
        input = filtered_input

    # Ignore specific characters
    if ignore_characters:
        input = ''.join([char for char in input if char not in ignore_characters])

    # Ignore specific positions
    if ignore_position:
        input = ''.join([char for i, char in enumerate(input)
                         if not ((i == 0 and 'first' in ignore_position) or
                                 (i == len(input) - 1 and 'last' in ignore_position) or
                                 (i % 2 == 0 and 'even' in ignore_position) or
                                 (i % 2 != 0 and 'odd' in ignore_position))])

    # Calculate the length
    length = len(input)

    # Format the output
    if output_format == 'text':
        return f'The length of the string is {length}.'
    elif output_format == 'json':
        return {'length': length}
    else:  # Default to integer
        return length

