def ascii_converter(characters, output_format='list', case_sensitive=True, include_non_printable=False):
    # Validate input parameters
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        raise ValueError("'characters' must be a list of single-character strings.")
    if output_format not in ['list', 'dictionary', 'json', 'csv']:
        raise ValueError("'output_format' must be one of ['list', 'dictionary', 'json', 'csv'].")
    if not isinstance(case_sensitive, bool):
        raise ValueError("'case_sensitive' must be a boolean.")
    if not isinstance(include_non_printable, bool):
        raise ValueError("'include_non_printable' must be a boolean.")

    # Convert characters to ASCII codes
    ascii_codes = {}
    for char in characters:
        if not case_sensitive:
            char = char.lower()
        ascii_code = ord(char)
        if include_non_printable or (32 <= ascii_code <= 126):
            ascii_codes[char] = ascii_code

    # Format output based on 'output_format'
    if output_format == 'list':
        return list(ascii_codes.values())
    elif output_format == 'dictionary':
        return ascii_codes
    elif output_format == 'json':
        import json
        return json.dumps(ascii_codes)
    elif output_format == 'csv':
        return ','.join(f'{char}:{code}' for char, code in ascii_codes.items())

