def consonant_counter(input: str, ignore_characters: list = None, ignore_position: list = None, case_sensitive: bool = False, output_format: str = 'integer') -> str:
    # Define consonants
    consonants = 'bcdfghjklmnpqrstvwxyz'
    if not case_sensitive:
        input = input.lower()
        consonants += consonants.upper()

    # Initialize variables
    count = 0
    detailed_report = {}

    # Validate ignore_position
    valid_positions = {'first', 'last', 'even', 'odd'}
    if ignore_position:
        for pos in ignore_position:
            if pos not in valid_positions:
                return 'Error: Invalid ignore_position value.'

    # Iterate over the string
    for i, char in enumerate(input):
        # Check ignore_characters
        if ignore_characters and char in ignore_characters:
            continue

        # Check ignore_position
        if ignore_position:
            if 'first' in ignore_position and i == 0:
                continue
            if 'last' in ignore_position and i == len(input) - 1:
                continue
            if 'even' in ignore_position and i % 2 == 0:
                continue
            if 'odd' in ignore_position and i % 2 != 0:
                continue

        # Count consonants
        if char in consonants:
            count += 1
            if output_format == 'detailed':
                if char in detailed_report:
                    detailed_report[char] += 1
                else:
                    detailed_report[char] = 1

    # Return based on output_format
    if output_format == 'integer':
        return str(count)
    elif output_format == 'text':
        return f'The number of consonants is {count}.'
    elif output_format == 'detailed':
        return str(detailed_report)
    else:
        return 'Error: Invalid output_format value.'

