def enhanced_timezone_difference_calculator(locations, reference_timezones, date, output_format='hours', include_dst=True):
    """
    Calculate the time difference between specified locations and reference time zones.

    Parameters:
    - locations (list of str): Geographical locations for time zone calculation.
    - reference_timezones (list of str): Reference time zones to compare against.
    - date (str): Date for calculation in YYYY-MM-DD format.
    - output_format (str): Output format ('hours', 'detailed', 'full_report').
    - include_dst (bool): Include daylight saving time adjustments.

    Returns:
    - dict: Result of the time difference calculation.
    """
    import datetime
    from pytz import timezone, UnknownTimeZoneError
    import pytz

    # Error handling for date format
    try:
        calculation_date = datetime.datetime.strptime(date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid date format. Please use YYYY-MM-DD.'}

    # Error handling for output format
    if output_format not in ['hours', 'detailed', 'full_report']:
        return {'error': "Invalid output format. Choose from 'hours', 'detailed', 'full_report'."}

    # Placeholder for time difference calculation
    time_differences = {}

    for location in locations:
        try:
            loc_tz = timezone(location)
        except UnknownTimeZoneError:
            return {'error': f'Unknown time zone for location: {location}'}

        loc_time = loc_tz.localize(calculation_date)

        for ref_tz_name in reference_timezones:
            try:
                ref_tz = timezone(ref_tz_name)
            except UnknownTimeZoneError:
                return {'error': f'Unknown reference time zone: {ref_tz_name}'}

            ref_time = ref_tz.localize(calculation_date)

            # Calculate time difference
            if include_dst:
                time_diff = (loc_time.utcoffset() - ref_time.utcoffset()).total_seconds() / 3600
            else:
                time_diff = (loc_time.utcoffset() - ref_time.utcoffset()).total_seconds() / 3600

            time_differences[(location, ref_tz_name)] = time_diff

    # Generate output based on the specified format
    if output_format == 'hours':
        return {'time_differences': time_differences}
    elif output_format == 'detailed':
        detailed_info = {key: f"Time difference is {value} hours." for key, value in time_differences.items()}
        return {'detailed_info': detailed_info}
    elif output_format == 'full_report':
        full_report = {key: f"Full report: Time difference is {value} hours. DST considered: {include_dst}." for key, value in time_differences.items()}
        return {'full_report': full_report}

