def closest_palindrome_finder(year, search_range=100, return_all=False, palindrome_type='numeric', priority='none'):
    # Helper function to check if a number is a palindrome
    def is_palindrome(num):
        s = str(num)
        return s == s[::-1]

    # Validate inputs
    if not isinstance(year, int):
        raise ValueError('Year must be an integer.')
    if not isinstance(search_range, int) or search_range < 0:
        raise ValueError('Search range must be a non-negative integer.')
    if palindrome_type not in ['numeric', 'alphanumeric']:
        raise ValueError("Palindrome type must be 'numeric' or 'alphanumeric'.")
    if priority not in ['earlier', 'later', 'none']:
        raise ValueError("Priority must be 'earlier', 'later', or 'none'.")

    closest_palindromes = []
    min_distance = float('inf')

    # Search for palindromes within the range
    for i in range(year - search_range, year + search_range + 1):
        if i != year and is_palindrome(i):
            distance = abs(year - i)
            if distance < min_distance:
                closest_palindromes = [i]
                min_distance = distance
            elif distance == min_distance:
                closest_palindromes.append(i)

    # Handle return_all and priority options
    if not return_all:
        if priority == 'earlier':
            return min(closest_palindromes)
        elif priority == 'later':
            return max(closest_palindromes)
        else:
            return closest_palindromes[0]
    return closest_palindromes

