def extract_last_name(full_name, delimiter=' ', ignore_suffixes=False, handle_compound_last_names=True, prefix_handling=False, cultural_convention='western'):
    """
    Extracts the last name from a given full name based on specified parameters.
    """
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name. It must be a non-empty string.'}

    # Split the full name using the specified delimiter
    name_parts = full_name.split(delimiter)

    # Handle prefixes if required
    if prefix_handling and len(name_parts) > 1:
        # Assuming prefix is the first part
        name_parts = name_parts[1:]

    # Handle suffixes if required
    if ignore_suffixes and len(name_parts) > 1:
        # Common suffixes list
        suffixes = ['Jr.', 'Sr.', 'II', 'III', 'IV']
        if name_parts[-1] in suffixes:
            name_parts = name_parts[:-1]

    # Handle compound last names
    if handle_compound_last_names:
        # Example logic for compound last names
        compound_identifiers = ['de', 'la', 'van', 'von']
        if len(name_parts) > 1 and name_parts[-2].lower() in compound_identifiers:
            last_name = delimiter.join(name_parts[-2:])
        else:
            last_name = name_parts[-1]
    else:
        last_name = name_parts[-1]

    # Cultural convention handling
    if cultural_convention == 'eastern' and len(name_parts) > 1:
        # In some eastern conventions, the last name comes first
        last_name = name_parts[0]

