def distinct_combinations(input_string, combination_length=2, output_format='count', case_sensitive=False):
    from itertools import combinations

    # Error handling for input types
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string.'}
    if not isinstance(combination_length, int) or combination_length <= 0:
        return {'error': 'combination_length must be a positive integer.'}
    if output_format not in ['list', 'count', 'detailed']:
        return {'error': "output_format must be one of ['list', 'count', 'detailed']."}
    if not isinstance(case_sensitive, bool):
        return {'error': 'case_sensitive must be a boolean.'}

    # Adjust case sensitivity
    if not case_sensitive:
        input_string = input_string.lower()

    # Generate combinations
    comb_set = set(combinations(input_string, combination_length))

    # Prepare output based on format
    if output_format == 'list':
        return {'result': [''.join(comb) for comb in comb_set]}
    elif output_format == 'count':
        return {'result': len(comb_set)}
    elif output_format == 'detailed':
        from collections import Counter
        comb_list = [''.join(comb) for comb in combinations(input_string, combination_length)]
        comb_count = Counter(comb_list)
        return {'result': [{'combination': k, 'count': v} for k, v in comb_count.items()]}

