def reverse_string(input: str, case_transformation: str = 'none', reverse_scope: str = 'full', whitespace_handling: str = 'preserve', encoding: str = 'UTF-8') -> str:
    """
    Reverses the order of characters in a given string with options for case transformation,
    reversal scope, whitespace handling, and character encoding.
    """
    # Validate parameters
    if case_transformation not in ['none', 'uppercase', 'lowercase']:
        raise ValueError("Invalid value for case_transformation. Allowed values are 'none', 'uppercase', 'lowercase'.")
    if reverse_scope not in ['full', 'words', 'characters']:
        raise ValueError("Invalid value for reverse_scope. Allowed values are 'full', 'words', 'characters'.")
    if whitespace_handling not in ['preserve', 'trim', 'collapse']:
        raise ValueError("Invalid value for whitespace_handling. Allowed values are 'preserve', 'trim', 'collapse'.")
    if encoding not in ['UTF-8', 'ASCII', 'ISO-8859-1']:
        raise ValueError("Invalid value for encoding. Allowed values are 'UTF-8', 'ASCII', 'ISO-8859-1'.")

    # Handle whitespace
    if whitespace_handling == 'trim':
        input = input.strip()
    elif whitespace_handling == 'collapse':
        input = ' '.join(input.split())

    # Reverse the string based on the scope
    if reverse_scope == 'full':
        reversed_string = input[::-1]
    elif reverse_scope == 'words':
        reversed_string = ' '.join(input.split()[::-1])
    elif reverse_scope == 'characters':
        reversed_string = ' '.join(word[::-1] for word in input.split())

    # Apply case transformation
    if case_transformation == 'uppercase':
        reversed_string = reversed_string.upper()
    elif case_transformation == 'lowercase':
        reversed_string = reversed_string.lower()

    return reversed_string

