def monarch_reign_analyzer(monarch_data, output_format='name_only', filter=None):
    import datetime
    from dateutil import parser

    def calculate_reign_duration(start_date, end_date):
        try:
            start = parser.parse(start_date)
            end = parser.parse(end_date) if end_date.lower() != 'present' else datetime.datetime.now()
            return (end - start).days
        except Exception as e:
            raise ValueError(f'Invalid date format: {e}')

    if not isinstance(monarch_data, list):
        raise ValueError('monarch_data must be a list of dictionaries.')

    longest_reign = {'name': '', 'duration': 0}

    for monarch in monarch_data:
        try:
            name = monarch['name']
            start_date = monarch['start_date']
            end_date = monarch['end_date']
            region = monarch.get('region', '')
            era = monarch.get('era', '')

            if filter:
                if 'region' in filter and filter['region'] != region:
                    continue
                if 'era' in filter and filter['era'] != era:
                    continue

            duration = calculate_reign_duration(start_date, end_date)

            if duration > longest_reign['duration']:
                longest_reign = {'name': name, 'duration': duration, 'region': region, 'era': era}

        except KeyError as e:
            raise ValueError(f'Missing required field: {e}')

    if output_format == 'name_only':
        return longest_reign['name']
    elif output_format == 'detailed':
        return f"{longest_reign['name']} reigned for {longest_reign['duration']} days."
    elif output_format == 'full_report':
        return f"{longest_reign['name']} reigned for {longest_reign['duration']} days in {longest_reign['region']} during the {longest_reign['era']} era."
    else:
        raise ValueError('Invalid output format specified.')

