def count_characters(input: str, characters: list = ['a', 'e', 'i', 'o', 'u'], ignore_case: bool = True, output_format: str = 'integer', count_non_alphabetic: bool = False, group_by: str = 'none') -> str:
    # Validate input types
    if not isinstance(input, str):
        return 'Error: Input must be a string.'
    if not isinstance(characters, list) or not all(isinstance(c, str) for c in characters):
        return 'Error: Characters must be a list of strings.'
    if not isinstance(ignore_case, bool):
        return 'Error: Ignore_case must be a boolean.'
    if output_format not in ['integer', 'text', 'detailed']:
        return 'Error: Output_format must be one of ["integer", "text", "detailed"].'
    if not isinstance(count_non_alphabetic, bool):
        return 'Error: Count_non_alphabetic must be a boolean.'
    if group_by not in ['none', 'vowel', 'consonant', 'custom']:
        return 'Error: Group_by must be one of ["none", "vowel", "consonant", "custom"].'

    # Prepare the input string based on case sensitivity
    if ignore_case:
        input = input.lower()
        characters = [c.lower() for c in characters]

    # Count occurrences of specified characters
    count = {char: 0 for char in characters}
    for char in input:
        if char in count:
            count[char] += 1

    # Calculate total count
    total_count = sum(count.values())

    # Format the output
    if output_format == 'integer':
        return str(total_count)
    elif output_format == 'text':
        return f'Total count of specified characters: {total_count}'
    elif output_format == 'detailed':
        return str(count)

