def extract_first_name(full_name, delimiters=[' '], ignore_titles=True, ignore_suffixes=True, output_format='string'):
    # Define common titles and suffixes
    titles = {'Mr.', 'Ms.', 'Mrs.', 'Dr.', 'Sir'}
    suffixes = {'Jr.', 'Sr.', 'III', 'IV'}

    # Error handling for incorrect input types
    if not isinstance(full_name, str):
        return {'error': 'full_name must be a string'}
    if not isinstance(delimiters, list) or not all(isinstance(d, str) for d in delimiters):
        return {'error': 'delimiters must be a list of strings'}
    if not isinstance(ignore_titles, bool):
        return {'error': 'ignore_titles must be a boolean'}
    if not isinstance(ignore_suffixes, bool):
        return {'error': 'ignore_suffixes must be a boolean'}
    if output_format not in ['string', 'json', 'array']:
        return {'error': 'output_format must be one of string, json, array'}

    # Split the full name using the provided delimiters
    import re
    pattern = '|'.join(map(re.escape, delimiters))
    name_parts = re.split(pattern, full_name)

    # Filter out titles and suffixes if required
    if ignore_titles:
        name_parts = [part for part in name_parts if part not in titles]
    if ignore_suffixes:
        name_parts = [part for part in name_parts if part not in suffixes]

    # Extract the first name
    first_name = name_parts[0] if name_parts else ''

    # Return the first name in the desired format
    if output_format == 'string':
        return first_name
    elif output_format == 'json':
        return {'first_name': first_name}
    elif output_format == 'array':
        return [first_name]

