        for title in titles:
            if full_name.startswith(title):
                full_name = full_name[len(title):].strip()

    # Split the full name based on the provided delimiters
    import re
    delimiter_pattern = '|'.join(map(re.escape, multiple_delimiters))
    name_parts = re.split(delimiter_pattern, full_name)

    # Determine the last name based on the name format
    if name_format == 'western':
        last_name = name_parts[-1]
    elif name_format == 'eastern':
        last_name = name_parts[0]
    elif name_format == 'arabic':
        last_name = name_parts[-1]
    elif name_format == 'hispanic':
        last_name = name_parts[-2] if len(name_parts) > 1 else name_parts[-1]
    elif name_format == 'custom':
