def enhanced_unique_letter_counter(input, case_sensitive=False, ignore_characters=[], alphabet='Latin', include_numbers=False, detailed_report=False):
    # Validate input parameter
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}

    # Validate other parameters
    if not isinstance(case_sensitive, bool):
        return {'error': 'case_sensitive must be a boolean.'}
    if not isinstance(ignore_characters, list) or not all(isinstance(ch, str) for ch in ignore_characters):
        return {'error': 'ignore_characters must be a list of strings.'}
    if not isinstance(alphabet, str):
        return {'error': 'alphabet must be a string.'}
    if not isinstance(include_numbers, bool):
        return {'error': 'include_numbers must be a boolean.'}
    if not isinstance(detailed_report, bool):
        return {'error': 'detailed_report must be a boolean.'}

    # Define the set of characters to consider based on the alphabet
    if alphabet == 'Latin':
        valid_characters = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ')
    else:
        return {'error': 'Unsupported alphabet.'}

    # Adjust valid characters based on case sensitivity
    if not case_sensitive:
        valid_characters = set(ch.lower() for ch in valid_characters)
        input = input.lower()

    # Filter out ignored characters
    valid_characters -= set(ignore_characters)

    # Include numbers if specified
    if include_numbers:
        valid_characters.update(set('0123456789'))

    # Count unique letters
    unique_letters = set(ch for ch in input if ch in valid_characters)

    # Prepare detailed report if required
    if detailed_report:
        report = {ch: input.count(ch) for ch in unique_letters}
        return {'unique_count': len(unique_letters), 'report': report}

    return {'unique_count': len(unique_letters)}

