def consonant_counter(input: str, consonant_set: list = ['b', 'c', 'd', 'f', 'g', 'h', 'j', 'k', 'l', 'm', 'n', 'p', 'q', 'r', 's', 't', 'v', 'w', 'x', 'y', 'z'], case_sensitive: bool = False, language_rules: str = 'none', exclude_characters: list = [], count_unique: bool = False, detailed_statistics: bool = False):
    # Error handling for required parameter
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}

    # Adjust consonant set based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        consonant_set = [c.lower() for c in consonant_set]
        exclude_characters = [c.lower() for c in exclude_characters]

    # Apply language-specific rules
    if language_rules == 'treat_y_as_vowel':
        consonant_set = [c for c in consonant_set if c != 'y']

    # Filter out excluded characters
    consonant_set = [c for c in consonant_set if c not in exclude_characters]

    # Count consonants
    consonant_count = 0
    consonant_frequency = {}
    for char in input:
        if char in consonant_set:
            if count_unique:
                if char not in consonant_frequency:
                    consonant_count += 1
                    consonant_frequency[char] = 1
            else:
                consonant_count += 1
                if detailed_statistics:
                    if char in consonant_frequency:
                        consonant_frequency[char] += 1
                    else:
                        consonant_frequency[char] = 1

    # Return results
    if detailed_statistics:
        return {'total_consonants': consonant_count, 'frequency': consonant_frequency}
    else:
        return {'total_consonants': consonant_count}

# Example usage based on the question
result = consonant_counter('Rohana')
print(result)  # Expected output: {'total_consonants': 3}

