def closest_palindrome_finder(year, direction='both', output_format='integer', range_limit=None, return_multiple=False):
    """
    Finds the closest palindrome number to a given year.

    Parameters:
    year (int): The year for which the closest palindrome number is to be found.
    direction (str): The direction in which to search for the closest palindrome. Defaults to 'both'.
    output_format (str): The format of the output. Defaults to 'integer'.
    range_limit (int): The maximum number of years to search in each direction. Defaults to no limit.
    return_multiple (bool): Whether to return multiple closest palindromes if they are equidistant from the given year. Defaults to false.

    Returns:
    int or str or list: The closest palindrome number(s) in the specified format.
    """
    def is_palindrome(n):
        return str(n) == str(n)[::-1]

    if not isinstance(year, int):
        raise ValueError("Year must be an integer.")
    if direction not in ['both', 'past', 'future']:
        raise ValueError("Direction must be 'both', 'past', or 'future'.")
    if output_format not in ['integer', 'text']:
        raise ValueError("Output format must be 'integer' or 'text'.")
    if range_limit is not None and not isinstance(range_limit, int):
        raise ValueError("Range limit must be an integer or None.")
    if not isinstance(return_multiple, bool):
        raise ValueError("Return multiple must be a boolean.")

    closest_palindromes = []
    min_distance = float('inf')

    def search_in_direction(start, step):
        nonlocal min_distance
        for i in range(range_limit if range_limit is not None else float('inf')):
            candidate_year = start + step * i
            if is_palindrome(candidate_year):
                distance = abs(candidate_year - year)
                if distance < min_distance:
                    closest_palindromes.clear()
                    closest_palindromes.append(candidate_year)
                    min_distance = distance
                elif distance == min_distance and return_multiple:
                    closest_palindromes.append(candidate_year)
                if not return_multiple:
                    break

    if direction in ['both', 'past']:
        search_in_direction(year, -1)
    if direction in ['both', 'future']:
        search_in_direction(year, 1)

    if output_format == 'text':
        return [str(p) for p in closest_palindromes] if return_multiple else str(closest_palindromes[0])
    return closest_palindromes if return_multiple else closest_palindromes[0]

# Example usage:
# closest_palindrome_finder(1813)  # Should return 1771

def extract_name_part(full_name: str, delimiter: str = ' ', name_part: str = 'last', handle_suffix: bool = False, handle_prefix: bool = False, cultural_convention: str = 'western', compound_name_handling: bool = True) -> str:
    # Split the full name using the specified delimiter
    name_parts = full_name.split(delimiter)

    # Handle prefix if specified
    if handle_prefix and cultural_convention == 'western':
        prefixes = ['Mr.', 'Mrs.', 'Dr.', 'Ms.']
        if name_parts[0] in prefixes:
            name_parts = name_parts[1:]

    # Handle suffix if specified
    if handle_suffix and cultural_convention == 'western':
        suffixes = ['Jr.', 'Sr.', 'II', 'III']
        if name_parts[-1] in suffixes:
            name_parts = name_parts[:-1]

    # Determine the part of the name to extract
    if name_part == 'first':
        return name_parts[0]
    elif name_part == 'middle':
        if len(name_parts) > 2:
            return ' '.join(name_parts[1:-1])
        else:
            return ''  # No middle name
    elif name_part == 'last':
        if compound_name_handling:
            return ' '.join(name_parts[1:]) if len(name_parts) > 1 else name_parts[0]
        else:
            return name_parts[-1]
    elif name_part == 'prefix':
        return name_parts[0] if handle_prefix else ''
    elif name_part == 'suffix':
        return name_parts[-1] if handle_suffix else ''
    else:
        raise ValueError('Invalid name part specified.')

    # Error handling for invalid cultural conventions
    if cultural_convention not in ['western', 'eastern', 'latin', 'custom']:
        raise ValueError('Invalid cultural convention specified.')

    # Default return if no valid part is found
    return ''

