def enhanced_combinations(input_string, combination_length=2, output_format='count', filter_characters='', case_sensitive=False):
    from itertools import combinations

    # Error handling for input validation
    if not isinstance(input_string, str) or not input_string:
        return {'error': 'Invalid input_string. It must be a non-empty string.'}
    if not isinstance(combination_length, int) or combination_length < 1:
        return {'error': 'Invalid combination_length. It must be an integer greater than or equal to 1.'}
    if output_format not in ['list', 'count', 'detailed']:
        return {'error': 'Invalid output_format. Choose from list, count, or detailed.'}
    if not isinstance(filter_characters, str):
        return {'error': 'Invalid filter_characters. It must be a string.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive. It must be a boolean.'}

    # Adjust input string based on case sensitivity
    if not case_sensitive:
        input_string = input_string.lower()
        filter_characters = filter_characters.lower()

    # Generate combinations
    all_combinations = combinations(input_string, combination_length)

    # Filter combinations if filter_characters is provided
    if filter_characters:
        filtered_combinations = [comb for comb in all_combinations if any(char in filter_characters for char in comb)]
    else:
        filtered_combinations = list(all_combinations)

    # Convert combinations to strings
    filtered_combinations = [''.join(comb) for comb in filtered_combinations]

    # Remove duplicates
    unique_combinations = set(filtered_combinations)

    # Return based on output_format
    if output_format == 'list':
        return list(unique_combinations)
    elif output_format == 'count':
        return len(unique_combinations)
    elif output_format == 'detailed':
        return {'combinations': list(unique_combinations), 'count': len(unique_combinations)}

    return {'error': 'Unexpected error occurred.'}

