def extract_last_name(full_name, delimiter='space', case_sensitive=False, output_format='string', include_prefix_suffix=False):
    # Define delimiter mapping
    delimiters = {
        'space': ' ',
        'apostrophe': "'",
        'comma': ',',
        'hyphen': '-'
    }

    # Validate delimiter
    if delimiter not in delimiters:
        return {'error': 'Invalid delimiter specified.'}

    # Split the full name based on the specified delimiter
    name_parts = full_name.split(delimiters[delimiter])

    # Handle case sensitivity
    if not case_sensitive:
        name_parts = [part.lower() for part in name_parts]

    # Determine the last name
    last_name = name_parts[-1]

    # Include prefix/suffix if specified
    if include_prefix_suffix and len(name_parts) > 1:
        last_name = ' '.join(name_parts[-2:])

    # Prepare output based on the specified format
    if output_format == 'string':
        return last_name
    elif output_format == 'array':
        return [last_name]
    elif output_format == 'detailed':
        return {
            'last_name': last_name,
            'name_parts': name_parts,
            'delimiter_used': delimiter
        }
    else:
        return {'error': 'Invalid output format specified.'}

