def get_last_character(input: str, ignore_special_characters: bool = False, ignore_whitespace: bool = False, character_set: str = '', case_sensitive: bool = True) -> str:
    # Validate input type
    if not isinstance(input, str):
        return 'Error: Input must be a string.'

    # Apply ignore_whitespace
    if ignore_whitespace:
        input = input.rstrip()

    # Apply ignore_special_characters
    if ignore_special_characters:
        input = ''.join(filter(str.isalnum, input))

    # Apply character_set filtering
    if character_set:
        input = ''.join(filter(lambda c: c in character_set, input))

    # Handle case sensitivity
    if not case_sensitive:
        input = input.lower()

    # Return the last character if available
    if input:
        return input[-1]
    else:
        return 'Error: No valid character found.'

