    # Find the actor in the cast
    actor_info = next((actor for actor in film_data['cast'] if actor['name'] == actor_name), None)
    if not actor_info:
        return {'error': 'Actor not found in the film cast.'}

    # Filter co-stars based on role_type
    co_stars = [actor['name'] for actor in film_data['cast'] if actor['name'] != actor_name and (role_type == 'any' or actor['role_type'] == role_type)]

    # Format output
    if output_format == 'list':
        return co_stars
    elif output_format == 'text':
        return ', '.join(co_stars)
