def string_length_calculator_v2(input: str, ignore_characters: list = [], ignore_position: list = [], case_sensitive: bool = False, count_types: list = ['all'], output_format: str = 'integer') -> int:
    # Validate input
    if not isinstance(input, str):
        raise ValueError("Input must be a string.")
    if not isinstance(ignore_characters, list) or not all(isinstance(c, str) for c in ignore_characters):
        raise ValueError("Ignore characters must be a list of strings.")
    if not isinstance(ignore_position, list) or not all(p in ['first', 'last', 'even', 'odd'] for p in ignore_position):
        raise ValueError("Ignore position must be a list containing 'first', 'last', 'even', or 'odd'.")
    if not isinstance(case_sensitive, bool):
        raise ValueError("Case sensitive must be a boolean.")
    if not isinstance(count_types, list) or not all(t in ['all', 'vowels', 'consonants'] for t in count_types):
        raise ValueError("Count types must be a list containing 'all', 'vowels', or 'consonants'.")
    if output_format not in ['integer', 'text', 'detailed']:
        raise ValueError("Output format must be 'integer', 'text', or 'detailed'.")

    # Normalize input if case insensitive
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [c.lower() for c in ignore_characters]

    # Define vowels and consonants
    vowels = 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyz'

    # Initialize count
    count = 0
    detailed_count = {'vowels': 0, 'consonants': 0}

    # Iterate over input string
    for i, char in enumerate(input):
        # Ignore specified characters
        if char in ignore_characters:
            continue

        # Ignore specified positions
        if ('first' in ignore_position and i == 0) or \
           ('last' in ignore_position and i == len(input) - 1) or \
           ('even' in ignore_position and i % 2 == 0) or \
           ('odd' in ignore_position and i % 2 != 0):
            continue

        # Count based on count_types
        if 'all' in count_types or ('vowels' in count_types and char in vowels) or ('consonants' in count_types and char in consonants):
            count += 1
            if char in vowels:
                detailed_count['vowels'] += 1
            elif char in consonants:
                detailed_count['consonants'] += 1

    # Return based on output_format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f"The total number of letters is {count}."
    elif output_format == 'detailed':
        return {
            'total': count,
            'vowels': detailed_count['vowels'],
            'consonants': detailed_count['consonants']
        }

