def date_calculator(start_date, duration, output_format='YYYY-MM-DD', timezone='UTC', business_days_only=False, exclude_holidays=[]):
    from datetime import datetime, timedelta
    import pytz
    from dateutil.relativedelta import relativedelta

    # Validate start_date format
    try:
        start_date_obj = datetime.strptime(start_date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid start_date format. Expected YYYY-MM-DD.'}

    # Validate duration
    if not isinstance(duration, dict) or 'value' not in duration or 'unit' not in duration:
        return {'error': 'Invalid duration format. Expected an object with value and unit.'}

    value = duration['value']
    unit = duration['unit']

    if unit not in ['minutes', 'hours', 'days', 'weeks', 'months', 'years']:
        return {'error': 'Invalid duration unit. Supported units are minutes, hours, days, weeks, months, years.'}

    # Calculate the new date based on the duration
    if unit == 'minutes':
        delta = timedelta(minutes=value)
    elif unit == 'hours':
        delta = timedelta(hours=value)
    elif unit == 'days':
        delta = timedelta(days=value)
    elif unit == 'weeks':
        delta = timedelta(weeks=value)
    elif unit == 'months':
        delta = relativedelta(months=value)
    elif unit == 'years':
        delta = relativedelta(years=value)

    new_date = start_date_obj + delta

    # Format the output date
    if output_format == 'MM-DD-YYYY':
        formatted_date = new_date.strftime('%m-%d-%Y')
    elif output_format == 'DD-MM-YYYY':
        formatted_date = new_date.strftime('%d-%m-%Y')
    else:
        formatted_date = new_date.strftime('%Y-%m-%d')

    return {'result': formatted_date}

