def day_of_week_calculator(date: str, calendar_system: str = 'gregorian', output_format: str = 'full', locale: str = 'en-US') -> str:
    import datetime
    import calendar
    from babel.dates import format_date

    # Error handling for unsupported calendar systems
    if calendar_system not in ['gregorian', 'julian', 'hebrew', 'islamic']:
        return 'Error: Unsupported calendar system.'

    # Error handling for unsupported output formats
    if output_format not in ['full', 'abbreviated', 'numeric']:
        return 'Error: Unsupported output format.'

    # Attempt to parse the date
    try:
        # Handle different date formats
        if '-' in date:
            if len(date.split('-')[0]) == 4:
                date_obj = datetime.datetime.strptime(date, '%Y-%m-%d')
            else:
                date_obj = datetime.datetime.strptime(date, '%d-%m-%Y')
        elif '/' in date:
            date_obj = datetime.datetime.strptime(date, '%m/%d/%Y')
        else:
            return 'Error: Unsupported date format.'
    except ValueError:
        return 'Error: Invalid date.'

    # Calculate the day of the week
    day_of_week = date_obj.weekday()  # Monday is 0 and Sunday is 6

    # Adjust for output format
    if output_format == 'full':
        return format_date(date_obj, 'EEEE', locale=locale)
    elif output_format == 'abbreviated':
        return format_date(date_obj, 'EEE', locale=locale)
    elif output_format == 'numeric':
        return str((day_of_week + 1) % 7)  # Adjusting to make Sunday 0

    return 'Error: Unknown error occurred.'

