def string_length_counter(input, ignore_characters=[], ignore_position=[], output_format='integer', case_sensitive=False, count_types=[]):
    # Validate input
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}
    if not isinstance(ignore_characters, list) or not all(isinstance(char, str) for char in ignore_characters):
        return {'error': 'Invalid ignore_characters type. Must be a list of strings.'}
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position type. Must be a list containing "first" or "last".'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format. Must be "integer", "text", or "detailed".'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive type. Must be a boolean.'}
    if not isinstance(count_types, list) or not all(ct in ['alphabets', 'digits', 'special'] for ct in count_types):
        return {'error': 'Invalid count_types. Must be a list containing "alphabets", "digits", or "special".'}

    # Initialize count
    count = 0

    # Define character type checks
    def is_alphabet(char):
        return char.isalpha()

    def is_digit(char):
        return char.isdigit()

    def is_special(char):
        return not char.isalnum()

    # Determine which types to count
    if not count_types:
        count_types = ['alphabets', 'digits', 'special']

    # Process input string
    for i, char in enumerate(input):
        if char in ignore_characters:
            continue
        if 'first' in ignore_position and i == 0:
            continue
        if 'last' in ignore_position and i == len(input) - 1:
            continue

        # Check character types
        if 'alphabets' in count_types and is_alphabet(char):
            count += 1
        elif 'digits' in count_types and is_digit(char):
            count += 1
        elif 'special' in count_types and is_special(char):
            count += 1

    # Format output
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'Total count: {count}'
    elif output_format == 'detailed':
        return {
            'total': count,
            'alphabets': sum(1 for char in input if is_alphabet(char)),
            'digits': sum(1 for char in input if is_digit(char)),
            'special': sum(1 for char in input if is_special(char))
        }

