            if start < 0 or end >= len(reversed_string) or start > end:
                return {'error': 'Invalid segment indices.'}
            segment_reversed = reversed_string[start:end+1][::-1]
            reversed_string = reversed_string[:start] + segment_reversed + reversed_string[end+1:]
    else:
        # Reverse the entire string
        reversed_string = reversed_string[::-1]

    # Handle case sensitivity
    if not case_sensitive:
        reversed_string = reversed_string.lower()

    # Handle output_format
    if output_format == 'array':
        return {'result': reversed_string.split(delimiter)}
    else:
        return {'result': reversed_string}

