    """
    Extracts the last name from a full name string based on the specified parameters.

    :param full_name: The full name from which to extract the last name.
    :param name_format: The format of the name ('western', 'eastern', 'custom').
    :param custom_delimiter: A custom delimiter for separating names.
    :param output_format: The format of the output ('string', 'array', 'detailed').
    :param include_middle_names: Whether to include middle names in the extraction.
    :param handle_suffixes: Whether to handle suffixes in the extraction.
    :param compound_last_name_handling: How to handle compound last names ('merge', 'separate').
    :return: The extracted last name in the specified format.
    """
    # Error handling for required parameter
    if not full_name:
        return {'error': 'The full_name parameter is required.'}

    # Split the full name based on the custom delimiter
    name_parts = full_name.split(custom_delimiter)

    # Determine the last name based on the name format
    if name_format == 'western':
