    else:
        return {'error': 'Invalid name_format value.'}

    # Handle compound last names
    if compound_last_name_handling == 'merge':
        last_name = ' '.join(last_name.split())
    elif compound_last_name_handling == 'separate':
        last_name = last_name.split()
    else:
        return {'error': 'Invalid compound_last_name_handling value.'}

    # Prepare the output based on the output format
    if output_format == 'string':
        return last_name if isinstance(last_name, str) else ' '.join(last_name)
    elif output_format == 'array':
        return last_name if isinstance(last_name, list) else [last_name]
    elif output_format == 'detailed':
