    if not isinstance(include_middle_name, bool):
        raise ValueError('The include_middle_name parameter must be a boolean.')
    if not isinstance(handle_suffixes, bool):
        raise ValueError('The handle_suffixes parameter must be a boolean.')
    if not isinstance(handle_prefixes, bool):
