def count_letters(input, ignore_characters=None, ignore_position=None, output_format='integer', case_sensitive=False, count_types=['all']):
    # Validate input parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type, expected a string.'}

    # Initialize variables
    count = 0
    vowels = 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyz'

    # Prepare input based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        vowels = vowels.lower()
        consonants = consonants.lower()

    # Handle ignore positions
    if ignore_position:
        if 'first' in ignore_position and len(input) > 0:
            input = input[1:]
        if 'last' in ignore_position and len(input) > 0:
            input = input[:-1]

    # Count letters based on specified types
    for char in input:
        if ignore_characters and char in ignore_characters:
            continue
        if 'all' in count_types:
            if char.isalpha():
                count += 1
        else:
            if 'vowels' in count_types and char in vowels:
                count += 1
            if 'consonants' in count_types and char in consonants:
                count += 1

    # Prepare output based on format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The count is {count}.'
    elif output_format == 'detailed':
        return {
            'total': count,
            'vowels': sum(1 for char in input if char in vowels),
            'consonants': sum(1 for char in input if char in consonants)
        }
    else:
        return {'error': 'Invalid output format specified.'}

