def extract_first_name(full_names, name_delimiter=' ', output_format='string', case_sensitive=False, handle_prefixes=False, handle_suffixes=False, allow_multiple_first_names=False, non_standard_character_handling='ignore'):
    # Define prefixes and suffixes to handle if specified
    prefixes = ['Mr.', 'Mrs.', 'Dr.', 'Ms.'] if handle_prefixes else []
    suffixes = ['Jr.', 'Sr.', 'II', 'III'] if handle_suffixes else []

    # Function to clean and process each name
    def process_name(name):
        # Handle non-standard characters
        if non_standard_character_handling == 'error' and not name.isascii():
            raise ValueError('Non-standard characters found in name.')
        elif non_standard_character_handling == 'replace':
            name = ''.join(c if c.isascii() else '?' for c in name)

        # Split the name by the delimiter
        parts = name.split(name_delimiter)

        # Remove prefixes and suffixes if specified
        if handle_prefixes and parts[0] in prefixes:
            parts.pop(0)
        if handle_suffixes and parts[-1] in suffixes:
            parts.pop()

        # Extract first name(s)
        if allow_multiple_first_names:
            first_name = ' '.join(parts[:2])  # Assuming two parts as multiple first names
        else:
            first_name = parts[0]

        return first_name

    # Process each full name
    first_names = [process_name(name) for name in full_names]

    # Return based on the output format
    if output_format == 'array':
        return first_names
    else:
        return first_names[0] if len(first_names) == 1 else ', '.join(first_names)

