def count_letters(input, ignore_characters=None, ignore_position=None, output_format='integer', case_sensitive=False, include_characters=None):
    # Validate the required 'input' parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Expected a string.'}

    # Initialize a set of characters to be counted
    characters_to_count = set(input)

    # Handle 'ignore_characters' parameter
    if ignore_characters:
        characters_to_count -= set(ignore_characters)

    # Handle 'include_characters' parameter
    if include_characters:
        characters_to_count &= set(include_characters)

    # Convert to lowercase if case sensitivity is not required
    if not case_sensitive:
        input = input.lower()
        characters_to_count = {char.lower() for char in characters_to_count}

    # Handle 'ignore_position' parameter
    if ignore_position:
        if 'first' in ignore_position and len(input) > 0:
            input = input[1:]
        if 'last' in ignore_position and len(input) > 0:
            input = input[:-1]

    # Count the letters
    count = sum(1 for char in input if char in characters_to_count)

    # Format the output based on 'output_format'
    if output_format == 'text':
        return f'The number of letters is {count}.'
    elif output_format == 'detailed':
        detailed_count = {char: input.count(char) for char in characters_to_count}
        return detailed_count
    else:  # Default to 'integer'
        return count

