        # Handle hyphenated words if necessary
        if handle_hyphenated and '-' in word:
            sub_words = word.split('-')
        else:
            sub_words = [word]

        for sub_word in sub_words:
            # Extract the first letter of each sub-word
            if ignore_non_alpha:
                sub_word = ''.join(filter(str.isalpha, sub_word))
            if sub_word:
                initial = sub_word[0]
                if not case_sensitive:
                    initial = initial.upper()
                initials.append(initial)

    # Join initials with the specified delimiter
    result = delimiter.join(initials)

