def extract_last_name(full_name, delimiter=' ', ignore_special_characters=False, output_format='string', include_middle_names=False, handle_suffixes=True, cultural_naming_convention='western'):
    # Validate input types
    if not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a string.'}
    if not isinstance(delimiter, str):
        return {'error': 'Invalid input: delimiter must be a string.'}
    if not isinstance(ignore_special_characters, bool):
        return {'error': 'Invalid input: ignore_special_characters must be a boolean.'}
    if output_format not in ['string', 'array']:
        return {'error': 'Invalid input: output_format must be either "string" or "array".'}
    if not isinstance(include_middle_names, bool):
        return {'error': 'Invalid input: include_middle_names must be a boolean.'}
    if not isinstance(handle_suffixes, bool):
        return {'error': 'Invalid input: handle_suffixes must be a boolean.'}
    if cultural_naming_convention not in ['western', 'eastern', 'custom']:
        return {'error': 'Invalid input: cultural_naming_convention must be "western", "eastern", or "custom".'}

    # Split the full name using the delimiter
    name_parts = full_name.split(delimiter)

    # Handle special characters if needed
    if ignore_special_characters:
        name_parts = [''.join(e for e in part if e.isalnum()) for part in name_parts]

    # Determine the last name based on cultural naming convention
    if cultural_naming_convention == 'western':
        # Western convention assumes the last part is the last name
        last_name = name_parts[-1]
    elif cultural_naming_convention == 'eastern':
        # Eastern convention assumes the first part is the last name
        last_name = name_parts[0]
    else:
        # Custom convention can be defined as needed
        last_name = name_parts[-1]  # Default to western for custom

    # Handle suffixes if needed
    if handle_suffixes and len(name_parts) > 1:
        suffixes = ['Jr', 'Sr', 'II', 'III', 'IV']
        if name_parts[-1].replace('.', '') in suffixes:
            last_name = name_parts[-2]

    # Include middle names if specified
    if include_middle_names and len(name_parts) > 2:
        middle_names = name_parts[1:-1] if cultural_naming_convention == 'western' else name_parts[1:]
        if output_format == 'array':
            return middle_names + [last_name]
        else:
            return ' '.join(middle_names + [last_name])

    # Return the last name in the specified format
    if output_format == 'array':
        return [last_name]
    else:
        return last_name

