def combined_length_calculator_v2(input, ignore_characters=None, ignore_position=None, case_sensitive=True, trim_whitespace=False, character_range=None, output_format='integer'):
    # Validate input
    if not isinstance(input, list) or len(input) < 2:
        return {'error': 'Input must be a list with at least two strings.'}
    if ignore_characters and not isinstance(ignore_characters, list):
        return {'error': 'ignore_characters must be a list of strings.'}
    if ignore_position and not isinstance(ignore_position, list):
        return {'error': 'ignore_position must be a list of strings.'}
    if character_range and not isinstance(character_range, dict):
        return {'error': 'character_range must be a dictionary with start and end keys.'}

    # Initialize total length
    total_length = 0

    # Process each string
    for string in input:
        # Trim whitespace if required
        if trim_whitespace:
            string = string.strip()

        # Apply character range if specified
        if character_range:
            start = character_range.get('start', 0)
            end = character_range.get('end', len(string))
            string = string[start:end]

        # Ignore specified characters
        if ignore_characters:
            for char in ignore_characters:
                string = string.replace(char, '')

        # Ignore specified positions
        if ignore_position:
            if 'first' in ignore_position and len(string) > 0:
                string = string[1:]
            if 'last' in ignore_position and len(string) > 0:
                string = string[:-1]
            if 'middle' in ignore_position and len(string) > 2:
                string = string[0] + string[2:]

        # Adjust case sensitivity
        if not case_sensitive:
            string = string.lower()

        # Add to total length
        total_length += len(string)

    # Return result in specified format
    if output_format == 'integer':
        return total_length
    elif output_format == 'text':
        return f'The combined length is {total_length}.'
    elif output_format == 'detailed':
        return {'combined_length': total_length, 'details': [{'string': s, 'length': len(s)} for s in input]}
    else:
        return {'error': 'Invalid output format specified.'}

