def date_calculator(start_date: str, days_to_add: int, hours_to_add: int = 0, minutes_to_add: int = 0, calendar_system: str = 'gregorian', output_format: str = 'YYYY-MM-DD', time_zone: str = 'UTC', calculate_difference: bool = False, end_date: str = None) -> str:
    from datetime import datetime, timedelta
    import pytz

    # Error handling for date format
    try:
        start_date_obj = datetime.strptime(start_date, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return 'Error: Invalid start_date format. Expected YYYY-MM-DDTHH:MM:SS.'

    # Error handling for calendar system
    if calendar_system not in ['gregorian', 'julian', 'islamic', 'hebrew']:
        return 'Error: Unsupported calendar system.'

    # Error handling for output format
    if output_format not in ['YYYY-MM-DD', 'MM/DD/YYYY', 'DD-MM-YYYY', 'YYYY-MM-DDTHH:MM:SS']:
        return 'Error: Unsupported output format.'

    # Adjust for time zone
    try:
        tz = pytz.timezone(time_zone)
        start_date_obj = tz.localize(start_date_obj)
    except pytz.UnknownTimeZoneError:
        return 'Error: Unknown time zone.'

    # Calculate new date
    new_date_obj = start_date_obj + timedelta(days=days_to_add, hours=hours_to_add, minutes=minutes_to_add)

    # Format the output date
    if output_format == 'YYYY-MM-DD':
        return new_date_obj.strftime('%Y-%m-%d')
    elif output_format == 'MM/DD/YYYY':
        return new_date_obj.strftime('%m/%d/%Y')
    elif output_format == 'DD-MM-YYYY':
        return new_date_obj.strftime('%d-%m-%Y')
    elif output_format == 'YYYY-MM-DDTHH:MM:SS':
        return new_date_obj.strftime('%Y-%m-%dT%H:%M:%S')

    return 'Error: Unexpected error occurred.'

