def string_length_counter(input, ignore_spaces=False, ignore_special_characters=False, case_sensitive=True, count_vowels=False, count_consonants=False, count_digits=False, count_special_characters=False):
    # Validate input type
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Initialize counts
    letter_count = 0
    vowels = 'aeiouAEIOU' if case_sensitive else 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyzBCDFGHJKLMNPQRSTVWXYZ' if case_sensitive else 'bcdfghjklmnpqrstvwxyz'
    digit_count = 0
    special_character_count = 0
    vowel_count = 0
    consonant_count = 0

    # Iterate over each character in the input string
    for char in input:
        if char.isalpha():
            if not case_sensitive:
                char = char.lower()
            letter_count += 1
            if count_vowels and char in vowels:
                vowel_count += 1
            if count_consonants and char in consonants:
                consonant_count += 1
        elif char.isdigit() and count_digits:
            digit_count += 1
        elif not char.isalnum() and count_special_characters:
            special_character_count += 1

    # Adjust counts based on ignore parameters
    if ignore_spaces:
        letter_count -= input.count(' ')
    if ignore_special_characters:
        letter_count -= special_character_count

    # Prepare the result
    result = {'letter_count': letter_count}
    if count_vowels:
        result['vowel_count'] = vowel_count
    if count_consonants:
        result['consonant_count'] = consonant_count
    if count_digits:
        result['digit_count'] = digit_count
    if count_special_characters:
        result['special_character_count'] = special_character_count

    return result

