def prime_factorization(number, include_negative=False, output_format='list', factor_range={'min_factor': 2}, performance_mode='standard'):
    # Error handling for invalid inputs
    if not isinstance(number, int) or number == 0:
        return {'error': 'Invalid input: number must be a non-zero integer.'}
    if output_format not in ['list', 'string', 'detailed']:
        return {'error': 'Invalid output_format. Choose from list, string, detailed.'}
    if performance_mode not in ['standard', 'optimized']:
        return {'error': 'Invalid performance_mode. Choose from standard, optimized.'}

    # Initialize variables
    factors = []
    abs_number = abs(number)
    min_factor = factor_range.get('min_factor', 2)
    max_factor = factor_range.get('max_factor', int(abs_number**0.5))

    # Factorization logic
    for i in range(min_factor, max_factor + 1):
        while abs_number % i == 0:
            factors.append(i)
            abs_number //= i
    if abs_number > 1:  # If there's any prime factor greater than sqrt(number)
        factors.append(abs_number)

    # Include negative factors if required
    if include_negative and number < 0:
        factors = [-f for f in factors]

    # Format the output
    if output_format == 'list':
        return factors
    elif output_format == 'string':
        return ', '.join(map(str, factors))
    elif output_format == 'detailed':
        from collections import Counter
        factor_count = Counter(factors)
        return {factor: count for factor, count in factor_count.items()}

