# Expected output: [2, 983]

def sum_calculator(numbers, output_format='float', include_statistics=False):
    """
    Calculate the sum of a list of numbers with various output options.

    :param numbers: List of numbers (integers, floats, or complex numbers) to sum.
    :param output_format: The format of the output ('integer', 'float', 'text', 'complex', 'summary').
    :param include_statistics: Boolean indicating if statistical information should be included.
    :return: Sum of the numbers in the specified format, with optional statistics.
    """
    import statistics

    # Error handling for invalid input types
    if not isinstance(numbers, list) or not all(isinstance(n, (int, float, complex)) for n in numbers):
        return {'error': 'Invalid input: numbers must be a list of numeric types.'}

    if output_format not in ['integer', 'float', 'text', 'complex', 'summary']:
        return {'error': 'Invalid output_format: must be one of integer, float, text, complex, summary.'}

    # Calculate the sum
    total_sum = sum(numbers)

    # Handle different output formats
    if output_format == 'integer':
        total_sum = int(total_sum)
    elif output_format == 'float':
        total_sum = float(total_sum)
    elif output_format == 'text':
        total_sum = str(total_sum)
    elif output_format == 'complex':
        total_sum = complex(total_sum)
    elif output_format == 'summary':
        summary = {
            'sum': total_sum,
            'mean': statistics.mean(numbers) if numbers else 0,
            'median': statistics.median(numbers) if numbers else 0,
            'stdev': statistics.stdev(numbers) if len(numbers) > 1 else 0
        }
        return summary

    # Include statistics if requested
    if include_statistics:
        stats = {
            'mean': statistics.mean(numbers) if numbers else 0,
            'median': statistics.median(numbers) if numbers else 0,
            'stdev': statistics.stdev(numbers) if len(numbers) > 1 else 0
        }
        return {'sum': total_sum, 'statistics': stats}

    return {'sum': total_sum}

