def digit_extractor(number, position=None, range=None, output_format='integer', handle_negatives=False, zero_padding=False):
    # Convert number to string for easy indexing
    num_str = str(number)
    # Handle negative numbers if handle_negatives is False
    if not handle_negatives and num_str[0] == '-':
        num_str = num_str[1:]
    # Determine the length of the number
    num_length = len(num_str)
    # Handle zero padding
    if zero_padding and position and abs(position) > num_length:
        num_str = num_str.zfill(abs(position))
    # Extract digits based on position or range
    if range:
        # Extract digits for the specified range
        start, end = range
        extracted_digits = num_str[start-1:end]
    elif position:
        # Adjust for negative indexing
        if position < 0:
            position = num_length + position + 1
        # Extract the single digit
        extracted_digits = num_str[position-1]
    else:
        raise ValueError('Either position or range must be specified.')
    # Format the output
    if output_format == 'integer':
        return int(extracted_digits)
    elif output_format == 'string':
        return extracted_digits
    elif output_format == 'array':
        return list(extracted_digits)
    else:
        raise ValueError('Invalid output format specified.')

