def digit_extractor(number, position, handle_out_of_bounds='error', counting_direction='left_to_right', numeral_system='decimal'):
    # Convert the number to the specified numeral system
    if numeral_system == 'binary':
        num_str = bin(int(number))[2:]  # Convert to binary and remove '0b'
    elif numeral_system == 'hexadecimal':
        num_str = hex(int(number))[2:]  # Convert to hexadecimal and remove '0x'
    else:
        num_str = str(number).replace('.', '')  # Default is decimal, remove decimal point

    # Handle negative numbers
    if number < 0:
        num_str = num_str[1:]  # Remove the negative sign

    # Determine the length of the number string
    num_length = len(num_str)

    # Adjust position based on counting direction
    if counting_direction == 'right_to_left':
        position = num_length - position + 1

    # Check if the position is out of bounds
    if position < 1 or position > num_length:
        if handle_out_of_bounds == 'error':
            raise ValueError('Position out of bounds')
        elif handle_out_of_bounds == 'null':
            return None
        elif handle_out_of_bounds == 'wrap':
            position = (position - 1) % num_length + 1
        elif handle_out_of_bounds == 'truncate':
            position = max(1, min(position, num_length))

    # Extract and return the digit at the specified position
    return int(num_str[position - 1])

