def date_calculator(start_date, months_to_add=0, days_to_add=0, hours_to_add=0, calendar_system='Gregorian', output_format='YYYY-MM-DD'):
    from datetime import datetime, timedelta
    import calendar

    # Error handling for invalid start_date format
    try:
        date_format = '%Y-%m-%d'
        start_date_obj = datetime.strptime(start_date, date_format)
    except ValueError:
        return {'error': 'Invalid start_date format. Expected YYYY-MM-DD.'}

    # Adjust for calendar system
    if calendar_system not in ['Gregorian', 'Julian', 'ISO8601']:
        return {'error': 'Invalid calendar system. Choose from Gregorian, Julian, ISO8601.'}

    # Calculate new date
    year, month = start_date_obj.year, start_date_obj.month
    day = start_date_obj.day

    # Adjust month and year
    month += months_to_add
    while month > 12:
        month -= 12
        year += 1
    while month < 1:
        month += 12
        year -= 1

    # Adjust for leap years and month lengths
    if calendar_system == 'Julian':
        is_leap = (year % 4 == 0)
    else:  # Gregorian and ISO8601
        is_leap = (year % 4 == 0 and (year % 100 != 0 or year % 400 == 0))

    days_in_month = [31, 29 if is_leap else 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    day = min(day, days_in_month[month - 1])

    # Create new date object
    new_date_obj = datetime(year, month, day) + timedelta(days=days_to_add, hours=hours_to_add)

    # Format output
    if output_format == 'YYYY-MM-DD':
        return new_date_obj.strftime('%Y-%m-%d')
    elif output_format == 'DD-MM-YYYY':
        return new_date_obj.strftime('%d-%m-%Y')
    elif output_format == 'MM-DD-YYYY':
        return new_date_obj.strftime('%m-%d-%Y')
    elif output_format == 'YYYY-MM-DD HH:MM':
        return new_date_obj.strftime('%Y-%m-%d %H:%M')
    elif output_format == 'DD-MM-YYYY HH:MM':
        return new_date_obj.strftime('%d-%m-%Y %H:%M')
    elif output_format == 'MM-DD-YYYY HH:MM':
        return new_date_obj.strftime('%m-%d-%Y %H:%M')
    else:
        return {'error': 'Invalid output format.'}

