def date_calculator(input_date: str, increment: dict, calendar_system: str = 'gregorian', output_format: str = 'date') -> str:
    from datetime import datetime, timedelta
    from dateutil.relativedelta import relativedelta

    # Validate input_date format
    try:
        start_date = datetime.strptime(input_date, '%Y-%m-%d')
    except ValueError:
        return 'Error: Invalid input_date format. Expected YYYY-MM-DD.'

    # Validate calendar_system
    if calendar_system not in ['gregorian', 'julian', 'islamic', 'hebrew']:
        return 'Error: Unsupported calendar system.'

    # Extract increments
    years = increment.get('years', 0)
    months = increment.get('months', 0)
    weeks = increment.get('weeks', 0)
    days = increment.get('days', 0)

    # Calculate new date
    try:
        new_date = start_date + relativedelta(years=years, months=months) + timedelta(weeks=weeks, days=days)
    except Exception as e:
        return f'Error: {str(e)}'

    # Format output
    if output_format == 'date':
        return new_date.strftime('%Y-%m-%d')
    elif output_format == 'text':
        return new_date.strftime('%A, %B %d, %Y')
    elif output_format == 'timestamp':
        return str(int(new_date.timestamp()))
    else:
        return 'Error: Unsupported output format.'

