def extract_last_name(full_name: str, name_format: str = 'first_last', ignore_special_characters: bool = False, include_suffix: bool = False, case_sensitive: bool = True) -> str:
    # Error handling for required parameter
    if not full_name:
        raise ValueError("The 'full_name' parameter is required.")

    # Split the full name based on spaces
    name_parts = full_name.split()

    # Handle different name formats
    if name_format == 'first_last':
        last_name = name_parts[-1]
    elif name_format == 'first_middle_last':
        last_name = name_parts[-1]
    elif name_format == 'first_initial_last':
        last_name = name_parts[-1]
    elif name_format == 'last_first':
        last_name = name_parts[0]
    elif name_format == 'last_first_middle':
        last_name = name_parts[0]
    elif name_format == 'first_last_suffix':
        last_name = name_parts[-2] if include_suffix else name_parts[-1]
    else:
        raise ValueError("Unsupported 'name_format' provided.")

    # Handle special characters
    if ignore_special_characters:
        last_name = ''.join(e for e in last_name if e.isalnum())

    # Handle case sensitivity
    if not case_sensitive:
        last_name = last_name.lower()

    return last_name

