print(result)  # Expected output: 7

def extract_first_name(full_name, delimiter=' ', output_format='string', include_prefix=False, include_suffix=False, cultural_format='western'):
    """
    Extracts the first name from a full name string based on specified parameters.

    Parameters:
    - full_name (str): The full name from which the first name will be extracted.
    - delimiter (str): The character used to separate names, default is a space.
    - output_format (str): The format of the output, can be 'string', 'json', or 'xml'.
    - include_prefix (bool): Whether to include name prefixes in the extraction.
    - include_suffix (bool): Whether to include name suffixes in the extraction.
    - cultural_format (str): The cultural format of the name, can be 'western', 'eastern', or 'custom'.

    Returns:
    - The extracted first name in the specified format.
    """
    # Error handling for incorrect input types
    if not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a string.'}
    if output_format not in ['string', 'json', 'xml']:
        return {'error': 'Invalid output format. Supported formats are string, json, xml.'}

    # Split the full name based on the delimiter
    name_parts = full_name.split(delimiter)

    # Determine the first name based on cultural format
    if cultural_format == 'western':
        first_name = name_parts[0]
    elif cultural_format == 'eastern':
        first_name = name_parts[-1]
    else:  # custom or other formats
        first_name = name_parts[0]  # Default to first part

    # Include prefix if specified
    if include_prefix and len(name_parts) > 1:
        first_name = name_parts[0] + ' ' + first_name

    # Include suffix if specified
    if include_suffix and len(name_parts) > 2:
        first_name += ' ' + name_parts[-1]

    # Format the output
    if output_format == 'json':
        return {'first_name': first_name}
    elif output_format == 'xml':
        return f'<firstName>{first_name}</firstName>'
    else:
        return first_name

