def find_longest_word(input_string, ignore_punctuation=True, case_sensitive=False, custom_delimiters=[' '], ignore_words=[], include_numbers=False, min_word_length=1, return_positions=False, handle_ties=True):
    import re

    # Error handling for required parameter
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string'}

    # Prepare the delimiters for splitting the string
    delimiters = '|'.join(map(re.escape, custom_delimiters))

    # Split the string into words
    words = re.split(delimiters, input_string)

    # Filter words based on ignore_words, min_word_length, and include_numbers
    filtered_words = []
    for word in words:
        if not include_numbers and word.isdigit():
            continue
        if len(word) < min_word_length:
            continue
        if word in ignore_words:
            continue
        filtered_words.append(word)

    # Handle case sensitivity
    if not case_sensitive:
        filtered_words = [word.lower() for word in filtered_words]

    # Handle punctuation
    if ignore_punctuation:
        filtered_words = [re.sub(r'\W+', '', word) for word in filtered_words]

    # Find the longest word(s)
    max_length = 0
    longest_words = []
    positions = []
    for i, word in enumerate(filtered_words):
        if len(word) > max_length:
            max_length = len(word)
            longest_words = [word]
            positions = [i]
        elif len(word) == max_length and handle_ties:
            longest_words.append(word)
            positions.append(i)

    # Prepare the result
    result = {'longest_words': longest_words}
    if return_positions:
        result['positions'] = positions

    return result

