def date_calculator(start_date, duration, output_format='YYYY-MM-DD', time_zone='UTC', business_days_only=False, sequence_operations=None):
    from datetime import datetime, timedelta
    import pytz

    # Parse the start date
    try:
        start_date = datetime.strptime(start_date, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return {'error': 'Invalid start_date format. Expected format: YYYY-MM-DDTHH:MM:SS'}

    # Adjust for time zone
    try:
        tz = pytz.timezone(time_zone)
        start_date = tz.localize(start_date)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Unknown time zone specified.'}

    # Initialize the result date
    result_date = start_date

    # Process sequence operations
    if sequence_operations:
        for operation in sequence_operations:
            op_type = operation.get('operation')
            op_duration = operation.get('duration', {})
            days = op_duration.get('days', 0)
            weeks = op_duration.get('weeks', 0)
            months = op_duration.get('months', 0)
            years = op_duration.get('years', 0)
            hours = op_duration.get('hours', 0)
            minutes = op_duration.get('minutes', 0)

            # Calculate total days to add/subtract
            total_days = days + weeks * 7
            total_seconds = hours * 3600 + minutes * 60

            if op_type == 'add':
                result_date += timedelta(days=total_days, seconds=total_seconds)
            elif op_type == 'subtract':
                result_date -= timedelta(days=total_days, seconds=total_seconds)
            else:
                return {'error': 'Invalid operation type. Supported types: add, subtract.'}

    # Format the result date
    if output_format == 'YYYY-MM-DD':
        formatted_date = result_date.strftime('%Y-%m-%d')
    elif output_format == 'MM-DD-YYYY':
        formatted_date = result_date.strftime('%m-%d-%Y')
    elif output_format == 'DD-MM-YYYY':
        formatted_date = result_date.strftime('%d-%m-%Y')
    elif output_format == 'YYYY-MM-DD HH:MM':
        formatted_date = result_date.strftime('%Y-%m-%d %H:%M')
    elif output_format == 'MM-DD-YYYY HH:MM':
        formatted_date = result_date.strftime('%m-%d-%Y %H:%M')
    elif output_format == 'DD-MM-YYYY HH:MM':
        formatted_date = result_date.strftime('%d-%m-%Y %H:%M')
    else:
        return {'error': 'Invalid output format specified.'}

    return {'result': formatted_date}

