def date_to_day_converter(date, calendar_system='gregorian', output_format='full', timezone='UTC', locale='en-US'):
    import datetime
    import calendar
    import pytz
    import locale as loc

    # Error handling for date format
    try:
        # Attempt to parse the date in different formats
        if '-' in date:
            date_obj = datetime.datetime.strptime(date, '%Y-%m-%d')
        elif '/' in date:
            date_obj = datetime.datetime.strptime(date, '%m/%d/%Y')
        else:
            date_obj = datetime.datetime.strptime(date, '%d-%m-%Y')
    except ValueError:
        return {'error': 'Invalid date format. Please use YYYY-MM-DD, DD-MM-YYYY, or MM/DD/YYYY.'}

    # Error handling for calendar system
    if calendar_system not in ['gregorian', 'julian', 'hebrew', 'islamic']:
        return {'error': 'Unsupported calendar system. Choose from gregorian, julian, hebrew, or islamic.'}

    # Error handling for timezone
    try:
        tz = pytz.timezone(timezone)
        date_obj = tz.localize(date_obj)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid timezone. Please use a valid IANA timezone format.'}

    # Set locale for day name
    try:
        loc.setlocale(loc.LC_TIME, locale)
    except loc.Error:
        return {'error': 'Invalid locale. Please use a valid locale format like en-US or fr-FR.'}

    # Convert date to day of the week
    day_index = date_obj.weekday()  # Monday is 0 and Sunday is 6

    # Determine output format
    if output_format == 'full':
        day_name = date_obj.strftime('%A')
    elif output_format == 'abbreviated':
        day_name = date_obj.strftime('%a')
    elif output_format == 'numeric':
        day_name = str(day_index + 1)
    else:
        return {'error': 'Invalid output format. Choose from full, abbreviated, or numeric.'}

    return {'day': day_name}

# Example usage
