    if handle_non_ascii not in ['error', 'ignore', 'message', 'replace']:
        raise ValueError("'handle_non_ascii' must be one of 'error', 'ignore', 'message', 'replace'.")
    if not isinstance(replacement_character, str) or len(replacement_character) != 1:
        raise ValueError("'replacement_character' must be a single character string.")
    if output_format not in ['list', 'string', 'json']:
        raise ValueError("'output_format' must be one of 'list', 'string', 'json'.")

    ascii_codes = {}
    non_ascii_detected = False

    for char in characters:
        if ord(char) < 128:  # ASCII range
            ascii_codes[char] = ord(char)
        else:
            non_ascii_detected = True
            if handle_non_ascii == 'error':
                raise ValueError(f"Non-ASCII character detected: {char}")
            elif handle_non_ascii == 'ignore':
                continue
            elif handle_non_ascii == 'message':
                ascii_codes[char] = 'Non-ASCII character'
            elif handle_non_ascii == 'replace':
                ascii_codes[char] = ord(replacement_character)

    # Format output
    if output_format == 'list':
        return [ascii_codes[char] for char in characters if char in ascii_codes]
    elif output_format == 'string':
        return ''.join(str(ascii_codes[char]) for char in characters if char in ascii_codes)
    elif output_format == 'json':
        return ascii_codes

