def extract_first_letter(input: str, ignore_whitespace: bool = True, case_sensitive: bool = True, extract_mode: str = 'single', encoding: str = 'UTF-8', output_format: str = 'string'):
    """
    Extracts the first letter from a given string or each word in a string.

    Parameters:
    - input (str): The string from which the first letter is to be extracted.
    - ignore_whitespace (bool): Whether to ignore leading whitespace. Defaults to True.
    - case_sensitive (bool): Whether to preserve the case of the first letter. Defaults to True.
    - extract_mode (str): 'single' for the first letter of the entire string or 'each_word' for each word. Defaults to 'single'.
    - encoding (str): The character encoding of the input string. Defaults to 'UTF-8'.
    - output_format (str): 'string' for a single concatenated string or 'list' for a list of letters. Defaults to 'string'.

    Returns:
    - str or list: The extracted first letter(s) based on the specified parameters.
    """
    # Error handling for empty input
    if not input:
        return {'error': 'Input string cannot be empty.'}

    # Handle encoding (simulated as Python natively handles UTF-8)
    try:
        input = input.encode(encoding).decode(encoding)
    except (UnicodeEncodeError, UnicodeDecodeError):
        return {'error': f'Encoding {encoding} is not supported.'}

    # Trim leading whitespace if ignore_whitespace is True
    if ignore_whitespace:
        input = input.lstrip()

    # Extract first letter(s) based on extract_mode
    if extract_mode == 'single':
        first_letter = input[0] if case_sensitive else input[0].lower()
        result = first_letter
    elif extract_mode == 'each_word':
        words = input.split()
        first_letters = [word[0] if case_sensitive else word[0].lower() for word in words]
        result = first_letters
    else:
        return {'error': 'Invalid extract_mode specified.'}

    # Format output based on output_format
    if output_format == 'string':
        if isinstance(result, list):
            result = ''.join(result)
    elif output_format == 'list':
        if isinstance(result, str):
            result = [result]
    else:
        return {'error': 'Invalid output_format specified.'}

    return result

