def char_to_binary(input: str, encoding: str = 'ASCII', separator: str = ' ', output_format: str = 'binary_string', padding: bool = True, case_sensitive: bool = True):
    # Validate encoding
    if encoding not in ['ASCII', 'UTF-8', 'UTF-16', 'UTF-32']:
        raise ValueError('Unsupported encoding type.')

    # Validate output_format
    if output_format not in ['binary_string', 'list', 'hexadecimal', 'base64']:
        raise ValueError('Unsupported output format.')

    # Handle case sensitivity
    if not case_sensitive:
        input = input.lower()

    # Convert input to binary
    binary_codes = []
    for char in input:
        if encoding == 'ASCII':
            binary_code = format(ord(char), '08b') if padding else format(ord(char), 'b')
        elif encoding == 'UTF-8':
            binary_code = ''.join(format(byte, '08b') for byte in char.encode('utf-8'))
        elif encoding == 'UTF-16':
            binary_code = ''.join(format(byte, '08b') for byte in char.encode('utf-16')[2:])  # Skip BOM
        elif encoding == 'UTF-32':
            binary_code = ''.join(format(byte, '08b') for byte in char.encode('utf-32')[4:])  # Skip BOM
        binary_codes.append(binary_code)

    # Format output
    if output_format == 'binary_string':
        return separator.join(binary_codes)
    elif output_format == 'list':
        return binary_codes
    elif output_format == 'hexadecimal':
        hex_string = ''.join(format(int(b, 2), 'x') for b in binary_codes)
        return hex_string
    elif output_format == 'base64':
        import base64
        byte_array = bytearray(int(b, 2) for b in binary_codes)
        base64_string = base64.b64encode(byte_array).decode('utf-8')
        return base64_string

