def extract_first_letter(input, ignore_non_alphabetic=True, output_format='character', ignore_characters=[]):
    # Helper function to extract the first valid letter from a string
    def get_first_letter(s):
        for char in s:
            if char in ignore_characters:
                continue
            if ignore_non_alphabetic and not char.isalpha():
                continue
            return char
        return ''

    # Process the input based on its type
    if not isinstance(input, list) or len(input) == 0:
        raise ValueError('Input must be a non-empty list.')

    result = []

    for item in input:
        if isinstance(item, str):
            first_letter = get_first_letter(item)
            if first_letter:
                result.append(first_letter)
        elif isinstance(item, list):
            for sub_item in item:
                if isinstance(sub_item, str):
                    first_letter = get_first_letter(sub_item)
                    if first_letter:
                        result.append(first_letter)
                else:
                    raise ValueError('Nested items must be strings.')
        else:
            raise ValueError('Items in the input list must be strings or lists of strings.')

    # Format the output based on the specified output_format
    if output_format == 'character':
        return result[0] if result else ''
    elif output_format == 'text':
        return ''.join(result)
    elif output_format == 'json':
        return {'first_letters': result}
    else:
        raise ValueError('Invalid output format specified.')

