def char_to_binary(characters, output_format='binary_string', delimiter='', encoding_scheme='ASCII'):
    """
    Convert characters to their binary code representation.

    :param characters: List of single-character strings to convert.
    :param output_format: The format of the output ('binary_string', 'binary_list', 'binary_dict').
    :param delimiter: Delimiter for binary_string format.
    :param encoding_scheme: Encoding scheme ('ASCII', 'UTF-8').
    :return: Binary representation of characters in specified format.
    """
    # Validate input parameters
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        raise ValueError("'characters' must be a list of single-character strings.")
    if output_format not in ['binary_string', 'binary_list', 'binary_dict']:
        raise ValueError("Invalid output_format. Choose from 'binary_string', 'binary_list', 'binary_dict'.")
    if encoding_scheme not in ['ASCII', 'UTF-8']:
        raise ValueError("Invalid encoding_scheme. Choose 'ASCII' or 'UTF-8'.")

    # Convert characters to binary
    binary_codes = []
    for char in characters:
        if encoding_scheme == 'ASCII':
            binary_code = format(ord(char), '08b')
        elif encoding_scheme == 'UTF-8':
            binary_code = ''.join(format(byte, '08b') for byte in char.encode('utf-8'))
        binary_codes.append(binary_code)

    # Format output
    if output_format == 'binary_string':
        return delimiter.join(binary_codes)
    elif output_format == 'binary_list':
        return binary_codes
    elif output_format == 'binary_dict':
        return {char: code for char, code in zip(characters, binary_codes)}

