def enhanced_timezone_difference_calculator(timezones, specific_datetime=None, include_current_time=False, output_format='text'):
    import pytz
    from datetime import datetime

    # Validate timezones
    if len(timezones) < 2:
        return {'error': 'At least two time zones must be provided.'}

    try:
        # Parse specific_datetime or use current time
        if specific_datetime:
            dt = datetime.fromisoformat(specific_datetime)
        else:
            dt = datetime.now()

        # Calculate time differences
        tz_objects = [pytz.timezone(tz) for tz in timezones]
        times = [dt.astimezone(tz) for tz in tz_objects]
        differences = [(times[i] - times[0]).total_seconds() / 3600 for i in range(1, len(times))]

        # Prepare output
        if output_format == 'json':
            result = {
                'differences': differences,
                'current_times': [time.isoformat() for time in times] if include_current_time else None
            }
        else:
            result = f"Time differences in hours: {differences}"
            if include_current_time:
                result += f"\nCurrent times: {[time.isoformat() for time in times]}"

        return result

    except Exception as e:
        return {'error': str(e)}

