def prime_factorizer(number, include_negative=False, output_format='list', performance_mode='standard', max_factor_limit=None):
    """
    Computes the prime factors of a given integer.

    Parameters:
    - number (int): The integer to be factorized into prime factors.
    - include_negative (bool): Whether to include negative factors for negative numbers. Defaults to False.
    - output_format (str): The format of the output. Defaults to 'list'.
    - performance_mode (str): The mode of performance. Defaults to 'standard'.
    - max_factor_limit (int): The maximum number of prime factors to compute. Defaults to no limit.

    Returns:
    - A list, string, or detailed dictionary of prime factors based on the output_format.
    """
    import math

    if not isinstance(number, int):
        return {'error': 'Invalid input: number must be an integer.'}
    if output_format not in ['list', 'text', 'detailed']:
        return {'error': 'Invalid input: output_format must be one of [list, text, detailed].'}
    if performance_mode not in ['standard', 'high_performance']:
        return {'error': 'Invalid input: performance_mode must be one of [standard, high_performance].'}

    def factorize(n):
        factors = []
        if n < 0:
            if include_negative:
                factors.append(-1)
            n = abs(n)
        while n % 2 == 0:
            factors.append(2)
            n = n // 2
        for i in range(3, int(math.sqrt(n)) + 1, 2):
            while n % i == 0:
                factors.append(i)
                n = n // i
        if n > 2:
            factors.append(n)
        return factors

    factors = factorize(number)

    if max_factor_limit is not None:
        factors = factors[:max_factor_limit]

    if output_format == 'list':
        return factors
    elif output_format == 'text':
        return ', '.join(map(str, factors))
    elif output_format == 'detailed':
        from collections import Counter
        factor_count = Counter(factors)
        return {factor: count for factor, count in factor_count.items()}

