def enhanced_timezone_difference_calculator(from_timezone: str, to_timezone: str, dates: list = None, time: str = None, output_format: str = 'hours') -> str:
    import pytz
    from datetime import datetime

    # Default to current date and time if not provided
    if dates is None:
        dates = [datetime.now().strftime('%Y-%m-%d')]
    if time is None:
        time = datetime.now().strftime('%H:%M')

    # Validate output_format
    if output_format not in ['hours', 'detailed', 'json', 'text']:
        return 'Error: Invalid output format specified.'

    try:
        # Initialize time zones
        from_tz = pytz.timezone(from_timezone)
        to_tz = pytz.timezone(to_timezone)

        # Calculate time differences
        differences = []
        for date in dates:
            # Parse date and time
            dt = datetime.strptime(f'{date} {time}', '%Y-%m-%d %H:%M')
            from_dt = from_tz.localize(dt)
            to_dt = from_dt.astimezone(to_tz)

            # Calculate difference in hours
            difference = (to_dt - from_dt).total_seconds() / 3600
            differences.append(difference)

        # Format output
        if output_format == 'hours':
            return str(differences[0])
        elif output_format == 'detailed':
            return f'Time difference from {from_timezone} to {to_timezone} on {dates[0]} at {time} is {differences[0]} hours.'
        elif output_format == 'json':
            return str({"from_timezone": from_timezone, "to_timezone": to_timezone, "dates": dates, "time": time, "differences": differences})
        elif output_format == 'text':
            return f'Time difference: {differences[0]} hours.'
    except Exception as e:
        return f'Error: {str(e)}'

