def character_extractor(input, position='last', custom_index=None, condition=None, case_sensitive=False, output_format='character'):
    # Validate required parameters
    if not input or not isinstance(input, list) or len(input) < 1:
        return {'error': 'Invalid input: must be a non-empty list of strings.'}
    if position not in ['first', 'last', 'custom', 'conditional']:
        return {'error': 'Invalid position: must be one of first, last, custom, conditional.'}

    # Extract characters based on position
    extracted_characters = []
    for string in input:
        if position == 'last':
            extracted_characters.append(string[-1])
        elif position == 'first':
            extracted_characters.append(string[0])
        elif position == 'custom':
            if not custom_index or not isinstance(custom_index, list) or len(custom_index) < 1:
                return {'error': 'Invalid custom_index: must be a non-empty list of integers.'}
            for index in custom_index:
                if 0 <= index < len(string):
                    extracted_characters.append(string[index])
                else:
                    return {'error': f'Index {index} out of range for string {string}.'}
        elif position == 'conditional':
            if not condition or condition not in ['vowel', 'consonant', 'uppercase', 'lowercase']:
                return {'error': 'Invalid condition: must be one of vowel, consonant, uppercase, lowercase.'}
            for char in string:
                if condition == 'vowel' and char.lower() in 'aeiou':
                    extracted_characters.append(char)
                elif condition == 'consonant' and char.lower() not in 'aeiou':
                    extracted_characters.append(char)
                elif condition == 'uppercase' and char.isupper():
                    extracted_characters.append(char)
                elif condition == 'lowercase' and char.islower():
                    extracted_characters.append(char)

    # Format the output
    if output_format == 'character':
        return extracted_characters[0] if extracted_characters else ''
    elif output_format == 'array':
        return extracted_characters
    elif output_format == 'object':
        return {i: char for i, char in enumerate(extracted_characters)}
    else:
        return {'error': 'Invalid output_format: must be one of character, array, object.'}

