def enhanced_timezone_difference_calculator(timezones, dates=['current_date'], output_format='hours', include_exact_times=False):
    import pytz
    from datetime import datetime

    # Validate timezones
    if len(timezones) < 2:
        return {'error': 'At least two time zones must be provided.'}

    # Validate output_format
    if output_format not in ['hours', 'minutes', 'detailed']:
        return {'error': 'Invalid output format. Choose from hours, minutes, or detailed.'}

    # Validate dates
    if not dates:
        dates = [datetime.now().strftime('%Y-%m-%d')]

    # Initialize result
    result = {}

    try:
        # Calculate time difference for each date
        for date in dates:
            date_obj = datetime.strptime(date, '%Y-%m-%d')
            times = []
            for tz in timezones:
                timezone = pytz.timezone(tz)
                local_time = timezone.localize(date_obj)
                times.append(local_time)

            # Calculate differences
            diff = (times[1] - times[0]).total_seconds() / 3600
            if output_format == 'minutes':
                diff *= 60

            # Prepare output
            if output_format == 'detailed' or include_exact_times:
                result[date] = {
                    'difference': diff,
                    'exact_times': {tz: time.strftime('%Y-%m-%d %H:%M:%S') for tz, time in zip(timezones, times)}
                }
            else:
                result[date] = {'difference': diff}

        return result
    except Exception as e:
        return {'error': str(e)}

