def enhanced_year_calculator(current_year, calendar_system='Gregorian', include_leap_year_check=False, calculate_first_day_of_next_year=False):
    """
    Calculate the year following the given year with optional leap year check and day of the week calculation.

    :param current_year: The current year for which the next year is to be calculated.
    :param calendar_system: The calendar system of the year. Defaults to Gregorian.
    :param include_leap_year_check: Indicates whether to check if the next year is a leap year.
    :param calculate_first_day_of_next_year: Determines if the tool should calculate the day of the week for the first day of the next year.
    :return: A dictionary with the next year, leap year status, and first day of the week if requested.
    """
    # Error handling for invalid inputs
    if not isinstance(current_year, int):
        return {'error': 'Invalid input: current_year must be an integer.'}
    if calendar_system not in ['AD', 'BC', 'Gregorian', 'Julian']:
        return {'error': 'Invalid input: calendar_system must be one of AD, BC, Gregorian, Julian.'}

    # Calculate the next year
    next_year = current_year + 1

    # Initialize the result dictionary
    result = {'next_year': next_year}

    # Check if the next year is a leap year if requested
    if include_leap_year_check:
        if calendar_system in ['Gregorian', 'AD']:
            is_leap_year = (next_year % 4 == 0 and (next_year % 100 != 0 or next_year % 400 == 0))
        elif calendar_system == 'Julian':
            is_leap_year = (next_year % 4 == 0)
        else:
            is_leap_year = False  # Simplified assumption for BC
        result['is_leap_year'] = is_leap_year

    # Calculate the first day of the next year if requested
    if calculate_first_day_of_next_year:
        import datetime
        try:
            first_day = datetime.date(next_year, 1, 1).strftime('%A')
            result['first_day_of_next_year'] = first_day
        except ValueError as e:
            result['error'] = str(e)

    return result

