def enhanced_unique_letter_counter(input: str, case_sensitive: bool = False, exclude_characters: list = [], count_vowels: bool = False, count_consonants: bool = False, include_non_letters: bool = False, detailed_output: bool = False):
    # Validate input
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not isinstance(case_sensitive, bool) or not isinstance(count_vowels, bool) or not isinstance(count_consonants, bool) or not isinstance(include_non_letters, bool) or not isinstance(detailed_output, bool):
        return {'error': 'Boolean parameters must be of type bool.'}
    if not isinstance(exclude_characters, list) or not all(isinstance(char, str) for char in exclude_characters):
        return {'error': 'Exclude characters must be a list of strings.'}

    # Normalize input based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        exclude_characters = [char.lower() for char in exclude_characters]

    # Define vowels and consonants
    vowels = set('aeiou')
    consonants = set('bcdfghjklmnpqrstvwxyz')

    # Initialize a set to track unique characters
    unique_chars = set()

    # Iterate over each character in the input
    for char in input:
        # Check for exclusions
        if char in exclude_characters:
            continue
        # Check for non-letter inclusion
        if not char.isalpha() and not include_non_letters:
            continue
        # Check for vowel or consonant counting
        if count_vowels and char not in vowels:
            continue
        if count_consonants and char not in consonants:
            continue
        # Add character to the set of unique characters
        unique_chars.add(char)

    # Prepare detailed output if required
    if detailed_output:
        frequency = {char: input.count(char) for char in unique_chars}
        return {'unique_count': len(unique_chars), 'details': frequency}

    # Return the count of unique characters
    return {'unique_count': len(unique_chars)}

