def date_difference_calculator(start_date_time, end_date_time, calendar_system='gregorian', output_format='integer', time_zone='UTC', exclude_weekends=False, exclude_holidays=[]):
    from datetime import datetime, timedelta
    import pytz

    # Error handling for date format
    try:
        start_dt = datetime.strptime(start_date_time, '%Y-%m-%dT%H:%M:%S')
        end_dt = datetime.strptime(end_date_time, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return 'Invalid date format. Please use YYYY-MM-DDTHH:MM:SS.'

    # Error handling for calendar system
    if calendar_system not in ['gregorian', 'julian', 'islamic', 'hebrew']:
        return 'Unsupported calendar system. Please choose from gregorian, julian, islamic, hebrew.'

    # Convert to specified time zone
    try:
        tz = pytz.timezone(time_zone)
        start_dt = tz.localize(start_dt)
        end_dt = tz.localize(end_dt)
    except pytz.UnknownTimeZoneError:
        return 'Unknown time zone. Please provide a valid time zone.'

    # Calculate the difference
    delta = end_dt - start_dt
    total_days = delta.days
    total_seconds = delta.seconds
    total_hours = total_seconds // 3600
    total_minutes = (total_seconds % 3600) // 60

    # Exclude weekends if specified
    if exclude_weekends:
        current_date = start_dt
        while current_date < end_dt:
            if current_date.weekday() >= 5:  # Saturday or Sunday
                total_days -= 1
            current_date += timedelta(days=1)

    # Exclude holidays if specified
    for holiday in exclude_holidays:
        try:
            holiday_date = datetime.strptime(holiday, '%Y-%m-%d').date()
            if start_dt.date() <= holiday_date <= end_dt.date():
                total_days -= 1
        except ValueError:
            return 'Invalid holiday date format. Please use YYYY-MM-DD.'

    # Return the result in the specified format
    if output_format == 'integer':
        return total_days
    elif output_format == 'text':
        return f'{total_days} days'
    elif output_format == 'detailed':
        return f'{total_days} days, {total_hours} hours, {total_minutes} minutes'
    else:
        return 'Invalid output format. Please choose from integer, text, detailed.'

