def count_repeated_letters(input, case_sensitive=False, output_format='integer', ignore_characters='', alphabetic_only=False):
    # Validate input type
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if output_format not in ['integer', 'detailed', 'detailed_with_positions']:
        return {'error': 'Invalid output format.'}

    # Prepare the input string based on parameters
    if not case_sensitive:
        input = input.lower()
        ignore_characters = ignore_characters.lower()

    # Filter out ignored characters
    filtered_input = ''.join([ch for ch in input if ch not in ignore_characters])

    # Consider only alphabetic characters if required
    if alphabetic_only:
        filtered_input = ''.join([ch for ch in filtered_input if ch.isalpha()])

    # Count repeated letters
    from collections import Counter
    letter_counts = Counter(filtered_input)
    repeated_letters = {ch: count for ch, count in letter_counts.items() if count > 1}

    # Prepare output based on the format
    if output_format == 'integer':
        return len(repeated_letters)
    elif output_format == 'detailed':
        return repeated_letters
    elif output_format == 'detailed_with_positions':
        detailed_positions = {}
        for ch in repeated_letters:
            positions = [i for i, letter in enumerate(filtered_input) if letter == ch]
            detailed_positions[ch] = {'count': repeated_letters[ch], 'positions': positions}
        return detailed_positions

