def string_length_counter(input: str, ignore_spaces: bool = False, ignore_special_characters: bool = False, case_sensitive: bool = False, count_vowels: bool = False, count_consonants: bool = False, output_format: str = 'integer') -> str:
    # Error handling for conflicting options
    if count_vowels and count_consonants:
        return 'Error: Cannot count both vowels and consonants simultaneously.'

    # Define vowels and consonants
    vowels = 'aeiouAEIOU' if case_sensitive else 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyzBCDFGHJKLMNPQRSTVWXYZ' if case_sensitive else 'bcdfghjklmnpqrstvwxyz'

    # Initialize count
    count = 0

    # Iterate over each character in the input string
    for char in input:
        # Ignore spaces if specified
        if ignore_spaces and char.isspace():
            continue
        # Ignore special characters if specified
        if ignore_special_characters and not char.isalnum():
            continue
        # Handle case sensitivity
        if not case_sensitive:
            char = char.lower()
        # Count vowels or consonants if specified
        if count_vowels and char in vowels:
            count += 1
        elif count_consonants and char in consonants:
            count += 1
        elif not count_vowels and not count_consonants and char.isalpha():
            count += 1

    # Format output based on specified format
    if output_format == 'integer':
        return str(count)
    elif output_format == 'text':
        return f'The count is {count}.'
    elif output_format == 'detailed':
        return f'Total count: {count}, Vowels: {sum(1 for c in input if c in vowels)}, Consonants: {sum(1 for c in input if c in consonants)}.'
    else:
        return 'Error: Invalid output format specified.'

