def find_closest_palindrome(number, direction='both', return_distance=False, max_search_limit=1000, detailed_output=False):
    # Helper function to check if a number is a palindrome
    def is_palindrome(num):
        return str(num) == str(num)[::-1]

    # Validate input types
    if not isinstance(number, int):
        raise ValueError("'number' must be an integer.")
    if direction not in ['both', 'up', 'down']:
        raise ValueError("'direction' must be 'both', 'up', or 'down'.")
    if not isinstance(return_distance, bool):
        raise ValueError("'return_distance' must be a boolean.")
    if not isinstance(max_search_limit, int) or max_search_limit <= 0:
        raise ValueError("'max_search_limit' must be a positive integer.")
    if not isinstance(detailed_output, bool):
        raise ValueError("'detailed_output' must be a boolean.")

    # Initialize variables
    closest_palindrome = None
    closest_distance = float('inf')
    search_count = 0

    # Search for the closest palindrome
    for offset in range(max_search_limit):
        if direction in ['both', 'down']:
            candidate_down = number - offset
            if candidate_down >= 0 and is_palindrome(candidate_down):
                closest_palindrome = candidate_down
                closest_distance = offset
                break
        if direction in ['both', 'up']:
            candidate_up = number + offset
            if is_palindrome(candidate_up):
                closest_palindrome = candidate_up
                closest_distance = offset
                break
        search_count += 1

    # Prepare the result
    if detailed_output:
        result = {
            'closest_palindrome': closest_palindrome,
            'distance': closest_distance,
            'direction': 'down' if closest_palindrome < number else 'up'
        }
    elif return_distance:
        result = (closest_palindrome, closest_distance)
    else:
        result = closest_palindrome

    return result

