def enhanced_timezone_difference_calculator(timezones, date=None, output_format='hours', historical_data=False):
    """
    Calculate the time difference between specified time zones and UTC.

    Parameters:
    - timezones (list of str): A list of IANA time zone identifiers.
    - date (str, optional): The date for which the time difference is calculated.
    - output_format (str, optional): The format of the output ('hours', 'minutes', 'detailed').
    - historical_data (bool, optional): Whether to consider historical time zone data.

    Returns:
    - dict: A dictionary with time zone differences from UTC.
    """
    import pytz
    from datetime import datetime

    # Validate timezones parameter
    if not isinstance(timezones, list) or not all(isinstance(tz, str) for tz in timezones):
        return {'error': 'Invalid timezones parameter. Must be a list of strings.'}

    # Validate date parameter
    if date:
        try:
            date_obj = datetime.strptime(date, '%Y-%m-%d')
        except ValueError:
            return {'error': 'Invalid date format. Must be YYYY-MM-DD.'}
    else:
        date_obj = datetime.utcnow()

    results = {}
    for tz in timezones:
        try:
            timezone = pytz.timezone(tz)
            if date:
                local_time = timezone.localize(date_obj)
            else:
                local_time = datetime.now(timezone)
            utc_offset = local_time.utcoffset().total_seconds() / 3600
            if output_format == 'minutes':
                utc_offset *= 60
            elif output_format == 'detailed':
                dst_info = 'DST' if local_time.dst() else 'Standard'
                results[tz] = {'offset': utc_offset, 'dst_info': dst_info}
                continue
            results[tz] = utc_offset
        except pytz.UnknownTimeZoneError:
            results[tz] = 'Unknown time zone'

    return results

