def digit_sum_calculator_v2(number, output_format='integer', digit_filter=None, base=10):
    """
    Calculate the sum of digits of a given number with optional digit filtering and base conversion.

    :param number: The numerical input whose digits are to be summed. It should be a non-negative integer.
    :param output_format: The format of the output. Defaults to 'integer'.
    :param digit_filter: An optional list of digits to include in the sum calculation.
    :param base: The numerical base of the input number. Defaults to base 10.
    :return: The sum of the digits in the specified format.
    """
    # Error handling for invalid inputs
    if not isinstance(number, int) or number < 0:
        return {'error': 'Invalid input: number must be a non-negative integer.'}
    if base < 2 or base > 36:
        return {'error': 'Invalid input: base must be between 2 and 36.'}
    if output_format not in ['integer', 'text', 'json']:
        return {'error': 'Invalid input: output_format must be one of ["integer", "text", "json"].'}

    # Convert number to the specified base
    digits = []
    n = number
    while n > 0:
        digits.append(n % base)
        n //= base

    # Apply digit filter if specified
    if digit_filter is not None:
        digits = [d for d in digits if d in digit_filter]

    # Calculate the sum of the digits
    digit_sum = sum(digits)

    # Format the output based on the specified output format
    if output_format == 'integer':
        return digit_sum
    elif output_format == 'text':
        return f'The sum of the digits is {digit_sum}.'
    elif output_format == 'json':
        return {'sum': digit_sum}

