def date_calculator(input_date, operation='subtract', days=1, second_date=None, output_format='YYYY-MM-DD', time_zone='UTC'):
    from datetime import datetime, timedelta
    import pytz

    # Validate input_date format
    try:
        date_obj = datetime.strptime(input_date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid input_date format. Expected YYYY-MM-DD.'}

    # Set timezone
    try:
        tz = pytz.timezone(time_zone)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time zone.'}

    date_obj = tz.localize(date_obj)

    # Perform operation
    if operation == 'subtract':
        result_date = date_obj - timedelta(days=days)
    elif operation == 'add':
        result_date = date_obj + timedelta(days=days)
    elif operation == 'difference':
        if not second_date:
            return {'error': 'second_date is required for difference operation.'}
        try:
            second_date_obj = datetime.strptime(second_date, '%Y-%m-%d')
            second_date_obj = tz.localize(second_date_obj)
        except ValueError:
            return {'error': 'Invalid second_date format. Expected YYYY-MM-DD.'}
        result_date = abs((date_obj - second_date_obj).days)
    else:
        return {'error': 'Invalid operation. Choose from add, subtract, difference.'}

    # Format output
    if operation in ['add', 'subtract']:
        if output_format == 'YYYY-MM-DD':
            formatted_date = result_date.strftime('%Y-%m-%d')
        elif output_format == 'MM/DD/YYYY':
            formatted_date = result_date.strftime('%m/%d/%Y')
        elif output_format == 'DD-MM-YYYY':
            formatted_date = result_date.strftime('%d-%m-%Y')
        elif output_format == 'DD/MM/YYYY':
            formatted_date = result_date.strftime('%d/%m/%Y')
        else:
            return {'error': 'Invalid output format.'}
        return {'result': formatted_date}
    else:
        return {'result': result_date}

