def distinct_combinations(input_string, combination_length=2, ignore_characters=None, output_format='count', case_sensitive=False, max_combinations=None, allow_duplicates=False):
    # Validate input_string
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string.'}

    # Validate combination_length
    if not isinstance(combination_length, int) or combination_length < 1:
        return {'error': 'combination_length must be an integer greater than or equal to 1.'}

    # Validate ignore_characters
    if ignore_characters is not None:
        if not all(isinstance(char, str) for char in ignore_characters):
            return {'error': 'ignore_characters must be a list of strings.'}
    else:
        ignore_characters = []

    # Validate output_format
    if output_format not in ['list', 'count']:
        return {'error': "output_format must be either 'list' or 'count'."}

    # Validate max_combinations
    if max_combinations is not None:
        if not isinstance(max_combinations, int) or max_combinations < 1:
            return {'error': 'max_combinations must be an integer greater than or equal to 1.'}

    # Process input_string
    if not case_sensitive:
        input_string = input_string.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Filter out ignored characters
    filtered_string = ''.join([char for char in input_string if char not in ignore_characters])

    # Generate combinations
    from itertools import combinations
    unique_combinations = set()
    for comb in combinations(filtered_string, combination_length):
        if allow_duplicates or len(set(comb)) == len(comb):
            unique_combinations.add(comb)
            if max_combinations and len(unique_combinations) >= max_combinations:
                break

    # Return result based on output_format
    if output_format == 'list':
        return list(unique_combinations)
    else:  # output_format == 'count'
        return len(unique_combinations)

