    if not isinstance(handle_suffixes, bool):
        return {'error': 'Invalid input: handle_suffixes must be a boolean.'}
    if title_handling not in ['ignore', 'include', 'separate']:
        return {'error': 'Invalid input: title_handling must be one of ["ignore", "include", "separate"].'}

    # Split the full name based on the delimiter
    name_parts = full_name.split(delimiter)

