def extract_last_character_v2(input, output_format='character', ignore_empty=False):
    """
    Extracts the last character from each string in the input list.

    Parameters:
    - input (list of str): The strings from which the last character will be extracted.
    - output_format (str): The format of the output. Options include 'character', 'text', 'json', 'list'.
    - ignore_empty (bool): Option to ignore empty strings in the input.

    Returns:
    - The last character(s) in the specified format.
    """
    if not isinstance(input, list) or not all(isinstance(i, str) for i in input):
        raise ValueError("Input must be a list of strings.")
    if len(input) < 1 or len(input) > 100:
        raise ValueError("Input list must contain between 1 and 100 strings.")

    last_characters = []
    for string in input:
        if string == "" and ignore_empty:
            continue
        if string == "":
            raise ValueError("Empty strings are not allowed unless 'ignore_empty' is set to True.")
        last_characters.append(string[-1])

    if output_format == 'character':
        return last_characters[0] if last_characters else None
    elif output_format == 'text':
        return ''.join(last_characters)
    elif output_format == 'json':
        return {string: string[-1] for string in input if string}
    elif output_format == 'list':
        return last_characters
    else:
        raise ValueError("Invalid output format specified.")

