def reverse_order(input: str, output_format: str = 'string', exclude_characters: str = '') -> any:
    # Error handling for unsupported output formats
    if output_format not in ['string', 'number', 'array', 'json']:
        return {'error': 'Unsupported output format'}

    # Initialize variables
    reversed_result = ''
    excluded_indices = {i: char for i, char in enumerate(input) if char in exclude_characters}

    # Reverse the input while excluding specified characters
    reversed_chars = [char for char in input if char not in exclude_characters][::-1]
    for i, char in enumerate(input):
        if i in excluded_indices:
            reversed_result += excluded_indices[i]
        else:
            reversed_result += reversed_chars.pop(0)

    # Format the output based on the specified output format
    if output_format == 'number':
        try:
            return int(reversed_result)
        except ValueError:
            return {'error': 'Reversed result cannot be converted to a number'}
    elif output_format == 'array':
        return list(reversed_result)
    elif output_format == 'json':
        return {'reversed': reversed_result}
    else:  # Default to 'string'
        return reversed_result

