def enhanced_unique_character_counter(input_strings, case_sensitive=False, include_non_alphabetic=False, character_set='latin', detailed_output=False):
    # Validate input parameters
    if not isinstance(input_strings, list) or not all(isinstance(s, str) for s in input_strings):
        return {'error': 'Invalid input: input_strings must be a list of strings.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid input: case_sensitive must be a boolean.'}
    if not isinstance(include_non_alphabetic, bool):
        return {'error': 'Invalid input: include_non_alphabetic must be a boolean.'}
    if not isinstance(character_set, str):
        return {'error': 'Invalid input: character_set must be a string.'}
    if not isinstance(detailed_output, bool):
        return {'error': 'Invalid input: detailed_output must be a boolean.'}

    # Initialize a set to store unique characters
    unique_chars = set()

    # Define a function to filter characters based on the character set
    def is_valid_char(char):
        if character_set == 'latin':
            return char.isalpha() and (char.isascii() or include_non_alphabetic)
        elif character_set == 'cyrillic':
            return 'а' <= char <= 'я' or 'А' <= char <= 'Я'
        elif character_set == 'all':
            return True
        return False

    # Process each string in the input list
    for string in input_strings:
        for char in string:
            if not case_sensitive:
                char = char.lower()
            if is_valid_char(char):
                unique_chars.add(char)

    # Prepare the result
    if detailed_output:
        char_count = {char: string.count(char) for char in unique_chars for string in input_strings}
        return {'unique_count': len(unique_chars), 'details': char_count}
    else:
        return {'unique_count': len(unique_chars)}

