def date_calculator(input_date: str, days_to_add: int, time_to_add: str = '00:00:00', calendar_system: str = 'Gregorian', output_format: str = 'YYYY-MM-DD', business_days_only: bool = False, timezone: str = 'UTC') -> str:
    from datetime import datetime, timedelta
    import pytz

    # Validate input_date format
    try:
        date_obj = datetime.strptime(input_date, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return 'Error: Invalid input_date format. Expected YYYY-MM-DDTHH:MM:SS.'

    # Validate calendar_system
    if calendar_system not in ['Gregorian', 'Julian', 'ISO8601']:
        return 'Error: Unsupported calendar system.'

    # Validate output_format
    if output_format not in ['YYYY-MM-DD', 'DD-MM-YYYY', 'MM-DD-YYYY', 'YYYY-MM-DDTHH:MM:SS']:
        return 'Error: Unsupported output format.'

    # Adjust for timezone
    try:
        timezone_obj = pytz.timezone(timezone)
        date_obj = timezone_obj.localize(date_obj)
    except pytz.UnknownTimeZoneError:
        return 'Error: Unknown timezone specified.'

    # Add days
    if business_days_only:
        # Logic to add only business days
        days_added = 0
        while days_added < abs(days_to_add):
            date_obj += timedelta(days=1 if days_to_add > 0 else -1)
            if date_obj.weekday() < 5:  # Monday to Friday are business days
                days_added += 1
    else:
        date_obj += timedelta(days=days_to_add)

    # Add time
    try:
        hours, minutes, seconds = map(int, time_to_add.split(':'))
        time_delta = timedelta(hours=hours, minutes=minutes, seconds=seconds)
        date_obj += time_delta
    except ValueError:
        return 'Error: Invalid time_to_add format. Expected HH:MM:SS.'

    # Format output
    if output_format == 'YYYY-MM-DD':
        return date_obj.strftime('%Y-%m-%d')
    elif output_format == 'DD-MM-YYYY':
        return date_obj.strftime('%d-%m-%Y')
    elif output_format == 'MM-DD-YYYY':
        return date_obj.strftime('%m-%d-%Y')
    elif output_format == 'YYYY-MM-DDTHH:MM:SS':
        return date_obj.strftime('%Y-%m-%dT%H:%M:%S')

    return 'Error: Unexpected error in date calculation.'

