def advanced_date_calculator(start_date, days_to_add=0, months_to_add=0, years_to_add=0, adjust_for_month_end=True, date_format='YYYY-MM-DD'):
    from datetime import datetime
    from dateutil.relativedelta import relativedelta
    import calendar

    try:
        # Parse the start date
        start_date_obj = datetime.strptime(start_date, '%Y-%m-%d')
    except ValueError:
        return {'error': 'Invalid start_date format. Expected YYYY-MM-DD.'}

    # Calculate the new date
    try:
        # Add years, months, and days
        new_date = start_date_obj + relativedelta(years=years_to_add, months=months_to_add, days=days_to_add)

        # Adjust for month end if necessary
        if adjust_for_month_end:
            if start_date_obj.day == calendar.monthrange(start_date_obj.year, start_date_obj.month)[1]:
                # If the start date is the last day of the month, adjust the new date to the last day of the new month
                new_date = new_date.replace(day=calendar.monthrange(new_date.year, new_date.month)[1])

        # Format the new date
        formatted_date = new_date.strftime('%Y-%m-%d') if date_format == 'YYYY-MM-DD' else new_date.strftime(date_format)

        return {'result': formatted_date}
    except Exception as e:
        return {'error': str(e)}

