def date_calculator(start_date, days_to_add=0, weeks_to_add=0, months_to_add=0, years_to_add=0, business_days_only=False, time_zone='UTC', output_format='YYYY-MM-DD'):
    from datetime import datetime, timedelta
    import pytz
    from dateutil.relativedelta import relativedelta

    # Validate and parse the start_date
    try:
        # Attempt to parse the date in various formats
        date_formats = ['%Y-%m-%d', '%m/%d/%Y', '%d-%m-%Y']
        for fmt in date_formats:
            try:
                start_date_obj = datetime.strptime(start_date, fmt)
                break
            except ValueError:
                continue
        else:
            raise ValueError('Invalid date format')
    except Exception as e:
        return {'error': str(e)}

    # Convert weeks to days
    total_days_to_add = days_to_add + weeks_to_add * 7

    # Add days, months, and years
    try:
        result_date = start_date_obj + timedelta(days=total_days_to_add)
        result_date += relativedelta(months=months_to_add, years=years_to_add)
    except Exception as e:
        return {'error': str(e)}

    # Adjust for time zone
    try:
        tz = pytz.timezone(time_zone)
        result_date = tz.localize(result_date)
    except Exception as e:
        return {'error': str(e)}

    # Format the output date
    try:
        if output_format == 'YYYY-MM-DD':
            formatted_date = result_date.strftime('%Y-%m-%d')
        elif output_format == 'MM/DD/YYYY':
            formatted_date = result_date.strftime('%m/%d/%Y')
        elif output_format == 'DD-MM-YYYY':
            formatted_date = result_date.strftime('%d-%m-%Y')
        elif output_format == 'ISO8601':
            formatted_date = result_date.isoformat()
        else:
            raise ValueError('Invalid output format')
    except Exception as e:
        return {'error': str(e)}

    return {'result': formatted_date}

