    try:
        tz_offset = int(time_zone[:3]) * 60 + int(time_zone[4:])
        start_date_obj = start_date_obj + timedelta(minutes=tz_offset)
    except ValueError:
        return 'Error: Invalid time_zone format. Please use UTC offset format (e.g., +00:00).'

    # Perform date arithmetic
    try:
        result_date = start_date_obj + relativedelta(months=months_to_add)
        result_date += timedelta(days=days_to_add, hours=hours_to_add)
    except Exception as e:
        return f'Error: {str(e)}'

    # Format the output date
    if output_format == 'YYYY-MM-DD':
        return result_date.strftime('%Y-%m-%d')
    elif output_format == 'MM-DD-YYYY':
        return result_date.strftime('%m-%d-%Y')
    elif output_format == 'DD-MM-YYYY':
        return result_date.strftime('%d-%m-%Y')
    elif output_format == 'YYYY-MM-DDTHH:MM:SSZ':
        return result_date.strftime('%Y-%m-%dT%H:%M:%SZ')
    else:
        return 'Error: Invalid output_format. Please use one of the specified formats.'

