def reverse_number(number: str, preserve_sign: bool = True, output_format: str = 'integer', numeric_system: str = 'decimal') -> str:
    # Validate the output_format
    if output_format not in ['integer', 'decimal', 'scientific']:
        return 'Error: Invalid output_format. Choose from integer, decimal, scientific.'

    # Validate the numeric_system
    if numeric_system not in ['decimal', 'binary', 'octal', 'hexadecimal']:
        return 'Error: Invalid numeric_system. Choose from decimal, binary, octal, hexadecimal.'

    # Check if the number is valid
    try:
        # Handle scientific notation
        if 'e' in number.lower():
            base, exp = number.lower().split('e')
            reversed_base = base[::-1]
            reversed_number = f'{reversed_base}e{exp}'
        else:
            reversed_number = number[::-1]

        # Handle sign preservation
        if preserve_sign and number.startswith('-'):
            reversed_number = '-' + reversed_number.rstrip('-')

        # Convert to the desired numeric system
        if numeric_system == 'binary':
            reversed_number = bin(int(reversed_number))[2:]
        elif numeric_system == 'octal':
            reversed_number = oct(int(reversed_number))[2:]
        elif numeric_system == 'hexadecimal':
            reversed_number = hex(int(reversed_number))[2:]

        # Format the output
        if output_format == 'decimal':
            return str(float(reversed_number))
        elif output_format == 'scientific':
            return f'{float(reversed_number):.2e}'
        else:  # integer
            return str(int(reversed_number))
    except ValueError:
        return 'Error: Invalid number format.'

