def date_difference_calculator(start_date, end_date, date_format='YYYY-MM-DD', output_format='integer', time_zone='UTC', business_days_only=False, holidays=[]):
    from datetime import datetime, timedelta
    import pytz
    from dateutil import parser

    def parse_date(date_str, date_format):
        try:
            if date_format == 'YYYY-MM-DD':
                return datetime.strptime(date_str, '%Y-%m-%d')
            elif date_format == 'DD-MM-YYYY':
                return datetime.strptime(date_str, '%d-%m-%Y')
            else:
                return parser.parse(date_str)
        except ValueError:
            raise ValueError(f"Invalid date format for {date_str}. Expected format: {date_format}.")

    try:
        start = parse_date(start_date, date_format)
        end = parse_date(end_date, date_format)

        if time_zone != 'UTC':
            tz = pytz.timezone(time_zone)
            start = tz.localize(start)
            end = tz.localize(end)

        if business_days_only:
            day_count = 0
            current_date = start
            while current_date < end:
                if current_date.weekday() < 5 and current_date.strftime('%Y-%m-%d') not in holidays:
                    day_count += 1
                current_date += timedelta(days=1)
        else:
            day_count = (end - start).days

        if output_format == 'integer':
            return day_count
        elif output_format == 'text':
            return f"The number of days between {start_date} and {end_date} is {day_count}."
        elif output_format == 'detailed':
            years, remainder = divmod(day_count, 365)
            months, days = divmod(remainder, 30)
            return f"{years} years, {months} months, and {days} days."
        else:
            raise ValueError("Invalid output format specified.")
    except Exception as e:
        return str(e)

