    if not isinstance(input, str):
        return {'error': 'Invalid input type. Expected a string.'}

    # Validate ignore_characters parameter
    if not isinstance(ignore_characters, list) or not all(isinstance(c, str) for c in ignore_characters):
        return {'error': 'Invalid ignore_characters type. Expected a list of strings.'}

    # Validate ignore_position parameter
    if not isinstance(ignore_position, list) or not all(p in ['first', 'last'] for p in ignore_position):
        return {'error': 'Invalid ignore_position type. Expected a list with values "first" or "last".'}

    # Validate case_sensitive parameter
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive type. Expected a boolean.'}

    # Validate count_type parameter
    if count_type not in ['all', 'vowels', 'consonants']:
        return {'error': 'Invalid count_type. Expected "all", "vowels", or "consonants".'}

    # Validate output_format parameter
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format. Expected "integer", "text", or "detailed".'}

    # Prepare the input string
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [c.lower() for c in ignore_characters]

    # Remove ignored characters
    input = ''.join(c for c in input if c not in ignore_characters)

    # Remove ignored positions
    if 'first' in ignore_position and len(input) > 0:
        input = input[1:]
    if 'last' in ignore_position and len(input) > 0:
        input = input[:-1]

    # Define vowels and consonants
    vowels = 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyz'

    # Count letters based on count_type
    if count_type == 'vowels':
        count = sum(1 for c in input if c in vowels)
    elif count_type == 'consonants':
        count = sum(1 for c in input if c in consonants)
    else:
        count = sum(1 for c in input if c.isalpha())

    # Return result based on output_format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The number of letters is {count}.'
    elif output_format == 'detailed':
        vowel_count = sum(1 for c in input if c in vowels)
        consonant_count = sum(1 for c in input if c in consonants)
        return {
