def extract_first_name(names, ignore_prefixes=False, ignore_suffixes=False, include_middle_name=False, output_format='string'):
    # Validate input parameters
    if not isinstance(names, list) or len(names) < 1 or len(names) > 20:
        return {'error': 'Invalid input: names must be a list with 1 to 20 items.'}
    if output_format not in ['string', 'array', 'json']:
        return {'error': 'Invalid output format. Choose from string, array, or json.'}

    # Common prefixes and suffixes
    prefixes = ['Mr.', 'Mrs.', 'Ms.', 'Dr.']
    suffixes = ['Jr.', 'Sr.', 'II', 'III']

    # Function to process a single name
    def process_name(full_name):
        # Split the name into parts
        parts = full_name.split()

        # Remove prefixes if needed
        if ignore_prefixes and parts[0] in prefixes:
            parts = parts[1:]

        # Remove suffixes if needed
        if ignore_suffixes and parts[-1] in suffixes:
            parts = parts[:-1]

        # Extract the first name
        first_name = parts[0]

        # Include middle name if required
        if include_middle_name and len(parts) > 2:
            first_name += ' ' + ' '.join(parts[1:-1])

        return first_name

    # Process all names
    results = [process_name(name) for name in names]

    # Format the output
    if output_format == 'string':
        return results[0] if len(results) == 1 else ', '.join(results)
    elif output_format == 'array':
        return results
    elif output_format == 'json':
        return {'first_names': results}

    return {'error': 'Unexpected error occurred.'}

