            result = input[custom_index]
        elif position == 'range':
            if range_start is None or range_end is None:
                return {'error': 'range_start and range_end must be provided for range position.'}
            result = input[range_start:range_end]

        # Format the output
        if output_format == 'ascii':
            result = [ord(char) for char in result]
        elif output_format == 'unicode':
            result = [f'U+{ord(char):04X}' for char in result]
        elif output_format == 'hex':
            result = [f'{ord(char):02x}' for char in result]

        # Handle multiple extraction
        if not multiple and isinstance(result, list):
            result = result[0]

        return {'result': result}
    except IndexError:
        return {'error': 'Index out of range.'}
    except Exception as e:
        return {'error': str(e)}

