def char_to_binary(input: str, output_format: str = 'binary_string', include_non_ascii: bool = False, encoding: str = 'utf-8', error_handling: str = 'strict', batch_processing: bool = False):
    """
    Convert characters or strings into their binary code representation.

    Parameters:
    - input (str): The character or string to be converted to binary.
    - output_format (str): The format of the output. 'binary_string' or 'binary_list'.
    - include_non_ascii (bool): Whether to include non-ASCII characters.
    - encoding (str): The character encoding to use.
    - error_handling (str): The strategy for handling encoding errors.
    - batch_processing (bool): Whether to enable batch processing.

    Returns:
    - str or list: Binary representation of the input.
    """
    if not input:
        raise ValueError("Input must be at least one character long.")

    if batch_processing:
        if not isinstance(input, list):
            raise TypeError("Input must be a list of strings when batch_processing is enabled.")
        results = [char_to_binary(i, output_format, include_non_ascii, encoding, error_handling, False) for i in input]
        return results

    try:
        if encoding not in ['utf-8', 'utf-16', 'ascii']:
            raise ValueError("Unsupported encoding type.")

        binary_codes = []
        for char in input:
            if not include_non_ascii and ord(char) > 127:
                if error_handling == 'strict':
                    raise ValueError(f"Non-ASCII character found: {char}")
                elif error_handling == 'ignore':
                    continue
                elif error_handling == 'replace':
                    char = '?'  # or any other placeholder

            binary_code = format(ord(char), '08b')
            binary_codes.append(binary_code)

        if output_format == 'binary_string':
            return ''.join(binary_codes)
        elif output_format == 'binary_list':
            return binary_codes
        else:
            raise ValueError("Invalid output format.")

    except Exception as e:
        if error_handling == 'strict':
            raise e
        elif error_handling == 'ignore':
            return '' if output_format == 'binary_string' else []
        elif error_handling == 'replace':
            return '?' if output_format == 'binary_string' else ['?']

