def extract_last_letter(input, trim_whitespace=True, ignore_special_characters=False, case_sensitive=True, exclude_numeric=False, return_position=False, summary=False):
    import re

    # Error handling for empty input
    if not input or not isinstance(input, list) or not all(isinstance(i, str) for i in input):
        return {'error': 'Invalid input: input must be a list of strings with at least one string.'}

    results = []
    for string in input:
        original_string = string

        # Trim whitespace if required
        if trim_whitespace:
            string = string.strip()

        # Remove special characters if required
        if ignore_special_characters:
            string = re.sub(r'[^\w\s]', '', string)

        # Remove numeric characters if required
        if exclude_numeric:
            string = re.sub(r'\d', '', string)

        # Extract the last letter
        if string:
            last_letter = string[-1] if case_sensitive else string[-1].lower()
            position = len(original_string) - 1 if return_position else None
            results.append({'last_letter': last_letter, 'position': position})
        else:
            results.append({'error': 'No valid characters to process in string.'})

    # Prepare summary if required
    if summary:
        summary_info = {
            'total_strings': len(input),
            'processed_strings': len(results),
            'errors': sum(1 for result in results if 'error' in result)
        }
        return {'results': results, 'summary': summary_info}

    return {'results': results}

