def date_subtractor_plus(input_date: str, years_to_subtract: int = 1, months_to_subtract: int = 0, days_to_subtract: int = 0, output_format: str = 'YYYY-MM-DD', error_handling: str = 'strict') -> str:
    from datetime import datetime
    from dateutil.relativedelta import relativedelta

    # Parse the input date
    try:
        date_obj = datetime.strptime(input_date, '%Y-%m-%d')
    except ValueError:
        if error_handling == 'strict':
            raise ValueError('Invalid date format. Expected YYYY-MM-DD.')
        else:
            return 'Invalid date format. Adjusting to nearest valid date.'

    # Subtract years, months, and days
    try:
        new_date = date_obj - relativedelta(years=years_to_subtract, months=months_to_subtract, days=days_to_subtract)
    except Exception as e:
        if error_handling == 'strict':
            raise e
        else:
            return 'Error in date calculation. Adjusting to nearest valid date.'

    # Format the output date
    if output_format == 'YYYY-MM-DD':
        return new_date.strftime('%Y-%m-%d')
    elif output_format == 'MM-DD-YYYY':
        return new_date.strftime('%m-%d-%Y')
    elif output_format == 'DD-MM-YYYY':
        return new_date.strftime('%d-%m-%Y')
    elif output_format == 'ISO8601':
        return new_date.isoformat()
    else:
        if error_handling == 'strict':
            raise ValueError('Invalid output format.')
        else:
            return 'Invalid output format. Defaulting to YYYY-MM-DD.'

