def day_of_week_calculator(date, calendar_system='gregorian', output_format='full', time_zone='+00:00'):
    from datetime import datetime
    import pytz
    from dateutil import parser

    # Error handling for date format
    try:
        # Attempt to parse the date
        parsed_date = parser.parse(date, dayfirst=True)
    except ValueError:
        return {'error': 'Invalid date format. Please use YYYY-MM-DD or DD-MM-YYYY.'}

    # Error handling for calendar system
    if calendar_system not in ['gregorian', 'julian', 'hebrew', 'islamic']:
        return {'error': 'Unsupported calendar system. Please choose from gregorian, julian, hebrew, islamic.'}

    # Error handling for output format
    if output_format not in ['full', 'abbreviated', 'numeric']:
        return {'error': 'Invalid output format. Please choose from full, abbreviated, numeric.'}

    # Error handling for time zone
    try:
        timezone = pytz.timezone('Etc/GMT' + time_zone.replace(':', ''))
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time zone format. Please use a valid UTC offset like +00:00 or -05:00.'}

    # Adjust date for time zone
    localized_date = timezone.localize(parsed_date)

    # Determine the day of the week
    if calendar_system == 'gregorian':
        day_of_week = localized_date.strftime('%A')
    elif calendar_system == 'julian':
        # Implement Julian calendar logic
        day_of_week = 'Julian logic not implemented'
    elif calendar_system == 'hebrew':
        # Implement Hebrew calendar logic
        day_of_week = 'Hebrew logic not implemented'
    elif calendar_system == 'islamic':
        # Implement Islamic calendar logic
        day_of_week = 'Islamic logic not implemented'

    # Format the output
    if output_format == 'full':
        return {'day_of_week': day_of_week}
    elif output_format == 'abbreviated':
        return {'day_of_week': day_of_week[:3]}
    elif output_format == 'numeric':
        return {'day_of_week': localized_date.weekday()}

