def extract_last_name(full_name, delimiter='space', case_sensitive=False, include_suffix=False, naming_convention='western'):
    # Define valid delimiters
    delimiters = {
        'space': ' ',
        'apostrophe': "'",
        'hyphen': '-',
        'comma': ','
    }

    # Validate delimiter
    if delimiter not in delimiters:
        return {'error': 'Invalid delimiter. Choose from space, apostrophe, hyphen, comma.'}

    # Split the full name based on the specified delimiter
    parts = full_name.split(delimiters[delimiter])

    # Handle naming convention
    if naming_convention == 'western':
        # Western convention assumes last part is the last name
        last_name = parts[-1]
    elif naming_convention == 'eastern':
        # Eastern convention assumes first part is the last name
        last_name = parts[0]
    else:
        return {'error': 'Invalid naming convention. Choose from western, eastern.'}

    # Handle suffix inclusion
    if include_suffix and naming_convention == 'western' and len(parts) > 1:
        # Check if the second last part is a suffix
        suffixes = ['Jr.', 'Sr.', 'II', 'III']
        if parts[-1] in suffixes:
            last_name = parts[-2] + ' ' + parts[-1]

    # Handle case sensitivity
    if not case_sensitive:
        last_name = last_name.lower()

    return {'last_name': last_name}

