def character_counter(input_string, characters, case_sensitive=True, ignore_whitespace=False, range={'start': 0, 'end': None}, output_format='integer'):
    # Validate input_string
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string'}

    # Validate characters
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        return {'error': 'characters must be a list of single-character strings'}

    # Validate range
    start = range.get('start', 0)
    end = range.get('end', len(input_string))
    if not isinstance(start, int) or not isinstance(end, int) or start < 0 or end > len(input_string) or start > end:
        return {'error': 'Invalid range specified'}

    # Adjust input_string based on range
    substring = input_string[start:end]

    # Handle case sensitivity
    if not case_sensitive:
        substring = substring.lower()
        characters = [c.lower() for c in characters]

    # Initialize count
    count = 0

    # Count occurrences
    for char in characters:
        if ignore_whitespace:
            count += sum(1 for c in substring if c == char and not c.isspace())
        else:
            count += substring.count(char)

    # Format output
    if output_format == 'text':
        return f'The characters {characters} appear {count} times.'
    else:
        return count

