def prime_factorizer(number, return_all_factors=False, output_format='list', max_factor_limit=None, include_factor_properties=False, performance_mode='standard'):
    """
    Computes the prime factors of a given integer.
    :param number: The integer to be factorized, must be greater than 1.
    :param return_all_factors: Whether to return all factors or only prime factors.
    :param output_format: The format of the output.
    :param max_factor_limit: The maximum number of factors to return.
    :param include_factor_properties: Whether to include additional properties of the factors.
    :param performance_mode: The mode of operation for performance.
    :return: Prime factors of the number in the specified format.
    """
    # Error handling for invalid inputs
    if not isinstance(number, int) or number <= 1:
        return {'error': 'Invalid input: number must be an integer greater than 1.'}

    # Helper function to find prime factors
    def find_prime_factors(n):
        factors = []
        # Check for number of 2s
        while n % 2 == 0:
            factors.append(2)
            n = n // 2
        # Check for odd factors
        for i in range(3, int(n**0.5) + 1, 2):
            while n % i == 0:
                factors.append(i)
                n = n // i
        # If n is a prime number greater than 2
        if n > 2:
            factors.append(n)
        return factors

    # Find prime factors
    prime_factors = find_prime_factors(number)

    # Limit the number of factors if max_factor_limit is set
    if max_factor_limit is not None:
        prime_factors = prime_factors[:max_factor_limit]

    # Prepare the output based on the output_format
    if output_format == 'list':
        return prime_factors
    elif output_format == 'text':
        return ', '.join(map(str, prime_factors))
    elif output_format == 'json':
        return {'factors': prime_factors}
    elif output_format == 'xml':
        factors_xml = ''.join(f'<factor>{factor}</factor>' for factor in prime_factors)
        return f'<factors>{factors_xml}</factors>'
    else:
        return {'error': 'Invalid output format specified.'}

# Example usage
