    if not isinstance(multiplier, (int, float)):
        return {'error': 'Invalid input: multiplier must be a number.'}
    if not isinstance(precision, int):
        return {'error': 'Invalid input: precision must be an integer.'}

    # Filter out negative numbers if ignore_negatives is True
    if ignore_negatives:
        numbers = [n for n in numbers if n >= 0]

