def reverse_number_advanced(number: str, preserve_sign: bool = True, output_format: str = 'string', delimiter: str = '', reverse_decimal: bool = False):
    # Validate output_format
    if output_format not in ['string', 'integer', 'float']:
        return {'error': 'Invalid output format specified.'}

    # Handle negative sign
    is_negative = number.startswith('-')
    if is_negative and preserve_sign:
        number = number[1:]

    # Split integer and decimal parts
    if '.' in number:
        integer_part, decimal_part = number.split('.')
    else:
        integer_part, decimal_part = number, ''

    # Reverse integer part
    reversed_integer = integer_part[::-1]

    # Reverse decimal part if required
    if reverse_decimal and decimal_part:
        reversed_decimal = decimal_part[::-1]
    else:
        reversed_decimal = decimal_part

    # Combine reversed parts
    if reversed_decimal:
        reversed_number = reversed_integer + '.' + reversed_decimal
    else:
        reversed_number = reversed_integer

    # Reapply negative sign if needed
    if is_negative and preserve_sign:
        reversed_number = '-' + reversed_number

    # Apply delimiter
    if delimiter:
        reversed_number = delimiter.join(reversed_number)

    # Convert to desired output format
    if output_format == 'integer':
        try:
            return int(reversed_number)
        except ValueError:
            return {'error': 'Cannot convert to integer.'}
    elif output_format == 'float':
        try:
            return float(reversed_number)
        except ValueError:
            return {'error': 'Cannot convert to float.'}
    else:
        return reversed_number

