        return {'individual_name': individual_name, 'relationship_type': relationship_type, 'result': result}
    elif output_format == 'xml':
        return f'<individual><name>{individual_name}</name><relationship>{relationship_type}</relationship><result>{result}</result></individual>'
    elif output_format == 'csv':
        return f'individual_name,relationship_type,result\n{individual_name},{relationship_type},{result}'
    else:  # Default to text
        return result

