def date_time_calculator(start_date_time, days_to_add, hours_to_add=0, calendar_system='Gregorian', time_zone='UTC'):
    from datetime import datetime, timedelta
    import pytz

    # Validate calendar_system
    if calendar_system not in ['Gregorian', 'Julian', 'ISO8601']:
        return {'error': 'Invalid calendar system. Choose from Gregorian, Julian, ISO8601.'}

    # Validate start_date_time format
    try:
        start_dt = datetime.strptime(start_date_time, '%Y-%m-%dT%H:%M:%S')
    except ValueError:
        return {'error': 'Invalid start_date_time format. Use YYYY-MM-DDTHH:MM:SS.'}

    # Validate time_zone
    try:
        tz = pytz.timezone(time_zone)
    except pytz.UnknownTimeZoneError:
        return {'error': 'Invalid time zone. Use a valid IANA time zone format.'}

    # Convert start_dt to the specified time zone
    start_dt = tz.localize(start_dt)

    # Calculate the new date and time
    delta = timedelta(days=days_to_add, hours=hours_to_add)
    new_dt = start_dt + delta

    # Return the result in the specified format
    return {'new_date_time': new_dt.strftime('%Y-%m-%dT%H:%M:%S'), 'calendar_system': calendar_system, 'time_zone': time_zone}

